  /**
   * Initialize the localization system
   */
  async initialize(): Promise<void> {
    try {
      // Detect user's preferred locale from Obsidian settings
      const detectedLocale = this.detectUserLocale();

      // Use detected locale (no user override needed since we follow Obsidian's settings)
      await this.setLocale(detectedLocale);

      this.plugin.logger.debug(`I18n initialized with locale: ${this.currentLocale}`);
    } catch (error) {
      this.plugin.logger.error('Error initializing I18n:', error);
      // Fall back to English if initialization fails
      await this.setLocale('en');
    }
  }

  /**
   * Detect the user's preferred locale from Obsidian settings
   */
  private detectUserLocale(): string {
    try {
      // FIX: Use typed interfaces instead of 'any'
      const obsidianLocale =
        this.getMomentLocale() || // Use existing safe method
        activeDocument.documentElement.lang ||
        (this.app as ObsidianAppWithConfig).vault?.config?.userInterfaceMode ||
        (this.app as ObsidianAppWithConfig).locale;

      this.plugin.logger.debug(`Detected Obsidian locale: ${obsidianLocale}`);

      if (obsidianLocale) {
        // Handle Chinese locale variants - map both to zh-CN
        if (obsidianLocale.toLowerCase().startsWith('zh')) {
          this.plugin.logger.debug(`Mapping Chinese variant ${obsidianLocale} to zh-CN`);
          return 'zh-CN';
        }

        // Check if exactly supported
        if (this.isLocaleSupported(obsidianLocale)) {
          return obsidianLocale;
        }

        // Try language code only (e.g., en-GB -> en)
        const languageCode = obsidianLocale.split('-')[0].toLowerCase();
        if (this.isLocaleSupported(languageCode)) {
          this.plugin.logger.debug(`Using language code: ${languageCode}`);
          return languageCode;
        }
      }

      // Fallback to browser locale
      const browserLocale = navigator.language || navigator.languages?.[0];
      if (browserLocale) {
        if (this.isLocaleSupported(browserLocale)) {
          return browserLocale;
        }

        const languageCode = browserLocale.split('-')[0];
        if (this.isLocaleSupported(languageCode)) {
          return languageCode;
        }
      }
    } catch (error) {
      this.plugin.logger.debug('Error detecting user locale:', error);
    }

    this.plugin.logger.debug(`Falling back to default locale: ${this.fallbackLocale}`);
    return this.fallbackLocale;
  }

  /**
   * Safely get moment.js locale if available
   */
  private getMomentLocale(): string | null {
    try {
      // FIX: Use typed interfaces for window and global moment access
      // Check if moment is available on window object
      if (typeof window !== 'undefined' && (window as WindowWithMoment).moment) {
        const momentInstance = (window as WindowWithMoment).moment;
        if (momentInstance?.locale && typeof momentInstance.locale === 'function') {
          return momentInstance.locale();
        }
      }

      // Check global moment
      if (typeof (window as GlobalWithMoment).moment !== 'undefined') {
        const momentInstance = (window as GlobalWithMoment).moment;
        if (momentInstance?.locale && typeof momentInstance.locale === 'function') {
          return momentInstance.locale();
        }
      }

      return null;
    } catch (error) {
      this.plugin.logger.debug('Error getting moment locale:', error);
      return null;
    }
  }

  /**
   * Check if a locale is supported
   */
  private isLocaleSupported(locale: string): boolean {
    return this.supportedLocales.has(locale);
  }

  /**
   * Load locale data from external translation files
   */
  private async loadLocaleData(locale: string): Promise<LocaleData> {
    try {
      // Get translations from external files
      const translations = this.getTranslationsFromFile(locale);

      if (Object.keys(translations).length > 0) {
        this.plugin.logger.debug(`Loaded translations for ${locale}`);
        return translations;
      }

      // If no translations found, log and return empty
      this.plugin.logger.debug(`No translations found for ${locale}`);
      return {};
    } catch (error) {
      this.plugin.logger.error(`Error loading locale data for ${locale}:`, error);
      return {};
    }
  }

  /**
   * Get translations from external language files
   */
  private getTranslationsFromFile(locale: string): LocaleData {
    const translationMap: Record<string, LocaleData> = {
      en: enTranslations,
      es: esTranslations,
      'zh-CN': zhCNTranslations,
      // Add more languages here as they become available
    };

    return translationMap[locale] || {};
  }

  /**
   * Set the current locale and load its translations
   */
  async setLocale(locale: string): Promise<void> {
    try {
      if (!this.isLocaleSupported(locale)) {
        this.plugin.logger.warn(
          `Unsupported locale: ${locale}, falling back to ${this.fallbackLocale}`
        );
        locale = this.fallbackLocale;
      }

      // Load locale data
      const localeData = await this.loadLocaleData(locale);

      // If locale is not English and has no data, fall back to English
      if (locale !== this.fallbackLocale && Object.keys(localeData).length === 0) {
        this.plugin.logger.warn(
          `No translations found for ${locale}, falling back to ${this.fallbackLocale}`
        );
        locale = this.fallbackLocale;
        const fallbackData = await this.loadLocaleData(locale);
        this.translations.set(locale, fallbackData);
      } else {
        this.translations.set(locale, localeData);
      }

      this.currentLocale = locale;

      this.plugin.logger.debug(`Locale set to: ${locale}`);
    } catch (error) {
      this.plugin.logger.error(`Error setting locale to ${locale}:`, error);
      throw error;
    }
  }

  /**
   * Get translated string with interpolation support
   */
  t(key: string, interpolations?: Record<string, string | number>): string {
    try {
      // Debug logging
      this.plugin.logger.debug(`Translating key: ${key} for locale: ${this.currentLocale}`);

      const value = this.getTranslation(key);
      this.plugin.logger.debug(
        `Translation result: ${typeof value === 'string' ? value : 'NOT_STRING'}`
      );

      if (interpolations && typeof value === 'string') {
        return this.interpolate(value, interpolations);
      }

      return typeof value === 'string' ? value : key;
    } catch (error) {
      this.plugin.logger.error(`Translation error for key "${key}":`, error);
      return key;
    }
  }

  /**
   * Get translation value by key path
   */
  private getTranslation(key: string): string | LocaleData {
    const currentTranslations = this.translations.get(this.currentLocale);
    const fallbackTranslations = this.translations.get(this.fallbackLocale);

    // Try current locale first
    let value = this.getNestedValue(currentTranslations, key);

    // Fall back to fallback locale if not found
    if (value === undefined && this.currentLocale !== this.fallbackLocale) {
      value = this.getNestedValue(fallbackTranslations, key);
    }

    return value ?? key;
  }

  /**
   * Get nested value from object using dot notation
   * FIX: Use proper typing for the reducer function
   */
  private getNestedValue(
    obj: LocaleData | undefined,
    path: string
  ): string | LocaleData | undefined {
    if (!obj) return undefined;

    return path.split('.').reduce((current: string | LocaleData | undefined, key: string) => {
      if (current && typeof current === 'object' && key in current) {
        return current[key];
      }
      return undefined;
    }, obj);
  }

  /**
   * Interpolate variables in translation strings
   */
  private interpolate(template: string, variables: Record<string, string | number>): string {
    return template.replace(/\{(\w+)\}/g, (match, key) => {
      return variables[key]?.toString() ?? match;
    });
  }

  /**
   * Get all supported locales
   */
  getSupportedLocales(): SupportedLocale[] {
    return Array.from(this.supportedLocales.values());
  }

  /**
   * Get current locale code
   */
  getCurrentLocale(): string {
    return this.currentLocale;
  }

  /**
   * Get current locale info
   */
  getCurrentLocaleInfo(): SupportedLocale | undefined {
    return this.supportedLocales.get(this.currentLocale);
  }

  /**
   * Check if current locale uses RTL direction
   */
  isRTL(): boolean {
    const localeInfo = this.getCurrentLocaleInfo();
    return localeInfo?.direction === 'rtl';
  }

  /**
   * Get available locales that have translation data
   */
  getAvailableLocales(): SupportedLocale[] {
    // Return locales that have external translation files
    const availableLocaleCodes = ['en', 'es', 'zh-CN']; // Add more as translations are added

    return availableLocaleCodes
      .map((code) => this.supportedLocales.get(code))
      .filter((locale): locale is SupportedLocale => locale !== undefined);
  }
}

// Convenience function for getting translations
export function t(key: string, interpolations?: Record<string, string | number>): string {
  try {
    return I18nManager.getInstance().t(key, interpolations);
  } catch (error) {
    // If I18nManager is not initialized, return the key
    return key;
  }
}

import MacrosPlugin from '../main';
import { Chart, ChartConfiguration, ChartDataset, TooltipItem, registerables } from 'chart.js';
import { ChartLoader, MacrosState, DOMUtils } from '../utils';
import { formatChartTitle, getCurrentEnergyUnitString } from '../utils/formatters';
import { t } from '../lang/I18nManager';
import { convertEnergyUnit } from '../utils/energyUtils';

interface ExtendedWindow extends Window {
  Chart?: typeof Chart;
  macroCharts?: Record<string, Chart>;
}

/**
 * ChartManager
 * ------------
 * Manages chart creation, rendering, and cleanup operations
 * for all charts in the Macros plugin.
 * Enhanced with kJ support for energy unit display.
 */
export class ChartManager {
  private plugin: MacrosPlugin;
  private chartLoader: ChartLoader = ChartLoader.getInstance();

  constructor(plugin: MacrosPlugin) {
    this.plugin = plugin;

    Chart.register(...registerables);
    (window as ExtendedWindow).Chart = Chart;

    if (!(window as ExtendedWindow).macroCharts) {
      (window as ExtendedWindow).macroCharts = {};
    }
  }

  /**
   * Draws a macros pie chart with nutrition data
   * Enhanced with kJ support
   */
  async drawMacrospc(id: string | string[], el: HTMLElement, width = 300, height = 300) {
    try {
      // Ensure Chart.js is loaded first - this is critical
      await this.chartLoader.loadChart();

      // Clear any existing content and add container class
      el.empty();
      el.addClass('macrospc-container');

      let ids: string[];
      if (Array.isArray(id)) {
        ids = id;
      } else if (typeof id === 'string' && id.includes(',')) {
        ids = id
          .split(',')
          .map((i) => i.trim())
          .filter((i) => i.length > 0);
      } else {
        ids = [id];
      }

      ids = ids.filter((i) => i && i.trim() !== '');
      if (ids.length === 0) {
        this.plugin.logger.error(`No valid IDs found in: ${id}`);
        el.createEl('div', { text: t('charts.errors.noIdsProvided') });
        return;
      }

      const combinedId = ids.join(',');

      // Create dashboard container with proper error handling
      const dashboardContainer = el.createDiv({ cls: 'macro-dashboard' });

      // Show loading state
      const loadingEl = dashboardContainer.createEl('div', {
        cls: 'macrospc-loading',
        text: t('charts.loading'),
      });

      // Data loading phase - with better error handling
      interface DataLoadResult {
        id: string;
        success: boolean;
        data: string[];
      }

      const dataLoadResults: DataLoadResult[] = [];
      for (const currentId of ids) {
        try {
          this.plugin.logger.debug(`Loading data for ID: ${currentId}`);

          // Force fresh data load with timeout
          const freshDataPromise = this.plugin.dataManager.getFullMacrosData(currentId);
          const timeoutPromise = new Promise<string[]>((_, reject) =>
            window.setTimeout(() => reject(new Error('Data load timeout')), 5000)
          );

          const freshData = (await Promise.race([freshDataPromise, timeoutPromise]));

          if (freshData && Array.isArray(freshData) && freshData.length > 0) {
            this.plugin.dataManager.macroTables.set(currentId, freshData);
            this.plugin.logger.debug(`Loaded ${freshData.length} lines for ID: ${currentId}`);
            dataLoadResults.push({ id: currentId, success: true, data: freshData });
          } else {
            this.plugin.logger.warn(`No data found for ID: ${currentId}`);
            dataLoadResults.push({ id: currentId, success: false, data: [] });
          }
        } catch (error) {
          this.plugin.logger.error(`Error loading data for ID: ${currentId}:`, error);
          dataLoadResults.push({ id: currentId, success: false, data: [] });
        }
      }

      // Check if we have any successful data loads
      const successfulLoads = dataLoadResults.filter(
        (result): result is DataLoadResult => result.success
      );
      if (successfulLoads.length === 0) {
        loadingEl.textContent = t('charts.noData', { ids: ids.join(', ') });
        return;
      }

      // Remove loading indicator
      loadingEl.remove();

      // Create header with better state management
      const _allDates = ids
        .map((id) => {
          const parsed = Date.parse(id);
          return isNaN(parsed) ? null : { id, date: new Date(parsed) };
        })
        .filter((d): d is { id: string; date: Date } => d !== null)
        .sort((a, b) => b.date.getTime() - a.date.getTime());

      const dashboardHeader = dashboardContainer.createDiv({
        cls: 'macroscalc-dashboard-header macro-dashboard-header',
      });

      const headerContent = dashboardHeader.createDiv({
        cls: 'macroscalc-header-content',
      });

      // Use the localized chart title formatter
      const dynamicHeaderText = formatChartTitle(undefined, ids);

      headerContent.createSpan({
        cls: 'macroscalc-header-title',
        text: dynamicHeaderText,
      });

      const toggleButton = headerContent.createSpan({
        cls: 'macroscalc-toggle-button toggle-icon',
      });

      // Load collapse state
      const isCollapsed = MacrosState.getChartCollapsedState(combinedId, this.plugin);
      this.plugin.logger.debug(`Retrieved collapse state for ${combinedId}: ${isCollapsed}`);

      if (isCollapsed) {
        toggleButton.classList.add('collapsed');
        dashboardHeader.classList.add('collapsed');
      }

      // Create flex container
      const flexContainer = dashboardContainer.createDiv({ cls: 'macro-dashboard-flex-container' });

      if (isCollapsed) {
        flexContainer.classList.add('collapsed');
      }

      // Chart container with explicit sizing
      const chartContainer = flexContainer.createDiv({ cls: 'macro-pie-chart-container' });
      const canvas = chartContainer.createEl('canvas', {
        attr: {
          'data-width': width.toString(),
          'data-height': height.toString(),
        },
      });
      canvas.width = width;
      canvas.height = height;

      // Summary container
      const summaryContainer = flexContainer.createDiv({
        cls: 'macro-pie-chart-summary-container',
      });

      // Get canvas context with error handling
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        el.createEl('div', { text: t('charts.error') });
        return;
      }

      // Calculate totals with better error handling
      let totalProtein = 0,
        totalFat = 0,
        totalCarbs = 0,
        totalCalories = 0;
      const allResults: {
        id: string;
        result: { protein: number; fat: number; carbs: number; calories: number };
      }[] = [];

      // Process each successful data load
      for (const loadResult of successfulLoads) {
        try {
          const result = await this.plugin.calculateMacrosFromLinesAsync(loadResult.data);
          allResults.push({
            id: loadResult.id,
            result: {
              protein: parseFloat(result.protein.toFixed(1)),
              fat: parseFloat(result.fat.toFixed(1)),
              carbs: parseFloat(result.carbs.toFixed(1)),
              calories: parseFloat(result.calories.toFixed(1)),
            },
          });

          this.plugin.logger.debug(
            `Calculated for ${loadResult.id}: protein=${result.protein.toFixed(1)}g, fat=${result.fat.toFixed(1)}g, carbs=${result.carbs.toFixed(1)}g, calories=${result.calories.toFixed(1)}`
          );
        } catch (error) {
          this.plugin.logger.error(`Error calculating macros for ID ${loadResult.id}:`, error);
        }
      }

      // Aggregate totals
      for (const item of allResults) {
        totalProtein += item.result.protein;
        totalFat += item.result.fat;
        totalCarbs += item.result.carbs;
        totalCalories += item.result.calories;
      }

      totalProtein = parseFloat(totalProtein.toFixed(1));
      totalFat = parseFloat(totalFat.toFixed(1));
      totalCarbs = parseFloat(totalCarbs.toFixed(1));
      totalCalories = parseFloat(totalCalories.toFixed(1));

      this.plugin.logger.debug(
        `Total calculated: protein=${totalProtein}g, fat=${totalFat}g, carbs=${totalCarbs}g, calories=${totalCalories}`
      );

      const totalMacros = totalProtein + totalFat + totalCarbs;

      if (totalMacros <= 0) {
        el.createEl('div', { text: t('charts.noMacros', { ids: ids.join(', ') }) });
        return;
      }

      // Create summary with energy unit support
      const calorieDiv = summaryContainer.createDiv({ cls: 'macro-summary-item' });

      // Enhanced calories display with kJ support
      const currentEnergyUnit = this.plugin.settings.energyUnit;
      let calorieDisplayValue: string;
      let calorieTooltip: string;

      if (currentEnergyUnit === 'kJ') {
        const kjValue = convertEnergyUnit(totalCalories, 'kcal', 'kJ');
        calorieDisplayValue = `${kjValue.toFixed(1)} kJ`;
        calorieTooltip = `${totalCalories.toFixed(1)} kcal = ${kjValue.toFixed(1)} kJ`;
      } else {
        calorieDisplayValue = `${totalCalories.toFixed(1)} kcal`;
        calorieTooltip = `${totalCalories.toFixed(1)} kcal`;
      }

      calorieDiv.createSpan({ cls: 'macro-summary-label', text: t('charts.calories') });
      const calorieValueSpan = calorieDiv.createSpan({
        cls: 'macro-summary-value',
        text: calorieDisplayValue,
      });

      // Add tooltip to show both units
      if (currentEnergyUnit === 'kJ') {
        calorieValueSpan.setAttribute('title', calorieTooltip);
      }

      this.createMetricCard(
        summaryContainer,
        t('table.headers.protein'),
        totalProtein,
        totalMacros,
        this.plugin.settings.proteinColor
      );
      this.createMetricCard(
        summaryContainer,
        t('table.headers.fat'),
        totalFat,
        totalMacros,
        this.plugin.settings.fatColor
      );
      this.createMetricCard(
        summaryContainer,
        t('table.headers.carbs'),
        totalCarbs,
        totalMacros,
        this.plugin.settings.carbsColor
      );

      // Create chart with retry logic
      const chartId = `macro-pie-${combinedId}`;
      canvas.id = chartId;

      // Add a small delay to ensure DOM is ready
      await new Promise((resolve) => window.setTimeout(resolve, 50));

      // Verify Chart.js is still available
      if (!window.Chart) {
        this.plugin.logger.error('Chart.js not available when creating pie chart');
        el.createEl('div', { text: t('charts.error') });
        return;
      }

      // Create the pie chart with error handling
      try {
        const chart = this.createPieChart(
          ctx,
          chartId,
          [totalProtein, totalFat, totalCarbs],
          [t('table.headers.protein'), t('table.headers.fat'), t('table.headers.carbs')],
          [
            this.plugin.settings.proteinColor,
            this.plugin.settings.fatColor,
            this.plugin.settings.carbsColor,
          ],
          totalMacros
        );

        if (!chart) {
          throw new Error('Chart creation failed');
        }

        this.plugin.logger.debug(`Successfully created pie chart with ID: ${chartId}`);
      } catch (chartError) {
        this.plugin.logger.error('Error creating pie chart:', chartError);
        el.createEl('div', { text: t('charts.error') });
        return;
      }

      // Setup header click handler
      const headerClickHandler = (e: Event) => {
        const mouseEvent = e as MouseEvent;
        mouseEvent.preventDefault();
        mouseEvent.stopPropagation();

        const currentCollapsedState = toggleButton.classList.contains('collapsed');
        const newCollapsedState = !currentCollapsedState;

        toggleButton.classList.toggle('collapsed', newCollapsedState);
        dashboardHeader.classList.toggle('collapsed', newCollapsedState);
        flexContainer.classList.toggle('collapsed', newCollapsedState);

        MacrosState.saveChartCollapsedState(combinedId, this.plugin, newCollapsedState);

        this.plugin.logger.debug(
          `Toggle header clicked, new state: ${newCollapsedState ? 'collapsed' : 'expanded'}`
        );
      };

      // Use plugin's registerDomListener for proper cleanup
      this.plugin.registerDomListener(dashboardHeader, 'click', headerClickHandler);

      // Register containers for refresh
      for (const currentId of ids) {
        if (!this.plugin.dataManager.macrospcContainers.has(currentId)) {
          this.plugin.dataManager.macrospcContainers.set(currentId, new Set());
        }
        const containerSet = this.plugin.dataManager.macrospcContainers.get(currentId);
        if (containerSet) {
          containerSet.add(el);
        }
      }

      if (!this.plugin.dataManager.macrospcContainers.has(combinedId)) {
        this.plugin.dataManager.macrospcContainers.set(combinedId, new Set());
      }
      const containerSet = this.plugin.dataManager.macrospcContainers.get(combinedId);
      if (containerSet) {
        containerSet.add(el);
      }
    } catch (err) {
      this.plugin.logger.error('drawMacrospc error', err);
      el.empty();
      el.createEl('div', {
        text: t('charts.error'),
        cls: 'macrospc-error',
      });
    }
  }

  private createMetricCard(
    container: HTMLElement,
    label: string,
    value: number,
    total: number,
    color: string
  ) {
    const itemDiv = container.createDiv({ cls: 'macro-summary-item' });

    const indicator = itemDiv.createSpan({ cls: 'macro-color-indicator' });
    DOMUtils.setCSSProperty(indicator, '--indicator-color', color);

    itemDiv.createSpan({ cls: 'macro-summary-label', text: `${label}:` });

    const progressContainer = itemDiv.createDiv({ cls: 'macro-pie-progress-container' });

    const progressBar = progressContainer.createDiv({ cls: 'macro-pie-progress-bar' });
    DOMUtils.setCSSProperty(progressBar, '--progress-color', color);

    const percentage = Math.round((value / total) * 100);
    const roundedPercentage = Math.round(percentage / 5) * 5;
    progressBar.classList.add(`pie-progress-width-${roundedPercentage}`);
    DOMUtils.setCSSProperty(progressBar, '--progress-width', `${percentage}%`);

    progressContainer.createDiv({
      cls: 'macro-pie-progress-text',
      text: `${value.toFixed(1)}g (${percentage}%)`,
    });
  }

  public createPieChart(
    ctx: CanvasRenderingContext2D,
    chartId: string,
    data: number[],
    labels: string[],
    colors: string[],
    totalValue?: number
  ): Chart | null {
    try {
      // Validate inputs
      if (!ctx) {
        this.plugin.logger.error('No canvas context provided to createPieChart');
        return null;
      }

      if (!data || data.length === 0) {
        this.plugin.logger.error('No data provided to createPieChart');
        return null;
      }

      if (!labels || labels.length !== data.length) {
        this.plugin.logger.error('Labels array length does not match data array length');
        return null;
      }

      if (!colors || colors.length !== data.length) {
        this.plugin.logger.error('Colors array length does not match data array length');
        return null;
      }

      // Check if Chart.js is available
      const ChartConstructor = (window as ExtendedWindow).Chart;
      if (!ChartConstructor) {
        this.plugin.logger.error('Chart.js not available in createPieChart');
        return null;
      }

      this.plugin.logger.debug(`Creating pie chart with ID: ${chartId}`);

      // Destroy any existing chart with this ID
      this.chartLoader.destroyChart(chartId);

      const total = totalValue || data.reduce((sum, val) => sum + val, 0);

      if (total <= 0) {
        this.plugin.logger.error('Total value is zero or negative, cannot create pie chart');
        return null;
      }

      // Create chart configuration with better error handling
      const config: ChartConfiguration = {
        type: 'pie',
        data: {
          labels: labels,
          datasets: [
            {
              data: data,
              backgroundColor: colors,
              borderColor: 'rgba(255, 255, 255, 0.4)',
              borderWidth: 1,
              hoverBorderWidth: 2,
              hoverBorderColor: 'rgba(255, 255, 255, 0.9)',
            },
          ],
        },
        options: {
          responsive: false,
          maintainAspectRatio: false,
          animation: {
            duration: 800,
            easing: 'easeOutQuart',
          },
          layout: {
            padding: 5,
          },
          plugins: {
            legend: {
              display: false,
            },
            tooltip: {
              backgroundColor: 'rgba(0, 0, 0, 0.8)',
              titleFont: { weight: 'bold', size: 14 },
              bodyFont: { size: 12 },
              cornerRadius: 6,
              padding: 8,
              callbacks: {
                label: function (context: TooltipItem<'pie'>) {
                  const label = context.label || '';
                  const value = context.raw as number;
                  const percentage = ((value / total) * 100).toFixed(1) + '%';
                  return `${label}: ${value.toFixed(1)}g (${percentage})`;
                },
              },
            },
          },
        },
      };

      this.plugin.logger.debug('Chart configuration created, attempting to instantiate chart');

      // Create the chart with try-catch
      let chart;
      try {
        chart = new ChartConstructor(ctx, config);
      } catch (chartCreationError) {
        this.plugin.logger.error('Error during Chart.js instantiation:', chartCreationError);
        return null;
      }

      if (!chart) {
        this.plugin.logger.error('Chart creation returned null/undefined');
        return null;
      }

      this.plugin.logger.debug('Chart instance created successfully');

      // Register the chart for management
      this.chartLoader.registerChart(chartId, chart);

      // Maintain backward compatibility with global charts object
      if (!(window as ExtendedWindow).macroCharts) {
        (window as ExtendedWindow).macroCharts = {};
      }
      (window as ExtendedWindow).macroCharts[chartId] = chart;

      this.plugin.logger.debug(`Pie chart created and registered with ID: ${chartId}`);
      return chart;
    } catch (error) {
      this.plugin.logger.error('Unexpected error in createPieChart:', error);
      return null;
    }
  }

  public createLineChart(
    ctx: CanvasRenderingContext2D,
    chartId: string,
    labels: string[],
    datasets: {
      label: string;
      data: number[];
      borderColor: string;
      backgroundColor: string;
    }[]
  ): Chart {
    const ChartConstructor = (window as ExtendedWindow).Chart;
    if (!ChartConstructor) {
      throw new Error('Chart.js not loaded properly');
    }

    this.chartLoader.destroyChart(chartId);

    // Enhanced line chart configuration with energy unit support
    const currentEnergyUnit = getCurrentEnergyUnitString();
    const isKjUnit = currentEnergyUnit === 'kJ';

    const config: ChartConfiguration = {
      type: 'line',
      data: {
        labels,
        datasets: datasets.map(
          (dataset) =>
            ({
              ...dataset,
              tension: 0.2,
              fill: false,
              pointRadius: 4,
              pointHoverRadius: 6,
            })
        ),
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            position: 'top',
          },
          tooltip: {
            callbacks: {
              label: function (context: TooltipItem<'line'>) {
                let value = context.parsed.y.toFixed(1);
                let unit = '';

                // Check if this is a calorie dataset and convert if needed
                if (context.dataset.label?.toLowerCase().includes('calorie') && isKjUnit) {
                  const kjValue = convertEnergyUnit(context.parsed.y, 'kcal', 'kJ');
                  value = kjValue.toFixed(1);
                  unit = ' kJ';
                } else if (context.dataset.label?.toLowerCase().includes('calorie')) {
                  unit = ' kcal';
                } else {
                  unit = 'g';
                }

                return `${context.dataset.label}: ${value}${unit}`;
              },
            },
          },
        },
        scales: {
          x: {
            title: {
              display: true,
              text: 'Table ID (Date)',
            },
          },
          y: {
            beginAtZero: true,
            title: {
              display: true,
              text: `Grams / ${currentEnergyUnit}`,
            },
          },
        },
      },
    };

    const chart = new ChartConstructor(ctx, config);

    this.chartLoader.registerChart(chartId, chart);

    if (!(window as ExtendedWindow).macroCharts) {
      (window as ExtendedWindow).macroCharts = {};
    }
    (window as ExtendedWindow).macroCharts[chartId] = chart;

    return chart;
  }

  async redrawAllMacrospc() {
    try {
      const idsToRefresh = new Set([...this.plugin.dataManager.macroTables.keys()]);

      for (const [id, _] of this.plugin.dataManager.macrospcContainers.entries()) {
        if (typeof id === 'string') {
          if (id.includes(',')) {
            id.split(',')
              .map((i) => i.trim())
              .forEach((singleId) => {
                idsToRefresh.add(singleId);
              });
          } else {
            idsToRefresh.add(id);
          }
        }
      }

      for (const id of idsToRefresh) {
        try {
          const loaded = await this.plugin.dataManager.getFullMacrosData(id);
          if (loaded && loaded.length > 0) {
            this.plugin.dataManager.macroTables.set(id, loaded);
          }
        } catch (error) {
          this.plugin.logger.error(`Error reloading macro table ${id}: ${error}`);
        }
      }

      for (const [id, containerSet] of this.plugin.dataManager.macrospcContainers.entries()) {
        const aliveElements = new Set<HTMLElement>();
        for (const el of containerSet) {
          if (el.isConnected) {
            // Get dimensions from data attributes if available
            const widthAttr = el.getAttribute('data-width');
            const heightAttr = el.getAttribute('data-height');
            const width = widthAttr ? parseInt(widthAttr) : 300;
            const height = heightAttr ? parseInt(heightAttr) : 300;

            await this.drawMacrospc(id, el, width, height);
            aliveElements.add(el);
          }
        }
        this.plugin.dataManager.macrospcContainers.set(id, aliveElements);
      }
    } catch (error) {
      this.plugin.logger.error('Error in redrawAllMacrospc:', error);
    }
  }

  async redrawAllMacrocalc(): Promise<void> {
    try {
      this.plugin.logger.debug('Redrawing all macroscalc tables');

      for (const id of this.plugin.dataManager.macroTables.keys()) {
        const freshData = await this.plugin.dataManager.getFullMacrosData(id);
        if (freshData && freshData.length > 0) {
          this.plugin.dataManager.macroTables.set(id, freshData);
          this.plugin.logger.debug(`Refreshed data for ${id}: ${freshData.length} lines`);
        } else {
          this.plugin.logger.debug(`No data found for ${id} during refresh`);
        }
      }

      if (
        this.plugin.dataManager._activeMacrosCalcRenderers &&
        this.plugin.dataManager._activeMacrosCalcRenderers.size > 0
      ) {
        this.plugin.logger.debug(
          `Updating ${this.plugin.dataManager._activeMacrosCalcRenderers.size} macroscalc renderers`
        );

        for (const renderer of this.plugin.dataManager._activeMacrosCalcRenderers) {
          try {
            renderer.setNeedsRefresh();

            const ids = renderer.getIds();
            this.plugin.logger.debug(`Recalculating for IDs: ${ids.join(',')}`);
            const { aggregate, breakdown } = this.plugin.processNutritionalDataFromLines(ids);

            await renderer.render(aggregate, breakdown);
            this.plugin.logger.debug(`Renderer updated successfully`);
          } catch (error) {
            this.plugin.logger.error('Error updating macroscalc renderer:', error);
          }
        }
      } else {
        this.plugin.logger.debug('No active macroscalc renderers to update');
      }
    } catch (error) {
      this.plugin.logger.error('Error in redrawAllMacrocalc:', error);
    }
  }

  /**
   * Cleanup handled by plugin's onunload - no explicit cleanup needed
   */
  cleanup(): void {
    try {
      this.chartLoader.destroyAllCharts();

      const windowExt = window as ExtendedWindow;
      if (windowExt.macroCharts) {
        Object.values(windowExt.macroCharts).forEach((chart: Chart) => {
          if (chart && typeof chart.destroy === 'function') {
            try {
              chart.destroy();
            } catch (err) {
              this.plugin.logger.debug(`Error destroying legacy chart: ${err}`);
            }
          }
        });
        windowExt.macroCharts = {};
      }
    } catch (error) {
      this.plugin.logger.error('Error during ChartManager cleanup:', error);
    }
  }
}

import { TFolder, TFile, normalizePath } from 'obsidian';
import MacrosPlugin from '../main';
import { processNutritionalData } from '../utils/nutritionUtils';
import { fetchFatSecretMicronutrients, FoodItem } from '../core/api';
import { UnifiedFoodResult } from '../core/search';
import { OffFoodResult } from '../core/openFoodFacts';
import {
  MICRONUTRIENT_KEYS,
  MICRONUTRIENT_MAP,
  formatMicroAmount,
} from '../utils/nutrition/micronutrients';

// Constant used for interactive lines in macros blocks.
const INTERACTIVE_PREFIX = 'interactive:';

// Type definitions for the structured data
interface MacrosStructure {
  meals: Map<string, Map<string, number>>; // mealName -> (foodName -> quantity)
  individualItems: Map<string, number>; // foodName -> quantity
}

interface NewItemsStructure {
  meals: Map<string, Map<string, number>>;
  individualItems: Map<string, number>;
}

// FIX: Add proper type for active renderers instead of any
interface MacroTotals {
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
}

interface CalcBreakdown {
  id: string;
  totals: MacroTotals;
}

interface MacrosCalcRenderer {
  el: HTMLElement;
  getIds: () => string[];
  render: (aggregate: MacroTotals, breakdown: CalcBreakdown[]) => Promise<void>;
  setNeedsRefresh?: () => void;
}

/**
 * DataManager
 * -----------
 * Manages all data-related operations for the Macros Plugin,
 * including cache management, file operations, and data fetching.
 */
export class DataManager {
  private plugin: MacrosPlugin;

  // Maps and caches moved from main class
  additionalMacros: Map<string, string[]> = new Map();
  macroTables: Map<string, string[]> = new Map();
  macrospcContainers: Map<string, Set<HTMLElement>> = new Map();
  macrocalcContainers: Set<HTMLElement> = new Set();
  // FIX: Use proper type instead of any
  _activeMacrosCalcRenderers: Set<MacrosCalcRenderer> = new Set();
  _registeredDomElements: { el: HTMLElement; type: string; handler: EventListener }[] = [];

  // File cache system
  private fileCache: Map<string, TFile[]> = new Map();
  private contentCache: Map<string, string> = new Map();

  // CONCURRENCY LOCK: A simple update mutex to serialize file modifications
  private updateMutex: Promise<void> = Promise.resolve();

  constructor(plugin: MacrosPlugin) {
    this.plugin = plugin;
    this._activeMacrosCalcRenderers = new Set();
    this.additionalMacros = new Map();
  }

  /**
   * Register a DOM event for proper cleanup during plugin unload
   * @param el The HTML element to attach the event to
   * @param type The event type (e.g., 'click')
   * @param handler The event handler function
   */
  public registerDomEvent(el: HTMLElement, type: string, handler: EventListener): void {
    el.addEventListener(type, handler);
    this._registeredDomElements.push({ el, type, handler });
  }

  /**
   * Invalidates the file cache. Call this on file modifications.
   */
  invalidateFileCache(): void {
    this.fileCache.clear();
    this.contentCache.clear();
  }

  /**
   * Clears all caches and data structures. More comprehensive than invalidateFileCache.
   */
  clearAllCaches(): void {
    this.fileCache.clear();
    this.contentCache.clear();
    this.macroTables.clear();
    this.additionalMacros.clear();
  }

  /**
   * Reads the content of a file, with caching for performance
   * @param file The file to read
   * @param forceRefresh Whether to force a fresh read
   * @returns The file content as a string
   */
  async readFileContent(file: TFile, forceRefresh = false): Promise<string> {
    try {
      // Check if we need to bypass the cache
      if (forceRefresh || !this.contentCache.has(file.path)) {
        const content = await this.plugin.app.vault.cachedRead(file);
        this.contentCache.set(file.path, content);
        return content;
      }

      return this.contentCache.get(file.path) || '';
    } catch (error) {
      this.plugin.logger.error(`Error reading file ${file.path}:`, error);
      throw error;
    }
  }

  /**
   * Gets the active file in the editor
   * @returns The active file or null if none
   */
  getActiveFile(): TFile | null {
    return this.plugin.app.workspace.getActiveFile();
  }

  /**
   * Centralizes the logic for finding and extracting macros blocks from files
   * @param id The ID of the macros block
   * @param includeAllLines Whether to include bullet points
   * @returns The extracted lines or null if not found
   */
  async getMacrosBlockContent(id: string, includeAllLines = true): Promise<string[] | null> {
    try {
      const files = this.plugin.app.vault.getMarkdownFiles();

      // Escape special characters in the ID to ensure accurate regex matching
      const safeId = id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const regex = new RegExp('```\\s*macros\\s+id:\\s*' + safeId + '\\s*\\n([\\s\\S]*?)```', 'm');

      for (const file of files) {
        try {
          // Read the full file content
          const content = await this.readFileContent(file);

          // Look for macros blocks with this ID
          const match = content.match(regex);

          if (match) {
            // Get all lines from the match
            const lines = match[1]
              .split('\n')
              .map((line) => line.trim())
              .filter((line) => line !== '');

            // If we need all lines, return them; otherwise filter out bullet points
            if (includeAllLines) {
              this.plugin.logger.debug(
                `Found ${lines.length} lines for ID: ${id} (including bullets)`
              );
              return lines;
            } else {
              const filteredLines = lines.filter((line) => !line.startsWith('-'));
              this.plugin.logger.debug(
                `Found ${filteredLines.length} lines for ID: ${id} (excluding bullets)`
              );
              return filteredLines;
            }
          }
        } catch (error) {
          this.plugin.logger.error(`Error reading file for ID ${id}:`, error);
        }
      }

      this.plugin.logger.debug(`No macros block found for ID: ${id}`);
      return null;
    } catch (error) {
      this.plugin.logger.error(`Error getting macros block content for ID ${id}:`, error);
      return null;
    }
  }

  /**
   * Modifies a macros block in a file
   * @param id The ID of the macros block
   * @param newLines The new lines to put in the block
   * @returns Whether the update was successful
   */
  async updateMacrosBlock(id: string, newLines: string[]): Promise<boolean> {
    try {
      const files = this.plugin.app.vault.getMarkdownFiles();
      const safeId = id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const regex = new RegExp('```\\s*macros\\s+id:\\s*' + safeId + '\\s*\\n([\\s\\S]*?)```', 'm');

      for (const file of files) {
        const content = await this.readFileContent(file, true);
        const match = content.match(regex);

        if (match) {
          // Create the updated block
          const newBlock = '```macros\nid: ' + id + '\n' + newLines.join('\n') + '\n```';

          // Replace the old block with the updated one
          const newContent = content.replace(match[0], newBlock);

          // Update the file
          await this.plugin.app.vault.modify(file, newContent);

          // Invalidate caches
          this.invalidateFileCache();

          // Update the macroTables cache
          this.macroTables.set(id, newLines);

          // Trigger a metadata update
          this.plugin.app.metadataCache.trigger('changed', file);

          this.plugin.logger.debug(`Updated macros block for ID: ${id}`);
          return true;
        }
      }

      this.plugin.logger.debug(`Could not find macros block for ID: ${id} to update`);
      return false;
    } catch (error) {
      this.plugin.logger.error(`Error updating macros block for ID ${id}:`, error);
      return false;
    }
  }

  /**
   * Creates a reusable callback function for handling selected food items
   * Updated to work with both FatSecret and USDA (UnifiedFoodResult) formats
   * FIXED: Proper file existence checking and error handling
   */
  createFoodItemCallback() {
    return async (selectedFood: UnifiedFoodResult | FoodItem) => {
      try {
        let foodName: string;
        let servingSize: string;
        let nutritionalData: {
          calories: string;
          protein: string;
          fat: string;
          carbs: string;
          fiber?: string;
          sugars?: string;
          salt?: string;
        };
        let additionalMetadata: {
          source: string;
          brands?: string;
          categories?: string;
          ingredients?: string;
          nutritionGrade?: string;
          novaGroup?: number;
          ecoscore?: string;
          dataQuality?: string;
          completeness?: number;
          imageUrl?: string;
        } = {
          source: 'unknown',
        };

        // Check if this is a UnifiedFoodResult (from the new search system).
        // The legacy FatSecret FoodItem has no `source` field.
        if ('source' in selectedFood) {
          foodName = selectedFood.name;

          if (selectedFood.source === 'openfoodfacts') {
            // Handle Open Food Facts format
            servingSize = `${selectedFood.gramsServing}g`;

            // Extract nutrition from description or raw data
            if (selectedFood.raw && typeof selectedFood.raw === 'object') {
              const offData = selectedFood.raw as OffFoodResult;
              nutritionalData = {
                calories: offData.calories?.toString() || '0',
                protein: offData.protein?.toString() || '0',
                fat: offData.fat?.toString() || '0',
                carbs: offData.carbs?.toString() || '0',
                fiber: offData.fiber?.toString(),
                sugars: offData.sugars?.toString(),
                salt: offData.salt?.toString(),
              };
            } else {
              // Fallback: parse from description
              nutritionalData = this.extractNutritionalDataFromDescription(
                selectedFood.description
              );
            }

            // Set Open Food Facts specific metadata
            additionalMetadata = {
              source: 'openfoodfacts',
              brands: selectedFood.brandName,
              categories: selectedFood.categories,
              ingredients: selectedFood.ingredients,
              nutritionGrade: selectedFood.nutritionGrade,
              novaGroup: selectedFood.novaGroup,
              ecoscore: selectedFood.ecoscore,
              dataQuality: selectedFood.dataQuality,
              completeness: selectedFood.completeness,
              imageUrl: selectedFood.imageUrl,
            };
          } else if (selectedFood.source === 'usda') {
            // Handle USDA format (existing code)
            servingSize = `${selectedFood.gramsServing}g`;
            const description = selectedFood.description;

            const caloriesMatch = description.match(/Calories:\s*(\d+(?:\.\d+)?)kcal/i);
            const fatMatch = description.match(/Fat:\s*(\d+(?:\.\d+)?)g/i);
            const carbsMatch = description.match(/Carbs:\s*(\d+(?:\.\d+)?)g/i);
            const proteinMatch = description.match(/Protein:\s*(\d+(?:\.\d+)?)g/i);

            nutritionalData = {
              calories: caloriesMatch ? caloriesMatch[1] : '0',
              fat: fatMatch ? fatMatch[1] : '0',
              carbs: carbsMatch ? carbsMatch[1] : '0',
              protein: proteinMatch ? proteinMatch[1] : '0',
            };

            additionalMetadata = {
              source: 'usda',
              ...(selectedFood.brandName && { brands: selectedFood.brandName }),
            };
          } else {
            // Handle FatSecret format (existing code)
            const fsRaw = selectedFood.raw as { food_description?: string } | undefined;
            if (fsRaw && fsRaw.food_description) {
              servingSize = this.extractServingSize(fsRaw.food_description);
              nutritionalData = this.extractNutritionalData(fsRaw.food_description);
            } else {
              servingSize = `${selectedFood.gramsServing}g`;
              nutritionalData = this.extractNutritionalDataFromDescription(
                selectedFood.description
              );
            }

            additionalMetadata = {
              source: 'fatsecret',
            };
          }
        } else {
          // Handle legacy FoodItem format (existing code)
          foodName = selectedFood.food_name;
          servingSize = this.extractServingSize(selectedFood.food_description);
          nutritionalData = this.extractNutritionalData(selectedFood.food_description);
          additionalMetadata = {
            source: 'fatsecret',
          };
        }

        // Validate that we have the required data
        if (!foodName) {
          throw new Error('Food name is missing');
        }

        // Narrowed views for the branches below (selectedFood is a union here).
        const unified: UnifiedFoodResult | undefined =
          'source' in selectedFood ? selectedFood : undefined;
        const legacyItem: FoodItem | undefined =
          'source' in selectedFood ? undefined : selectedFood;

        // ---- Resolve micronutrients ----------------------------------------
        // USDA and Open Food Facts attach canonical micronutrients (per 100g)
        // directly to the unified result. FatSecret only returns macros from
        // search, so fetch detailed per-serving data on demand via food.get.v4.
        let micronutrients: Record<string, number> = {};
        if (unified?.micronutrients && typeof unified.micronutrients === 'object') {
          micronutrients = { ...unified.micronutrients };
        }

        if (Object.keys(micronutrients).length === 0 && additionalMetadata.source === 'fatsecret') {
          const foodId: string | undefined =
            (unified?.raw as { food_id?: string } | undefined)?.food_id ?? legacyItem?.food_id;
          const fsKey = this.plugin.settings.fatSecretApiKey?.trim();
          const fsSecret = this.plugin.settings.fatSecretApiSecret?.trim();
          if (foodId && fsKey && fsSecret) {
            try {
              const fsMicros = await fetchFatSecretMicronutrients(
                this.plugin.app,
                String(foodId),
                fsKey,
                fsSecret
              );
              if (fsMicros) {
                micronutrients = fsMicros.micronutrients;
              }
            } catch (microErr) {
              this.plugin.logger.error('Error fetching FatSecret micronutrients:', microErr);
            }
          }
        }

        // Source micronutrients are expressed per 100g; rescale to the serving
        // size actually stored in the note so they match the macros and the
        // scaling done by extractMicronutrients().
        const storedServingGrams = parseFloat(String(servingSize));
        if (
          Object.keys(micronutrients).length > 0 &&
          Number.isFinite(storedServingGrams) &&
          storedServingGrams > 0 &&
          storedServingGrams !== 100
        ) {
          const microScale = storedServingGrams / 100;
          const rescaled: Record<string, number> = {};
          for (const [k, v] of Object.entries(micronutrients)) {
            rescaled[k] = v * microScale;
          }
          micronutrients = rescaled;
        }

        // Create safe filename for file operations
        const safeFileName = this.createSafeFileName(foodName);
        const fileName = `${safeFileName}.md`;

        // Enhanced frontmatter with Open Food Facts support
        let frontmatter = `---
calories: ${nutritionalData.calories}
protein: ${nutritionalData.protein}
fat: ${nutritionalData.fat}
carbs: ${nutritionalData.carbs}
serving_size: ${servingSize}`;

        // Add optional nutrition fields for Open Food Facts
        if (nutritionalData.fiber) {
          frontmatter += `\nfiber: ${nutritionalData.fiber}`;
        }
        if (nutritionalData.sugars) {
          frontmatter += `\nsugars: ${nutritionalData.sugars}`;
        }
        if (nutritionalData.salt) {
          frontmatter += `\nsalt: ${nutritionalData.salt}`;
        }

        // Add micronutrient keys (vitamins, minerals, other tracked nutrients).
        // These use the same canonical keys read back by extractMicronutrients().
        for (const key of MICRONUTRIENT_KEYS) {
          const value = micronutrients[key];
          if (value == null || !Number.isFinite(value) || value === 0) continue;
          frontmatter += `\n${key}: ${formatMicroAmount(value)}`;
        }

        // Add source-specific metadata
        frontmatter += `\nsource: ${additionalMetadata.source}`;

        if (additionalMetadata.source === 'openfoodfacts') {
          // Add Open Food Facts specific fields
          if (unified?.id) {
            frontmatter += `\noff_code: ${unified.id.replace('off_', '')}`;
          }
          if (additionalMetadata.brands) {
            frontmatter += `\nbrands: "${additionalMetadata.brands}"`;
          }
          if (additionalMetadata.categories) {
            frontmatter += `\ncategories: "${additionalMetadata.categories}"`;
          }
          if (additionalMetadata.nutritionGrade) {
            frontmatter += `\nnutrition_grade: ${additionalMetadata.nutritionGrade}`;
          }
          if (additionalMetadata.novaGroup) {
            frontmatter += `\nnova_group: ${additionalMetadata.novaGroup}`;
          }
          if (additionalMetadata.ecoscore) {
            frontmatter += `\necoScore: ${additionalMetadata.ecoscore}`;
          }
          if (additionalMetadata.dataQuality) {
            frontmatter += `\ndata_quality: ${additionalMetadata.dataQuality}`;
          }
          if (additionalMetadata.completeness) {
            frontmatter += `\ncompleteness: ${additionalMetadata.completeness}`;
          }
          if (additionalMetadata.imageUrl) {
            frontmatter += `\nimage_url: "${additionalMetadata.imageUrl}"`;
          }
        } else if (additionalMetadata.source === 'usda') {
          // Add USDA specific fields (existing code)
          if (unified?.id) {
            frontmatter += `\nfdc_id: ${unified.id.replace('usda_', '')}`;
          }
          if (unified?.dataType) {
            frontmatter += `\ndata_type: ${unified.dataType}`;
          }
          if (unified?.isFoundation) {
            frontmatter += `\nfoundation_food: true`;
          }
          if (unified?.brandName) {
            frontmatter += `\nbrand_name: "${unified.brandName}"`;
          }
        }

        frontmatter += `\ncreated: ${new Date().toISOString()}
---

# ${foodName}`;

        // Enhanced content with Open Food Facts information
        if (additionalMetadata.source === 'openfoodfacts') {
          frontmatter += `

## Product Information
`;
          if (additionalMetadata.brands) {
            frontmatter += `**Brands:** ${additionalMetadata.brands}  \n`;
          }
          if (additionalMetadata.categories) {
            frontmatter += `**Categories:** ${additionalMetadata.categories}  \n`;
          }
          if (additionalMetadata.nutritionGrade) {
            frontmatter += `**Nutrition Grade:** ${additionalMetadata.nutritionGrade.toUpperCase()} (Nutri-Score)  \n`;
          }
          if (additionalMetadata.novaGroup) {
            const novaLabels = [
              '',
              'Unprocessed or minimally processed',
              'Processed culinary ingredients',
              'Processed foods',
              'Ultra-processed foods',
            ];
            frontmatter += `**Processing Level:** NOVA ${additionalMetadata.novaGroup} (${novaLabels[additionalMetadata.novaGroup]})  \n`;
          }
          if (additionalMetadata.ecoscore) {
            frontmatter += `**Environmental Impact:** Eco-Score ${additionalMetadata.ecoscore.toUpperCase()}  \n`;
          }
        }

        frontmatter += `

## Nutritional Information (per ${servingSize})
- **Calories:** ${nutritionalData.calories} kcal
- **Protein:** ${nutritionalData.protein}g
- **Fat:** ${nutritionalData.fat}g
- **Carbohydrates:** ${nutritionalData.carbs}g`;

        // Add optional nutrition information
        if (nutritionalData.fiber) {
          frontmatter += `\n- **Fiber:** ${nutritionalData.fiber}g`;
        }
        if (nutritionalData.sugars) {
          frontmatter += `\n- **Sugars:** ${nutritionalData.sugars}g`;
        }
        if (nutritionalData.salt) {
          frontmatter += `\n- **Salt:** ${nutritionalData.salt}g`;
        }

        // Add a readable micronutrient breakdown if any were resolved.
        const microKeysPresent = MICRONUTRIENT_KEYS.filter(
          (k) =>
            micronutrients[k] != null &&
            Number.isFinite(micronutrients[k]) &&
            micronutrients[k] !== 0
        );
        if (microKeysPresent.length > 0) {
          frontmatter += `

## Micronutrients (per ${servingSize})`;
          for (const key of microKeysPresent) {
            const def = MICRONUTRIENT_MAP[key];
            const label = def ? def.label : key;
            const unit = def ? def.unit : '';
            frontmatter += `\n- **${label}:** ${formatMicroAmount(micronutrients[key])}${unit}`;
          }
        }

        // Add ingredients if available
        if (additionalMetadata.ingredients) {
          frontmatter += `

## Ingredients
${additionalMetadata.ingredients}`;
        }

        // Add source attribution
        frontmatter += `

**Source:** `;
        if (additionalMetadata.source === 'openfoodfacts') {
          frontmatter += 'Open Food Facts (Community Database)';
          if (additionalMetadata.dataQuality) {
            frontmatter += ` - Data Quality: ${additionalMetadata.dataQuality.charAt(0).toUpperCase() + additionalMetadata.dataQuality.slice(1)}`;
          }
        } else if (additionalMetadata.source === 'usda') {
          frontmatter += 'USDA FoodData Central';
        } else {
          frontmatter += 'FatSecret Platform API';
        }

        // Add data quality notice for Open Food Facts
        if (
          additionalMetadata.source === 'openfoodfacts' &&
          additionalMetadata.dataQuality !== 'high'
        ) {
          frontmatter += `

> **Note:** This data comes from the Open Food Facts community database. Please verify nutrition information if accuracy is critical for your needs.`;
        }

        // File creation logic (existing code)
        const folderPath = normalizePath(this.plugin.settings.storageFolder);
        const filePath = normalizePath(`${folderPath}/${safeFileName}.md`);

        const folder = this.plugin.app.vault.getFolderByPath(folderPath);
        if (!folder) {
          await this.plugin.app.vault.createFolder(folderPath);
        }

        try {
          await this.plugin.app.vault.create(filePath, frontmatter);
          this.invalidateFileCache();
        } catch (createError) {
          if (createError instanceof Error && createError.message.includes('already exists')) {
            throw new Error(
              'File was created by another process. Please try again with a different name.'
            );
          }
          throw createError;
        }
      } catch (error) {
        this.plugin.logger.error('Error creating food file:', error);
        throw error;
      }
    };
  }
  /**
   * Helper method to extract serving size (keep existing implementation)
   */
  private extractServingSize(description: string): string {
    try {
      const regex = /Per\s*(\d+(\.\d+)?)\s*(g|medium|large|slice|cup|tbsp|oz)/i;
      const match = description.match(regex);
      return match ? `${match[1]}${match[3]}` : '100g';
    } catch (error) {
      console.error('Error extracting serving size:', error);
      return '100g';
    }
  }

  /**
   * Helper method to extract nutritional data (keep existing implementation)
   */
  private extractNutritionalData(description: string): {
    calories: string;
    fat: string;
    carbs: string;
    protein: string;
  } {
    try {
      const caloriesMatch = description.match(/Calories:\s*(\d+(\.\d+)?)kcal/i);
      const fatMatch = description.match(/Fat:\s*(\d+(\.\d+)?)g/i);
      const carbsMatch = description.match(/Carbs:\s*(\d+(\.\d+)?)g/i);
      const proteinMatch = description.match(/Protein:\s*(\d+(\.\d+)?)g/i);
      return {
        calories: caloriesMatch ? caloriesMatch[1] : '0',
        fat: fatMatch ? fatMatch[1] : '0',
        carbs: carbsMatch ? carbsMatch[1] : '0',
        protein: proteinMatch ? proteinMatch[1] : '0',
      };
    } catch (error) {
      console.error('Error extracting nutritional data:', error);
      return { calories: '0', fat: '0', carbs: '0', protein: '0' };
    }
  }

  /**
   * Helper method to extract nutritional data from generic description
   */
  private extractNutritionalDataFromDescription(description: string): {
    calories: string;
    fat: string;
    carbs: string;
    protein: string;
  } {
    // Try multiple patterns for different description formats
    const patterns = [
      // USDA format: "Per 100g - Calories: 52kcal | Fat: 0.2g | Carbs: 13.8g | Protein: 0.3g"
      {
        calories: /Calories:\s*(\d+(?:\.\d+)?)kcal/i,
        fat: /Fat:\s*(\d+(?:\.\d+)?)g/i,
        carbs: /Carbs:\s*(\d+(?:\.\d+)?)g/i,
        protein: /Protein:\s*(\d+(?:\.\d+)?)g/i,
      },
      // Alternative format
      {
        calories: /(\d+(?:\.\d+)?)\s*kcal/i,
        fat: /Fat[:\s]*(\d+(?:\.\d+)?)g/i,
        carbs: /Carb[s]?[:\s]*(\d+(?:\.\d+)?)g/i,
        protein: /Protein[:\s]*(\d+(?:\.\d+)?)g/i,
      },
    ];

    for (const pattern of patterns) {
      const caloriesMatch = description.match(pattern.calories);
      const fatMatch = description.match(pattern.fat);
      const carbsMatch = description.match(pattern.carbs);
      const proteinMatch = description.match(pattern.protein);

      // If we found at least calories, use this pattern
      if (caloriesMatch) {
        return {
          calories: caloriesMatch[1] || '0',
          fat: fatMatch?.[1] || '0',
          carbs: carbsMatch?.[1] || '0',
          protein: proteinMatch?.[1] || '0',
        };
      }
    }

    // Fallback
    return { calories: '0', fat: '0', carbs: '0', protein: '0' };
  }

  /**
   * Helper method to create a safe filename from food name
   * FIXED: More robust filename sanitization
   */
  private createSafeFileName(foodName: string): string {
    return foodName
      .replace(/[<>:"/\\|?*]/g, '') // Remove invalid filename characters
      .replace(/\s+/g, ' ') // Normalize spaces
      .replace(/^\s+|\s+$/g, '') // Trim whitespace
      .substring(0, 100) // Limit length
      .replace(/\.$/, ''); // Remove trailing period if present
  }

  /**
   * Returns the list of files in the given folder, using a cache for performance.
   */
  getFilesInFolder(folderPath: string): TFile[] {
    try {
      // Check cache first
      const cached = this.fileCache.get(folderPath);
      if (cached !== undefined) return cached;

      // Normalize the path
      const normalizedPath = normalizePath(folderPath);

      // Get the folder
      const folder = this.plugin.app.vault.getFolderByPath(normalizedPath);
      if (!folder) {
        // Folder doesn't exist, return empty array
        return [];
      }

      // Gather files recursively
      const files: TFile[] = [];
      this.getFilesInFolderRecursive(folder, files);

      // Cache and return results
      this.fileCache.set(folderPath, files);
      return files;
    } catch (error) {
      this.plugin.logger.error(`Error getting files in folder ${folderPath}:`, error);
      return [];
    }
  }

  /**
   * Helper method to recursively get files in a folder and its subfolders
   */
  private getFilesInFolderRecursive(folder: TFolder, files: TFile[]): void {
    // Iterate through folder children
    folder.children.forEach((child) => {
      if (child instanceof TFile) {
        files.push(child);
      } else if (child instanceof TFolder) {
        this.getFilesInFolderRecursive(child, files);
      }
    });
  }

  /**
   * Find a matching food file by name or partial name
   * Centralized implementation that replaces duplicated code in other components
   * @param foodQuery The food name to search for
   * @returns The matching file or null if not found
   */
  findFoodFile(foodQuery: string): TFile | null {
    if (!foodQuery || foodQuery.trim() === '') {
      return null;
    }

    // Normalize the folder path
    const folderPath = normalizePath(this.plugin.settings.storageFolder);

    // Get files from the folder
    const files = this.getFilesInFolder(folderPath);

    // Look for exact match first (case insensitive)
    const queryLower = foodQuery.toLowerCase();
    const exactMatches = files.filter(
      (f) => f.name.replace(/.md$/, '').toLowerCase() === queryLower
    );
    if (exactMatches.length === 1) {
      return exactMatches[0];
    }

    // If no exact match, look for partial matches
    const partialMatches = files.filter((f) => f.name.toLowerCase().includes(queryLower));
    if (partialMatches.length === 1) {
      return partialMatches[0];
    }

    // If multiple partial matches, log a warning and return null
    if (partialMatches.length > 1) {
      this.plugin.logger.warn(
        `Ambiguous food query "${foodQuery}" matches multiple files: [${partialMatches.map((f) => f.name).join(', ')}]. Please disambiguate.`
      );
      return null;
    }

    // No matches found
    return null;
  }

  /**
   * Find all food files matching a search term
   * @param searchTerm The search term
   * @returns Array of matching files
   */
  findFoodFiles(searchTerm: string): TFile[] {
    if (!searchTerm || searchTerm.trim() === '') {
      return [];
    }

    // Normalize the folder path
    const folderPath = normalizePath(this.plugin.settings.storageFolder);

    // Get files from the folder
    const files = this.getFilesInFolder(folderPath);

    // Return all matches (both exact and partial)
    const searchTermLower = searchTerm.toLowerCase();
    return files.filter((f) => f.name.toLowerCase().includes(searchTermLower));
  }

  /**
   * Gets all food files available in the storage folder
   * @returns Array of all food files
   */
  getAllFoodFiles(): TFile[] {
    // Normalize the folder path
    const folderPath = normalizePath(this.plugin.settings.storageFolder);

    // Get and return all files from the folder
    return this.getFilesInFolder(folderPath);
  }

  /**
   * Gets all food names available in the storage folder
   * @returns Array of food names (without .md extension)
   */
  getAllFoodNames(): string[] {
    return this.getAllFoodFiles().map((file) => file.name.replace(/\.md$/, ''));
  }

  /**
   * Enqueues an update function to serialize file modifications.
   * @param updateFn A function that returns a Promise<void> with the update logic.
   * @returns A Promise that resolves when the queued update has completed.
   */
  private queueUpdate(updateFn: () => Promise<void>): Promise<void> {
    // Capture the prior promise
    const prior = this.updateMutex;

    // Create a new promise that awaits the old one
    return (this.updateMutex = (async () => {
      try {
        // Wait for prior updates to complete
        await prior;

        // Set up a timeout for the update
        const timeoutPromise = new Promise<void>((_resolve, reject) => {
          window.setTimeout(() => reject(new Error('Update timed out')), 30000);
        });

        // Race the update function against the timeout
        await Promise.race([updateFn(), timeoutPromise]);
      } catch (error) {
        this.plugin.logger.error('Error during queued update (or update timed out):', error);
      }
    })());
  }

  /**
   * Updates the macros code block in the active file by merging static and interactive lines.
   * SIMPLIFIED VERSION: No multipliers, direct quantity merging under meal headers
   */
  async updateMacrosCodeBlock(): Promise<void> {
    await this.queueUpdate(async () => {
      const activeFile = this.plugin.app.workspace.getActiveFile();
      if (!activeFile) return;

      try {
        const content = await this.readFileContent(activeFile, true);
        const regex = /```macros\s+id:\s*(\S+)\s*([\s\S]*?)```/g;
        let newContent = content;
        let updatedAny = false;

        const processedIds = new Set<string>();

        // Process each macros block in the file
        let match: RegExpExecArray | null;
        while ((match = regex.exec(content)) !== null) {
          const id = match[1];
          const blockContent = match[2];
          processedIds.add(id);

          this.plugin.logger.debug(`Found macros block with ID: ${id}`);

          // Check if we have additional macros for this ID
          const additionalMacrosForId = this.additionalMacros.get(id);
          if (
            this.additionalMacros.has(id) &&
            additionalMacrosForId &&
            additionalMacrosForId.length > 0
          ) {
            this.plugin.logger.debug(`Processing additional macros for ID: ${id}`);
            this.plugin.logger.debug(`Additional items: ${additionalMacrosForId.length}`);

            // Parse existing content into structured format
            const existingStructure = this.parseExistingMacrosContent(blockContent);

            // Process new items from additionalMacros
            const newItems = this.processNewInteractiveItems(additionalMacrosForId);

            // Merge new items with existing structure
            const mergedStructure = this.mergeIntoExistingStructure(existingStructure, newItems);

            // Convert back to text format
            const updatedContent = this.generateMacrosBlockContent(mergedStructure);

            // Create the updated block
            const updatedBlock = '```macros\nid: ' + id + '\n' + updatedContent + '\n```';

            // Replace the old block with the updated one
            newContent = newContent.replace(match[0], updatedBlock);
            updatedAny = true;

            // Clear interactive lines after merging
            this.additionalMacros.set(id, []);
          }
        }

        // Only modify the file if changes were made
        if (updatedAny) {
          await this.plugin.app.vault.modify(activeFile, newContent);

          // Update the global macro tables with the latest content
          this.updateGlobalMacroTableFromContent(newContent);

          // Must trigger metadata changes to force refresh
          this.plugin.app.metadataCache.trigger('changed', activeFile);

          // Force refresh all views
          this.plugin.refreshMacrosTables();
          await this.plugin.redrawAllMacrospc();
          await this.plugin.redrawAllMacrocalc();

          this.plugin.logger.debug(
            `Successfully updated macros blocks: ${Array.from(processedIds).join(', ')}`
          );
        } else {
          this.plugin.logger.debug('No macros blocks were updated');
        }
      } catch (error) {
        this.plugin.logger.error('Error updating macros code block:', error);
        throw error;
      }
    });
  }

  /**
   * Parse existing macros block content into a structured format
   */
  private parseExistingMacrosContent(blockContent: string): MacrosStructure {
    const lines = blockContent
      .split('\n')
      .map((l) => l.trim())
      .filter((l) => l !== '' && !l.startsWith(INTERACTIVE_PREFIX));

    const structure: MacrosStructure = {
      meals: new Map(),
      individualItems: new Map(),
    };

    let currentMealName: string | null = null;

    for (const line of lines) {
      if (line.toLowerCase().startsWith('meal:')) {
        // Extract meal name (no more multiplier parsing)
        currentMealName = line.substring(5).trim();

        if (!structure.meals.has(currentMealName)) {
          structure.meals.set(currentMealName, new Map());
        }
      } else if (line.startsWith('-') && currentMealName) {
        // Parse bullet point under a meal
        const itemText = line.substring(1).trim();
        const { foodName, quantity } = this.parseItemText(itemText);

        if (foodName) {
          // FIX: Add null check instead of using non-null assertion
          const mealItems = structure.meals.get(currentMealName);
          if (mealItems) {
            const existingQuantity = mealItems.get(foodName) || 0;
            mealItems.set(foodName, existingQuantity + quantity);
          }
        }
      } else if (!line.startsWith('-') && !line.toLowerCase().startsWith('meal:')) {
        // Individual food item (not under a meal)
        currentMealName = null;
        const { foodName, quantity } = this.parseItemText(line);

        if (foodName) {
          const existingQuantity = structure.individualItems.get(foodName) || 0;
          structure.individualItems.set(foodName, existingQuantity + quantity);
        }
      }
    }

    return structure;
  }

  /**
   * Process new interactive items into structured format
   */
  private processNewInteractiveItems(interactiveItems: string[]): NewItemsStructure {
    const newItems: NewItemsStructure = {
      meals: new Map(),
      individualItems: new Map(),
    };

    let currentGroupName: string | null = null;
    let currentGroupItems = new Map<string, number>();

    for (const item of interactiveItems) {
      const cleanItem = item.startsWith(INTERACTIVE_PREFIX)
        ? item.substring(INTERACTIVE_PREFIX.length)
        : item;

      if (cleanItem.toLowerCase().startsWith('meal:')) {
        // Existing meal handling
        const mealName = cleanItem.substring(5).trim();
        const mealTemplate = this.plugin.settings.mealTemplates.find(
          (m) => m.name.toLowerCase() === mealName.toLowerCase()
        );

        if (mealTemplate) {
          const mealItems = new Map<string, number>();
          for (const templateItem of mealTemplate.items) {
            const { foodName, quantity } = this.parseItemText(templateItem);
            if (foodName) {
              const existingQuantity = mealItems.get(foodName) || 0;
              mealItems.set(foodName, existingQuantity + quantity);
            }
          }
          newItems.meals.set(mealName, mealItems);
        }
      } else if (cleanItem.toLowerCase().startsWith('group:')) {
        // FIXED: Group handling
        currentGroupName = cleanItem.substring(6).trim(); // Remove 'group:' prefix
        currentGroupItems = new Map<string, number>();

        // Don't add to meals yet, wait for the group items
      } else if (cleanItem.startsWith('- ') && currentGroupName) {
        // FIXED: Group item handling
        const itemText = cleanItem.substring(2).trim(); // Remove '- ' prefix
        const { foodName, quantity } = this.parseItemText(itemText);

        if (foodName) {
          const existingQuantity = currentGroupItems.get(foodName) || 0;
          currentGroupItems.set(foodName, existingQuantity + quantity);
        }
      } else if (!cleanItem.startsWith('-')) {
        // If we were building a group and hit a non-bullet item, finalize the group
        if (currentGroupName && currentGroupItems.size > 0) {
          newItems.meals.set(currentGroupName, new Map(currentGroupItems));
          currentGroupName = null;
          currentGroupItems = new Map();
        }

        // Individual food item
        const { foodName, quantity } = this.parseItemText(cleanItem);
        if (foodName) {
          const existingQuantity = newItems.individualItems.get(foodName) || 0;
          newItems.individualItems.set(foodName, existingQuantity + quantity);
        }
      }
    }

    // FIXED: Finalize any remaining group
    if (currentGroupName && currentGroupItems.size > 0) {
      newItems.meals.set(currentGroupName, new Map(currentGroupItems));
    }

    return newItems;
  }

  /**
   * Merge new items into existing structure
   */
  private mergeIntoExistingStructure(
    existing: MacrosStructure,
    newItems: NewItemsStructure
  ): MacrosStructure {
    const merged: MacrosStructure = {
      meals: new Map(existing.meals),
      individualItems: new Map(existing.individualItems),
    };

    // Merge new meals
    for (const [mealName, newMealItems] of newItems.meals) {
      if (!merged.meals.has(mealName)) {
        // New meal - add it directly
        merged.meals.set(mealName, new Map(newMealItems));
      } else {
        // Existing meal - merge quantities
        // FIX: Add null check instead of using non-null assertion
        const existingMealItems = merged.meals.get(mealName);
        if (existingMealItems) {
          for (const [foodName, quantity] of newMealItems) {
            const existingQuantity = existingMealItems.get(foodName) || 0;
            existingMealItems.set(foodName, existingQuantity + quantity);
          }
        }
      }
    }

    // Merge individual items
    for (const [foodName, quantity] of newItems.individualItems) {
      const existingQuantity = merged.individualItems.get(foodName) || 0;
      merged.individualItems.set(foodName, existingQuantity + quantity);
    }

    return merged;
  }

  /**
   * Generate macros block content from structured data
   */
  private generateMacrosBlockContent(structure: MacrosStructure): string {
    const lines: string[] = [];

    // Add meals first
    for (const [mealName, mealItems] of structure.meals) {
      lines.push(`meal:${mealName}`);

      for (const [foodName, quantity] of mealItems) {
        lines.push(`- ${foodName}:${quantity}g`);
      }
    }

    // Add individual items
    for (const [foodName, quantity] of structure.individualItems) {
      lines.push(`${foodName}:${quantity}g`);
    }

    return lines.join('\n');
  }

  /**
   * Parse item text to extract food name and quantity
   */
  private parseItemText(itemText: string): { foodName: string; quantity: number } {
    if (itemText.includes(':')) {
      const parts = itemText.split(':').map((s) => s.trim());
      const foodName = parts[0];
      const quantityStr = parts[1];

      // Parse quantity (remove 'g' suffix if present)
      const quantity = parseFloat(quantityStr.replace(/g$/i, '')) || 0;

      return { foodName, quantity };
    } else {
      // No quantity specified, assume default serving size from food file
      const foodName = itemText.trim();

      // Try to get default serving from food file
      const matchingFile = this.findFoodFile(foodName);
      if (matchingFile) {
        const nutrition = processNutritionalData(this.plugin.app, matchingFile);
        if (nutrition && nutrition.serving) {
          const defaultQuantity = parseFloat(nutrition.serving.replace(/g$/i, '')) || 100;
          return { foodName, quantity: defaultQuantity };
        }
      }

      // Fallback to 100g
      return { foodName, quantity: 100 };
    }
  }

  /**
   * Updates the global macro table cache by parsing macros blocks from the provided content.
   */
  updateGlobalMacroTableFromContent(content: string): void {
    try {
      const regex = /```[\t ]*macros[\t ]+id:[\t ]*(\S+)[\t ]*\n([\s\S]*?)```/g;
      let match: RegExpExecArray | null;

      while ((match = regex.exec(content)) !== null) {
        const id = match[1];
        // Filter out the bullet points when storing in the macro tables
        const blockContent = match[2]
          .trim()
          .split('\n')
          .map((l) => l.trim())
          .filter((l) => l !== '' && !l.startsWith('-'));

        this.macroTables.set(id, blockContent);
      }
    } catch (error) {
      this.plugin.logger.error('Error updating global macro table from content:', error);
    }
  }

  /**
   * Loads the macros table from the vault by searching markdown files.
   */
  async loadMacroTableFromVault(id: string): Promise<string[] | null> {
    // Use the central method, filtering out bullet points
    return await this.getMacrosBlockContent(id, false);
  }

  /**
   * New helper method to get complete macros data including bullet points
   */
  async getFullMacrosData(id: string): Promise<string[]> {
    // Use the central method, keeping all lines
    const lines = await this.getMacrosBlockContent(id, true);
    return lines || [];
  }

  /**
   * A centralized method to load the full document context for a macro block
   * This replaces duplicate code in TableRenderer and MacrosCalcRenderer
   *
   * @param id The ID of the macros block to find
   * @returns An object containing the document context and lines, or null if not found
   */
  async getDocumentContext(id: string): Promise<{
    file: TFile;
    content: string;
    match: RegExpMatchArray;
    allLines: string[];
  } | null> {
    try {
      // Find all markdown files that might contain the block
      const files = this.plugin.app.vault.getMarkdownFiles();

      // Create a safe regex pattern from the ID
      const safeId = id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const regex = new RegExp('```\\s*macros\\s+id:\\s*' + safeId + '\\s*\\n([\\s\\S]*?)```', 'm');

      for (const file of files) {
        try {
          // Read the full file content - force fresh read
          const content = await this.plugin.app.vault.cachedRead(file);

          // Look for macros blocks with this ID
          const match = content.match(regex);

          if (match) {
            // Get all lines from the match
            const allLines = match[1]
              .split('\n')
              .map((line) => line.trim())
              .filter((line) => line !== '');

            // Return the full context
            return {
              file,
              content,
              match,
              allLines,
            };
          }
        } catch (error) {
          this.plugin.logger.error(`Error reading file for ID ${id}:`, error);
        }
      }

      this.plugin.logger.debug(`No macros block found for ID: ${id}`);
      return null;
    } catch (error) {
      this.plugin.logger.error(`Error getting document context for ID ${id}:`, error);
      return null;
    }
  }

  /**
   * Cleanup resources when plugin is unloaded
   */
  cleanup(): void {
    // Clean up DOM event listeners
    for (const { el, type, handler } of this._registeredDomElements) {
      try {
        el.removeEventListener(type, handler);
      } catch (error) {
        this.plugin.logger.error(`Error removing event listener of type ${type}:`, error);
      }
    }
    this._registeredDomElements = [];

    // Clear internal data structures
    this.additionalMacros.clear();
    this.macroTables.clear();
    this.macrospcContainers.clear();
    this.macrocalcContainers.clear();
    this._activeMacrosCalcRenderers.clear();
    this.fileCache.clear();
    this.contentCache.clear();
  }
}

import MacrosPlugin from '../main';

/**
 * Logger
 * ------
 * A singleton class for managing logging throughout the plugin.
 * Enables debug mode to be toggled centrally.
 */
export class Logger {
  private static instance: Logger;
  private debugMode = false;
  private plugin: MacrosPlugin;

  private constructor(plugin: MacrosPlugin) {
    this.plugin = plugin;
  }

  /**
   * Initialize the logger
   */
  static init(plugin: MacrosPlugin): Logger {
    if (!this.instance) {
      this.instance = new Logger(plugin);
      // Initialize debug mode from settings
      this.instance.setDebugMode(plugin.settings.developerModeEnabled);
    }
    return this.instance;
  }

  /**
   * Clean up resources when plugin is unloaded
   */
  static unload(): void {
    this.instance = null;
  }

  /**
   * Get the singleton instance
   */
  static getInstance(): Logger {
    if (!this.instance) {
      throw new Error('Logger not initialized. Call Logger.init(plugin) first.');
    }
    return this.instance;
  }

  setDebugMode(enabled: boolean): void {
    this.debugMode = enabled;
  }

  getDebugMode(): boolean {
    return this.debugMode;
  }

  debug(message: string, ...args: unknown[]): void {
    if (this.debugMode) {
      console.debug(`[Macros Debug] ${message}`, ...args);
    }
  }

  info(message: string, ...args: unknown[]): void {
    if (this.debugMode) {
      console.info(`[Macros Info] ${message}`, ...args);
    }
  }

  error(message: string, ...args: unknown[]): void {
    console.error(`[Macros Error] ${message}`, ...args);
  }

  warn(message: string, ...args: unknown[]): void {
    console.warn(`[Macros Warning] ${message}`, ...args);
  }
}

import MacrosPlugin from '../main';
import { registerMacrosProcessor } from '../processors/macros';
import { registerMacrosPCProcessor } from '../processors/macrospc';
import { registerMacrosCalcProcessor } from '../processors/macroscalc';

/**
 * ProcessorManager
 * ----------------
 * Centralizes the registration of all markdown code block processors
 * for the Macros plugin. This helps keep the main plugin class clean.
 */
export function registerProcessors(plugin: MacrosPlugin): void {
  // Register all processors
  registerMacrosProcessor(plugin);
  registerMacrosPCProcessor(plugin);
  registerMacrosCalcProcessor(plugin);

  // Deprecated: the standalone `macrosmicro` block was merged into the `macros`
  // table. Register a no-op handler so any leftover blocks render nothing
  // instead of falling back to showing their raw source.
  plugin.registerMarkdownCodeBlockProcessor('macrosmicro', (_source, el) => {
    el.empty();
    el.style.display = 'none';
  });

  plugin.logger.debug('All processors registered');
}

import { MarkdownView } from 'obsidian';
import MacrosPlugin from '../main';

/**
 * RefreshManager
 * --------------
 * Centralizes all refresh and reloading functionality for the plugin.
 * Provides a unified interface for refreshing different components.
 */
export class RefreshManager {
  private plugin: MacrosPlugin;
  private refreshInProgress = false;

  constructor(plugin: MacrosPlugin) {
    this.plugin = plugin;
  }

  /**
   * Clean up any resources when plugin is unloaded
   */
  cleanup(): void {
    // Currently no cleanup needed, but the method is required for consistency
  }

  /**
   * Force a complete reload of all data and redraw all components
   * This is the primary method that should be called when data changes
   */
  async forceCompleteRefresh(): Promise<void> {
    if (this.refreshInProgress) {
      this.plugin.logger.debug('Refresh already in progress, skipping duplicate call');
      return;
    }

    this.refreshInProgress = true;
    this.plugin.logger.debug('Starting complete refresh of all components');

    try {
      // Step 1: Clear all caches
      this.plugin.dataManager.clearAllCaches();

      // Step 2: Find all unique IDs from all containers
      const allIds = new Set<string>();

      // Process macrospc containers
      for (const [id, _] of this.plugin.dataManager.macrospcContainers.entries()) {
        if (typeof id === 'string') {
          // Handle comma in string ID
          if (id.includes(',')) {
            id.split(',')
              .map((i) => i.trim())
              .forEach((singleId) => {
                allIds.add(singleId);
              });
          } else {
            allIds.add(id);
          }
        }
      }

      // Process macroscalc containers
      const macroscalcElements = activeDocument.querySelectorAll('[data-macroscalc-ids]');
      macroscalcElements.forEach((el) => {
        const idsAttr = el.getAttribute('data-macroscalc-ids');
        if (idsAttr) {
          idsAttr
            .split(',')
            .map((id) => id.trim())
            .forEach((id) => allIds.add(id));
        }
      });

      // Step 3: Reload fresh data for all IDs
      this.plugin.logger.debug(`Reloading data for ${allIds.size} unique IDs`);

      for (const id of allIds) {
        try {
          const loaded = await this.plugin.dataManager.getFullMacrosData(id);
          if (loaded && loaded.length > 0) {
            this.plugin.dataManager.macroTables.set(id, loaded);
            this.plugin.logger.debug(`Reloaded ${loaded.length} lines for ID ${id}`);
          } else {
            this.plugin.logger.warn(`No data found for ID ${id}`);
          }
        } catch (error) {
          this.plugin.logger.error(`Error reloading ID ${id}: ${error}`);
        }
      }

      // Step 4: Refresh all macrospc containers
      this.plugin.logger.debug('Refreshing macrospc containers');
      await this.refreshAllMacrospc();

      // Step 5: Refresh all macroscalc containers
      this.plugin.logger.debug('Refreshing macroscalc containers');
      await this.refreshAllMacroscalc();

      // Step 6: Refresh Markdown views to ensure all renderers are updated
      this.refreshMarkdownViews();

      this.plugin.logger.debug('Complete refresh finished');
    } catch (error) {
      this.plugin.logger.error('Error during complete refresh:', error);
    } finally {
      this.refreshInProgress = false;
    }
  }

  /**
   * Refreshes all macrospc containers with fresh data
   * This replaces the old redrawAllMacrospc method
   */
  async refreshAllMacrospc(): Promise<void> {
    try {
      // Process each container set
      for (const [id, containerSet] of this.plugin.dataManager.macrospcContainers.entries()) {
        const aliveElements = new Set<HTMLElement>();

        for (const el of containerSet) {
          if (el.isConnected) {
            // Get IDs and dimensions from data attributes
            const idsAttr = el.getAttribute('data-ids') || id;
            const ids = idsAttr.split(',').map((i) => i.trim());

            const widthAttr = el.getAttribute('data-width');
            const heightAttr = el.getAttribute('data-height');

            const width = widthAttr ? parseInt(widthAttr) : 300;
            const height = heightAttr ? parseInt(heightAttr) : 300;

            // Redraw the chart with fresh data
            await this.plugin.chartManager.drawMacrospc(ids, el, width, height);
            aliveElements.add(el);
          }
        }

        // Update container set to only include connected elements
        this.plugin.dataManager.macrospcContainers.set(id, aliveElements);
      }
    } catch (error) {
      this.plugin.logger.error('Error refreshing macrospc containers:', error);
    }
  }

  /**
   * Refreshes all macroscalc renderers with fresh data
   * This replaces the old redrawAllMacrocalc method
   */
  async refreshAllMacroscalc(): Promise<void> {
    try {
      // First, find all macroscalc elements in the DOM
      const macroscalcElements = activeDocument.querySelectorAll('[data-macroscalc-ids]');

      if (macroscalcElements.length > 0) {
        this.plugin.logger.debug(
          `Found ${macroscalcElements.length} macroscalc elements to refresh`
        );

        // Get all unique IDs that need refreshing
        const idsToRefresh = new Set<string>();

        // Collect IDs from all elements
        macroscalcElements.forEach((el) => {
          const idsAttr = el.getAttribute('data-macroscalc-ids');
          if (idsAttr) {
            idsAttr
              .split(',')
              .map((id) => id.trim())
              .forEach((id) => idsToRefresh.add(id));
          }
        });

        // Refresh data for all IDs
        for (const id of idsToRefresh) {
          const freshData = await this.plugin.dataManager.getFullMacrosData(id);
          if (freshData && freshData.length > 0) {
            this.plugin.macroService.macroTables.set(id, freshData);
            this.plugin.logger.debug(`Refreshed data for ID ${id}`);
          }
        }

        // Process each active renderer
        if (this.plugin.macroService._activeMacrosCalcRenderers) {
          for (const renderer of this.plugin.macroService._activeMacrosCalcRenderers) {
            try {
              // Mark renderer for refresh
              if (typeof renderer.setNeedsRefresh === 'function') {
                renderer.setNeedsRefresh();
              }

              // Get IDs and recalculate
              if (typeof renderer.getIds === 'function' && typeof renderer.render === 'function') {
                const ids = renderer.getIds();
                const { aggregate, breakdown } = this.plugin.processNutritionalDataFromLines(ids);
                await renderer.render(aggregate, breakdown);
              }
            } catch (error) {
              this.plugin.logger.error('Error updating macroscalc renderer:', error);
            }
          }
        }
      }
    } catch (error) {
      this.plugin.logger.error('Error refreshing macroscalc elements:', error);
    }
  }

  /**
   * Refreshes all markdown views to trigger re-rendering of code blocks
   */
  refreshMarkdownViews(): void {
    this.plugin.app.workspace.getLeavesOfType('markdown').forEach((leaf) => {
      const view = leaf.view as MarkdownView;
      if (view.previewMode && typeof view.previewMode.rerender === 'function') {
        view.previewMode.rerender(true);
      } else {
        leaf.setViewState(leaf.getViewState());
      }
    });
  }

  /**
   * Directly refresh macroscalc elements in the DOM
   * Useful for more targeted refreshes
   */
  async refreshMacroscalcElements(): Promise<void> {
    try {
      await this.refreshAllMacroscalc();

      // Also force a trigger of the metadataCache changed event
      const activeFile = this.plugin.dataManager.getActiveFile();
      if (activeFile) {
        this.plugin.app.metadataCache.trigger('changed', activeFile);

        // Add a short delay and refresh markdown views
        window.setTimeout(() => {
          this.refreshMarkdownViews();
        }, 100);
      }
    } catch (error) {
      this.plugin.logger.error(`Error in refreshMacroscalcElements:`, error);
    }
  }
}

import { TFile, EventRef } from 'obsidian';
import MacrosPlugin from '../main';
import { RenameConfirmationModal } from '../ui/modals/RenameConfirmationModal';
import { scanVaultForFoodReferences, createBackup } from '../utils/rename';
import { t } from '../lang/I18nManager';

/**
 * RenameWatcher
 * -------------
 * Listens for file rename events in the vault and handles updating macro references
 * when food files in the nutrition folder are renamed.
 *
 * Updated to use the storage folder setting instead of a separate renameScopeFolder.
 */
export class RenameWatcher {
  private plugin: MacrosPlugin;
  private renameEventRef: EventRef | null = null;

  constructor(plugin: MacrosPlugin) {
    this.plugin = plugin;
  }

  /**
   * Initialize the rename watcher
   */
  init(): void {
    // Listen for file rename events
    this.renameEventRef = this.plugin.app.vault.on('rename', this.handleFileRename.bind(this));
    this.plugin.registerEvent(this.renameEventRef);

    this.plugin.logger.debug('RenameWatcher initialized');
  }

  /**
   * Handle file rename events
   */
  private async handleFileRename(file: TFile, oldPath: string): Promise<void> {
    try {
      // Only proceed if rename tracking is enabled
      if (!this.plugin.settings.followRenamesEnabled) {
        return;
      }

      // Only handle markdown files
      if (file.extension !== 'md') {
        return;
      }

      // Get the storage folder from settings (this is the nutrition folder)
      const nutritionFolder = this.plugin.settings.storageFolder;

      // Check if the file is in the nutrition folder
      if (!oldPath.startsWith(nutritionFolder)) {
        return;
      }

      // Extract old and new names (without extension)
      const oldName = this.getBaseName(oldPath);
      const newName = this.getBaseName(file.path);

      // Skip if names are the same (shouldn't happen, but safety check)
      if (oldName === newName) {
        return;
      }

      this.plugin.logger.debug(`Food file renamed: ${oldName} -> ${newName}`);

      // Scan vault for references to the old food name
      // Use the storage folder as the exclude folder to avoid matching the food file itself
      const affectedFiles = await scanVaultForFoodReferences(
        this.plugin.app.vault,
        oldName,
        this.plugin.settings.caseSensitiveFoodMatch,
        nutritionFolder
      );

      if (affectedFiles.length === 0) {
        // No references found, show notice and exit
        this.plugin.app.workspace.trigger('notice', t('rename.noMatches'));
        return;
      }

      // If auto-confirm is enabled, proceed directly
      if (this.plugin.settings.autoConfirmRenames) {
        await this.performRename(oldName, newName, affectedFiles);
      } else {
        // Show confirmation modal
        const modal = new RenameConfirmationModal(
          this.plugin,
          oldName,
          newName,
          affectedFiles,
          (selectedFiles) => this.performRename(oldName, newName, selectedFiles),
          () => this.revertFileRename(file, oldPath) // Add cancel callback
        );
        modal.open();
      }
    } catch (error) {
      this.plugin.logger.error('Error handling file rename:', error);
      this.plugin.app.workspace.trigger('notice', t('rename.error', {
        error: error instanceof Error ? error.message : String(error),
      }));
    }
  }

  /**
   * Perform the actual rename operation
   */
  private async performRename(
    oldName: string,
    newName: string,
    affectedFiles: Array<{
      file: TFile;
      matches: Array<{ line: number; content: string; preview: string }>;
    }>
  ): Promise<void> {
    try {
      let successCount = 0;
      let errorCount = 0;

      for (const { file, matches } of affectedFiles) {
        try {
          // Create backup if enabled
          if (this.plugin.settings.backupOnRename) {
            await createBackup(this.plugin.app.vault, file);
          }

          // Read current file content
          const content = await this.plugin.app.vault.cachedRead(file);
          const lines = content.split('\n');

          // Apply replacements
          let modified = false;
          for (const match of matches) {
            const lineIndex = match.line - 1; // Convert to 0-based index
            if (lineIndex >= 0 && lineIndex < lines.length) {
              const oldLine = lines[lineIndex];
              const newLine = this.replaceFoodNameInLine(
                oldLine,
                oldName,
                newName,
                this.plugin.settings.caseSensitiveFoodMatch
              );

              if (newLine !== oldLine) {
                lines[lineIndex] = newLine;
                modified = true;
              }
            }
          }

          // Write back if modified
          if (modified) {
            const newContent = lines.join('\n');
            await this.plugin.app.vault.process(file, () => newContent);
            successCount++;
          }
        } catch (error) {
          this.plugin.logger.error(`Error updating file ${file.path}:`, error);
          errorCount++;
        }
      }

      // Show success/error summary
      if (successCount > 0) {
        this.plugin.app.workspace.trigger(
          'notice',
          t('rename.success', { count: successCount, oldName, newName })
        );
      }

      if (errorCount > 0) {
        this.plugin.app.workspace.trigger(
          'notice',
          t('rename.error', { error: `${errorCount} files failed to update` })
        );
      }
    } catch (error) {
      this.plugin.logger.error('Error performing rename operation:', error);
      this.plugin.app.workspace.trigger('notice', t('rename.error', {
        error: error instanceof Error ? error.message : String(error),
      }));
    }
  }

  /**
   * Replace food name in a single line, preserving formatting
   */
  private replaceFoodNameInLine(
    line: string,
    oldName: string,
    newName: string,
    caseSensitive: boolean
  ): string {
    // Escape special regex characters in the old name
    const escapedOldName = oldName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

    // Create regex pattern to match food key before first colon
    const flags = caseSensitive ? 'g' : 'gi';
    const pattern = new RegExp(`^(\\s*(?:[-*]\\s*)?)${escapedOldName}(\\s*:\\s*)(.*)$`, flags);

    return line.replace(pattern, `$1${newName}$2$3`);
  }

  /**
   * Extract base name from file path (without extension)
   */
  private getBaseName(path: string): string {
    const fileName = path.split('/').pop() || '';
    return fileName.replace(/\.md$/, '');
  }

  /**
   * Revert a file rename back to its original name
   */
  private async revertFileRename(file: TFile, originalPath: string): Promise<void> {
    try {
      this.plugin.logger.debug(`Reverting file rename: ${file.path} -> ${originalPath}`);

      // Rename the file back to its original path
      await this.plugin.app.vault.rename(file, originalPath);

      this.plugin.app.workspace.trigger(
        'notice',
        t('rename.cancelled', { fileName: this.getBaseName(originalPath) })
      );
    } catch (error) {
      this.plugin.logger.error('Error reverting file rename:', error);
      this.plugin.app.workspace.trigger(
        'notice',
        t('rename.revertError', { error: error instanceof Error ? error.message : String(error) })
      );
    }
  }

  /**
   * Cleanup when plugin is unloaded
   */
  cleanup(): void {
    if (this.renameEventRef) {
      this.plugin.app.vault.offref(this.renameEventRef);
      this.renameEventRef = null;
    }

    this.plugin.logger.debug('RenameWatcher cleaned up');
  }
}

import MacrosPlugin from '../main';
