            const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';
            const offLanguage =
              this.plugin.settings.openFoodFactsLanguage === 'auto'
                ? userLocale
                : this.plugin.settings.openFoodFactsLanguage;

