  /**
   * Open barcode scanner modal
   */
  private openBarcodeScanner(): void {
    // Fixed: Add null check instead of non-null assertion
    if (!this.plugin) {
      new Notice('Plugin context not available for barcode scanning');
      return;
    }

    const scannerModal = new BarcodeScannerModal(this.app, this.plugin, (barcode: string) =>
      this.handleBarcodeScanned(barcode)
    );

    scannerModal.open();
  }

  /**
   * Handle barcode scan result
   */
  async handleBarcodeScanned(barcode: string): Promise<void> {
    // Validate barcode
    if (!validateBarcodeChecksum(barcode)) {
      new Notice(t('barcode.manual.checksumWarning', { code: barcode }));
    }

    // Set the barcode in search input
    this.searchInput.value = barcode;
    this.isBarcodeSearch = true;

    // Perform barcode-specific search
    await this.performBarcodeSearch(barcode);

    // Focus back on input for potential manual editing
    window.setTimeout(() => {
      this.searchInput.focus();
      this.searchInput.select();
    }, 100);
  }

  /**
   * Perform barcode-specific search with proper result handling
   */
  private async performBarcodeSearch(barcode: string): Promise<void> {
    if (!this.plugin) {
      new Notice('Plugin context not available for barcode search');
      return;
    }

    this.loadingIndicator.classList.remove('is-hidden');
    this.noResultsMessage.classList.add('is-hidden');
    this.isSearching = true;

    // Clear previous results
    this.resultsContainer.empty();
    this.results = [];
    this.allResults = [];

    try {
      const settings = this.plugin.settings;

      // Configure sources for barcode search
      const sources = {
        openFoodFacts: { enabled: settings.openFoodFactsEnabled !== false },
        usda:
          settings.usdaEnabled && settings.usdaApiKey
            ? { enabled: true, apiKey: settings.usdaApiKey }
            : undefined,
      };

      // Get user's locale
      const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';

      // Search by barcode
      const barcodeResults = await searchByBarcode(this.app, barcode, sources, userLocale);

      // Properly set the results
      this.allResults = barcodeResults;
      this.results = barcodeResults;
      this.hasMoreResults = false; // Barcode search is typically exact match
      this.currentSearchTerm = barcode; // Set current search term

      this.loadingIndicator.classList.add('is-hidden');

      if (barcodeResults.length > 0) {
        // Build Fuse index for barcode results
        const foodDocs: FoodDoc[] = barcodeResults.map(unifiedResultToFoodDoc);
        buildFuseIndex(this.currentTab, foodDocs);

        // Call renderResults with the barcode as search term
        this.renderResults(barcode);
        new Notice(
          t('barcode.scanner.foundResults', { count: barcodeResults.length, code: barcode })
        );
      } else {
        // If no barcode results, show no results message
        this.noResultsMessage.textContent = t('barcode.scanner.noResults', { code: barcode });
        this.noResultsMessage.classList.remove('is-hidden');

        // Clear search input and reset for text search after a delay
        window.setTimeout(() => {
          this.searchInput.value = '';
          this.isBarcodeSearch = false;
          this.searchInput.placeholder = t('food.search.placeholder');
          this.searchInput.focus();
        }, 2000);
      }
    } catch (error) {
      this.plugin.logger.error('Barcode search error:', error);
      this.loadingIndicator.classList.add('is-hidden');
      new Notice(t('barcode.errors.apiError', { error: (error as Error).message }));

      // Reset for manual search
      this.isBarcodeSearch = false;
      this.noResultsMessage.textContent = `Barcode search failed: ${(error as Error).message}`;
      this.noResultsMessage.classList.remove('is-hidden');
    } finally {
      this.isSearching = false;
    }
  }

  private createLoadingIndicator(): void {
    this.loadingIndicator = this.contentEl.createDiv({
      cls: 'loading-indicator macros-loading-indicator is-hidden',
      text: t('food.search.searching'),
    });
  }

  private createResultsContainer(): void {
    this.resultsContainer = this.contentEl.createDiv({
      cls: 'results-container macros-results-container',
    });
  }

  private createNoResultsMessage(): void {
    this.noResultsMessage = this.contentEl.createDiv({
      cls: 'no-results-message is-hidden',
      text: t('food.search.noResults'),
    });
  }

  handleSearchInput = () => {
    const searchTerm = this.searchInput.value.trim();

    // Reset barcode search flag when user starts typing
    if (!this.isBarcodeSearch || searchTerm !== this.currentSearchTerm) {
      this.isBarcodeSearch = false;
    }

    if (this.searchTimeout) {
      window.clearTimeout(this.searchTimeout);
    }

    // Cancel any ongoing search
    if (this.currentSearchAbortController) {
      this.currentSearchAbortController.abort();
      this.currentSearchAbortController = null;
    }

    this.selectedIndex = -1;

    if (!searchTerm) {
      this.resultsContainer.empty();
      this.noResultsMessage.classList.add('is-hidden');
      this.loadingIndicator.classList.add('is-hidden');
      return;
    }

    // Use Fuse search if we have results indexed for current tab
    const fuseResults = fuseSearch(this.currentTab, searchTerm);
    if (fuseResults.length > 0) {
      this.results = fuseResults;
      this.renderResults(searchTerm);
      return;
    }

    this.loadingIndicator.classList.remove('is-hidden');
    this.noResultsMessage.classList.add('is-hidden');

    this.searchTimeout = window.setTimeout(() => {
      const currentSearchTerm = this.searchInput.value.trim();
      if (currentSearchTerm === searchTerm) {
        // Detect if this looks like a barcode (all numbers, 8-14 digits)
        if (/^\d{8,14}$/.test(searchTerm)) {
          this.isBarcodeSearch = true;
          this.performBarcodeSearch(searchTerm);
        } else {
          this.performSearch(searchTerm);
        }
      }
    }, 300);
  };

  handleKeyboardNavigation = (event: KeyboardEvent) => {
    if (this.results.length === 0) return;

    if (event.key === 'ArrowDown') {
      event.preventDefault();
      this.selectedIndex = (this.selectedIndex + 1) % this.results.length;
      this.highlightSelectedResult();
      this.scrollToSelectedResult();
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      this.selectedIndex = (this.selectedIndex - 1 + this.results.length) % this.results.length;
      this.highlightSelectedResult();
      this.scrollToSelectedResult();
    } else if (event.key === 'Enter' && this.selectedIndex >= 0) {
      event.preventDefault();
      this.handleFoodSelection(this.results[this.selectedIndex]);
    }
  };

  highlightSelectedResult() {
    this.resultsContainer.querySelectorAll('.food-result-item').forEach((item, index) => {
      if (index === this.selectedIndex) {
        item.addClass('highlighted-result');
      } else {
        item.removeClass('highlighted-result');
      }
    });
  }

  scrollToSelectedResult() {
    const selectedElement = this.resultsContainer.querySelector('.highlighted-result');
    if (selectedElement) {
      selectedElement.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }

  /**
   * Enhanced search with Fuse.js integration and fallback variants
   */
  async performSearch(searchTerm: string) {
    // Create new abort controller for this search
    this.currentSearchAbortController = new AbortController();
    const searchAbortSignal = this.currentSearchAbortController.signal;

    // Store the search term at the start of the request
    const requestSearchTerm = searchTerm;

    if (this.isSearching) {
      // If already searching, the abort controller above will cancel the previous request
    }

    this.isSearching = true;

    try {
      if (!this.plugin) {
        throw new Error('Plugin context not available');
      }

      // Check if search was aborted before making the request
      if (searchAbortSignal.aborted) {
        return;
      }

      // Validate that search term still matches current input
      const currentInputValue = this.searchInput.value.trim();
      if (currentInputValue !== requestSearchTerm) {
        this.plugin.logger.debug(
          `Search cancelled: input changed from "${requestSearchTerm}" to "${currentInputValue}"`
        );
        return;
      }

      // Fixed: Use proper typing instead of any
      const settings = this.plugin.settings;

      // Reset for new search
      this.currentPage = 0;
      this.hasMoreResults = true;
      this.allResults = [];

      let newResults: UnifiedFoodResult[] = [];

      // Check if search was aborted before processing results
      if (searchAbortSignal.aborted) {
        return;
      }

      // Try primary search first
      newResults = await this.performApiSearch(requestSearchTerm, settings, searchAbortSignal);

      // If no results, try search variants (singular/plural)
      if (newResults.length === 0) {
        const variants = generateSearchVariants(requestSearchTerm);

        for (const variant of variants) {
          if (searchAbortSignal.aborted) return;

          const variantResults = await this.performApiSearch(variant, settings, searchAbortSignal);

          if (variantResults.length > 0) {
            newResults = variantResults;
            break;
          }
        }
      }

      // Final validation before showing results
      const finalInputValue = this.searchInput.value.trim();
      if (finalInputValue !== requestSearchTerm || searchAbortSignal.aborted) {
        this.plugin.logger.debug(
          `Search results discarded: input changed from "${requestSearchTerm}" to "${finalInputValue}" or search was aborted`
        );
        return;
      }

      this.allResults = newResults;
      this.results = newResults;
      this.hasMoreResults = newResults.length > 0;

      // Build Fuse index for the results
      if (newResults.length > 0) {
        const foodDocs: FoodDoc[] = newResults.map(unifiedResultToFoodDoc);
        buildFuseIndex(this.currentTab, foodDocs);
      }

      this.loadingIndicator.classList.add('is-hidden');
      this.renderResults(requestSearchTerm);
      this.storeResultsInCache(requestSearchTerm);

      // Ensure search input maintains focus after results are rendered
      window.setTimeout(() => {
        this.searchInput.focus();
      }, 10);
    } catch (error) {
      // Don't show error if search was aborted
      if (searchAbortSignal.aborted) {
        return;
      }

      if (this.plugin && this.plugin.logger) {
        this.plugin.logger.error('Error fetching food data:', error);
      }
      this.loadingIndicator.classList.add('is-hidden');
      new Notice(t('food.search.error.fetchFailed'));
    } finally {
      this.isSearching = false;
      // Clear the abort controller if this search completed normally
      if (
        this.currentSearchAbortController &&
        this.currentSearchAbortController.signal === searchAbortSignal
      ) {
        this.currentSearchAbortController = null;
      }
    }
  }

  /**
   * Perform the actual API search for a given term
   */
  private async performApiSearch(
    searchTerm: string,
    // Fixed: Use proper typing instead of any
    settings: typeof this.plugin.settings,
    searchAbortSignal: AbortSignal
  ): Promise<UnifiedFoodResult[]> {
    let newResults: UnifiedFoodResult[] = [];

    if (this.currentTab === 'openfoodfacts') {
      // Open Food Facts only search
      if (settings.openFoodFactsEnabled !== false) {
        // Check if this is a barcode search first
        const cleanQuery = searchTerm.replace(/\s+/g, '');
        const isBarcodeSearch = /^\d{8,14}$/.test(cleanQuery);

        if (isBarcodeSearch) {
          // Use the barcode search function directly
          const { searchByBarcode } = await import('../../core/barcodeSearch');

          const sources = {
            openFoodFacts: { enabled: true },
            usda: undefined, // Don't search USDA for barcodes when on OFF tab
          };

          const userLocale = this.plugin?.i18nManager?.getCurrentLocale() || 'en';
          newResults = await searchByBarcode(this.app, cleanQuery, sources, userLocale);
        } else {
          // Regular text search
          // Get user's locale for localization
          const userLocale = this.plugin?.i18nManager?.getCurrentLocale() || 'en';
          const offLanguage =
            settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

          // Import and use Open Food Facts search
          const { searchOpenFoodFacts } = await import('../../core/openFoodFacts');
          const offResults = await searchOpenFoodFacts(
            this.app,
            searchTerm,
            0,
            this.maxResults,
            offLanguage
          );

          // Convert to UnifiedFoodResult format
          newResults = offResults.map((item) => ({
            id: `off_${item.code}`,
            name: item.productName,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'openfoodfacts' as const,
            brandName: item.brands,
            nutritionGrade: item.nutritionGrade,
            novaGroup: item.novaGroup,
            dataQuality: item.dataQuality,
            completeness: item.completeness,
            ecoscore: item.ecoscore,
            imageUrl: item.imageUrl,
            categories: item.categories,
            ingredients: item.ingredientsText,
            micronutrients: item.micronutrients,
            raw: item,
          }));

          // Apply data quality filter
          if (settings.openFoodFactsDataQualityFilter !== 'all') {
            newResults = newResults.filter((result) => {
              if (settings.openFoodFactsDataQualityFilter === 'high') {
                return result.dataQuality === 'high';
              } else if (settings.openFoodFactsDataQualityFilter === 'medium') {
                return result.dataQuality === 'high' || result.dataQuality === 'medium';
              }
              return true;
            });
          }
        }
      }
    } else if (this.currentTab === 'usda-foundation') {
      // Foundation only search
      if (settings.usdaEnabled && settings.usdaApiKey) {
        newResults = await searchFoundationFoodsOnly(
          this.app,
          searchTerm,
          this.maxResults,
          settings.usdaApiKey
        );
      }
    } else if (this.currentTab === 'usda-branded') {
      // Branded only search
      if (settings.usdaEnabled && settings.usdaApiKey) {
        const usdaResults = await searchFoods(
          this.app,
          searchTerm,
          0,
          this.maxResults,
          settings.usdaApiKey
        );
        newResults = usdaResults
          .filter((item) => item.isBranded)
          .map((item) => ({
            id: `usda_${item.fdcId}`,
            name: item.description,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'usda' as const,
            brandName: item.brandName,
            isFoundation: item.isFoundation,
            isBranded: item.isBranded,
            isSrLegacy: item.isSrLegacy,
            dataType: item.dataType,
            micronutrients: item.micronutrients,
            raw: item,
          }));
      }
    } else if (this.currentTab === 'usda-legacy') {
      // Legacy only search
      if (settings.usdaEnabled && settings.usdaApiKey) {
        const usdaResults = await searchFoods(
          this.app,
          searchTerm,
          0,
          this.maxResults,
          settings.usdaApiKey
        );
        newResults = usdaResults
          .filter((item) => item.isSrLegacy)
          .map((item) => ({
            id: `usda_${item.fdcId}`,
            name: item.description,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'usda' as const,
            brandName: item.brandName,
            isFoundation: item.isFoundation,
            isBranded: item.isBranded,
            isSrLegacy: item.isSrLegacy,
            dataType: item.dataType,
            micronutrients: item.micronutrients,
            raw: item,
          }));
      }
    } else if (this.currentTab === 'fatsecret') {
      // Search ONLY FatSecret, completely exclude Open Food Facts and USDA
      if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
        // Import FatSecret search function directly
        const { searchFatSecret } = await import('../../core/search');

        newResults = await searchFatSecret(
          this.app,
          searchTerm,
          this.currentPage,
          this.maxResults,
          settings.fatSecretApiKey,
          settings.fatSecretApiSecret
        );
      }
    } else {
      // Determine which sources to search based on current tab
      const sources: {
        fatSecret?: { enabled: boolean; apiKey: string; apiSecret: string };
        usda?: { enabled: boolean; apiKey: string };
        openFoodFacts?: { enabled: boolean };
      } = {};

      if (this.currentTab === 'all') {
        // Search all available sources
        if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
          sources.fatSecret = {
            enabled: true,
            apiKey: settings.fatSecretApiKey,
            apiSecret: settings.fatSecretApiSecret,
          };
        }
        if (settings.usdaEnabled && settings.usdaApiKey) {
          sources.usda = {
            enabled: true,
            apiKey: settings.usdaApiKey,
          };
        }
        if (settings.openFoodFactsEnabled !== false) {
          sources.openFoodFacts = {
            enabled: true,
          };
        }
      }

      // Get user's locale for Open Food Facts
      const userLocale = this.plugin?.i18nManager?.getCurrentLocale() || 'en';
      const offLanguage =
        settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

      newResults = await searchAllSources(
        this.app,
        searchTerm,
        this.currentPage,
        this.maxResults,
        sources,
        offLanguage
      );

      // Apply Open Food Facts data quality filter if applicable
      if (settings.openFoodFactsDataQualityFilter !== 'all') {
        newResults = newResults
          .map((result) => {
            if (result.source === 'openfoodfacts') {
              if (
                settings.openFoodFactsDataQualityFilter === 'high' &&
                result.dataQuality !== 'high'
              ) {
                return null;
              } else if (
                settings.openFoodFactsDataQualityFilter === 'medium' &&
                result.dataQuality === 'low'
              ) {
                return null;
              }
            }
            return result;
          })
          .filter(Boolean);
      }
    }

    return newResults;
  }

  escapeRegExp(string: string): string {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\');
  }

  /**
   * Render a compact micronutrient summary for a result, when the food carries
   * per-100g micronutrient data. Foods whose source has no recorded
   * micronutrients (e.g. many Open Food Facts entries, or FatSecret results
   * before the food is selected) simply render nothing.
   */
  private renderMicronutrientSummary(container: HTMLElement, food: UnifiedFoodResult) {
    const micros = food.micronutrients;
    if (!micros) return;

    const presentKeys = MICRONUTRIENT_KEYS.filter(
      (key) => micros[key] != null && Number.isFinite(micros[key]) && micros[key] !== 0
    );
    if (presentKeys.length === 0) return;

    const grams = food.gramsServing || 100;
    const microsDiv = container.createDiv({ cls: 'food-result-micros' });
    microsDiv.createSpan({
      cls: 'food-result-micros-label',
      text: t('food.search.micronutrients', { grams: String(grams) }),
    });

    const chipsWrap = microsDiv.createDiv({ cls: 'food-result-micros-chips' });
    for (const key of presentKeys) {
      const def = MICRONUTRIENT_MAP[key];
      const label = def ? def.label : key;
      const unit = def ? def.unit : '';
      chipsWrap.createSpan({
        cls: 'food-result-micro-chip',
        text: `${label} ${formatMicroAmount(micros[key])}${unit}`,
      });
    }
  }

  renderResults(searchTerm: string) {
    this.resultsContainer.empty();

    if (this.results.length === 0) {
      this.noResultsMessage.classList.remove('is-hidden');
      return;
    }

    this.noResultsMessage.classList.add('is-hidden');

    const normalizedQuery = searchTerm.toLowerCase();
    const escapedSearchTerm = this.escapeRegExp(searchTerm);

    // For barcode searches, show all results regardless of name matching
    const resultsToShow = this.isBarcodeSearch
      ? this.results
      : this.results.filter((food) => food.name.toLowerCase().includes(normalizedQuery));

    resultsToShow.forEach((food, index) => {
      const foodDiv = this.resultsContainer.createDiv({
        cls: `food-result-item ${this.isBarcodeSearch ? 'barcode-result' : ''}`,
      });

      // Create main content container
      const contentDiv = foodDiv.createDiv({ cls: 'food-result-content' });

      // Food name with highlighting and brand info
      const nameDiv = contentDiv.createDiv({ cls: 'food-result-name' });
      const nameContentDiv = nameDiv.createDiv({ cls: 'food-name-content' });

      // Only highlight text matches for non-barcode searches
      if (this.isBarcodeSearch) {
        // For barcode searches, just show the name without highlighting
        nameContentDiv.createSpan({ text: food.name });
      } else {
        // For text searches, highlight matching text
        const regex = new RegExp(`(${escapedSearchTerm})`, 'gi');
        const parts = food.name.split(regex);

        parts.forEach((part) => {
          if (part.toLowerCase() === searchTerm.toLowerCase()) {
            nameContentDiv.createEl('strong', { text: part });
          } else if (part) {
            nameContentDiv.createSpan({ text: part });
          }
        });
      }

      // Add brand name if available
      if (food.brandName) {
        nameContentDiv.createSpan({
          cls: 'food-brand-name',
          text: ` (${food.brandName})`,
        });
      }

      // Create enhanced chips container
      const chipsDiv = nameDiv.createDiv({ cls: 'food-result-chips' });

      // Add enhanced source chip with more specific labeling
      let sourceLabel = '';
      let chipClass = `macros-source-chip macros-source-${food.source}`;

      if (food.source === 'usda') {
        if (food.isFoundation) {
          sourceLabel = 'USDA Foundation';
          chipClass += ' macros-source-foundation';
        } else if (food.isSrLegacy) {
          sourceLabel = 'USDA SR Legacy';
          chipClass += ' macros-source-sr-legacy';
        } else if (food.isBranded) {
          sourceLabel = 'USDA Branded';
          chipClass += ' macros-source-branded';
        } else {
          sourceLabel = 'USDA';
        }
      } else if (food.source === 'openfoodfacts') {
        sourceLabel = 'Open Food Facts';
        chipClass += ' macros-source-openfoodfacts';
      } else {
        sourceLabel = t(`food.search.source.${food.source}`);
      }

      chipsDiv.createSpan({
        cls: chipClass,
        text: sourceLabel,
      });

      // Add quality indicators for different sources
      if (food.isFoundation) {
        chipsDiv.createSpan({
          cls: 'macros-quality-chip macros-foundation-indicator',
          text: 'High Quality',
          attr: { title: 'Foundation data is the most reliable and comprehensive USDA data' },
        });
      } else if (food.source === 'openfoodfacts') {
        // Add data quality indicator for Open Food Facts
        if (food.dataQuality === 'high') {
          chipsDiv.createSpan({
            cls: 'macros-quality-chip macros-off-high-quality',
            text: 'High Quality',
            attr: { title: 'High quality Open Food Facts data' },
          });
        } else if (food.dataQuality === 'medium') {
          chipsDiv.createSpan({
            cls: 'macros-quality-chip macros-off-medium-quality',
            text: 'Medium Quality',
            attr: { title: 'Medium quality Open Food Facts data' },
          });
        }

        // Add nutrition grade if available
        if (
          food.nutritionGrade &&
          ['A', 'B', 'C', 'D', 'E'].includes(food.nutritionGrade.toUpperCase())
        ) {
          chipsDiv.createSpan({
            cls: `macros-nutrition-grade macros-nutrition-grade-${food.nutritionGrade.toLowerCase()}`,
            text: `Grade ${food.nutritionGrade.toUpperCase()}`,
            attr: { title: 'Nutri-Score nutrition grade' },
          });
        }

        // Add NOVA group indicator if available
        if (food.novaGroup && food.novaGroup >= 1 && food.novaGroup <= 4) {
          // Fixed: Removed unused variable assignment
          chipsDiv.createSpan({
            cls: `macros-nova-chip macros-nova-${food.novaGroup}`,
            text: `NOVA ${food.novaGroup}`,
            attr: { title: 'NOVA food processing classification' },
          });
        }
      }

      // Food description
      // Fixed: Prefix unused variable with underscore
      const _descDiv = contentDiv.createDiv({
        cls: 'food-result-description',
        text: food.description,
      });

      // Micronutrient summary (only for foods whose source provided per-100g
      // micronutrient data; many database entries have none recorded).
      this.renderMicronutrientSummary(contentDiv, food);

      // Add product image for Open Food Facts if available
      if (food.source === 'openfoodfacts' && food.imageUrl) {
        const imageDiv = contentDiv.createDiv({ cls: 'food-result-image' });
        const img = imageDiv.createEl('img', {
          attr: {
            src: food.imageUrl,
            alt: food.name,
            loading: 'lazy',
          },
          cls: 'food-product-image',
        });

        // Handle image load errors gracefully
        img.addEventListener('error', () => {
          imageDiv.style.display = 'none';
        });
      }

      if (index === this.selectedIndex) {
        foodDiv.addClass('highlighted-result');
      }

      this.component.registerDomEvent(foodDiv, 'click', () => {
        this.handleFoodSelection(food);
      });

      this.component.registerDomEvent(foodDiv, 'mouseenter', () => {
        this.selectedIndex = index;
        this.highlightSelectedResult();
      });
    });

    // Add infinite scroll functionality
    this.setupInfiniteScroll(searchTerm);
  }

  private async handleFoodSelection(food: UnifiedFoodResult): Promise<void> {
    // Check if this is from API search (not already saved food)
    if (food.source === 'usda' || food.source === 'fatsecret' || food.source === 'openfoodfacts') {
      await this.promptForFileName(food);
    } else {
      // Directly call onSelect for already saved foods
      this.onSelect(food);
      this.close();
    }
  }

  private async promptForFileName(food: UnifiedFoodResult): Promise<void> {
    // Create a simple modal for file name input
    const modal = new FileNameModal(
      this.app,
      food.name,
      food.gramsServing || 100, // Pass the original serving size
      async (fileName: string, defaultServing?: number) => {
        // Use the SAME sanitization logic as DataManager
        const safeFileName = this.sanitizeFileName(fileName);

        // Check if sanitization changed the filename significantly
        if (safeFileName !== fileName.trim()) {
          this.plugin?.logger.debug(`Filename sanitized: "${fileName}" -> "${safeFileName}"`);
        }

        // Check existence using the sanitized filename
        const existsResult = await this.checkFileExists(safeFileName);
        if (existsResult.exists) {
          new Notice(
            `A food item with the name "${safeFileName}" already exists in your Nutrition folder. Please choose a different name to avoid conflicts.`
          );
          return false; // Keep modal open
        }

        // File name is unique, proceed with saving
        try {
          // Pass the ORIGINAL filename and default serving to saveFoodFile
          await this.saveFoodFile(food, fileName, defaultServing);
          // Don't call this.onSelect(food) here - saveFoodFile already shows success notice
          this.close();
          return true; // Close modal
        } catch (error) {
          this.plugin?.logger.error('Error saving food file:', error);
          new Notice(`Error saving food item: ${(error as Error).message}`);
          return false; // Keep modal open
        }
      },
      this.plugin
    );

    modal.open();
  }

  // Proper file existence check with normalization
  private async checkFileExists(fileName: string): Promise<{ exists: boolean; path?: string }> {
    if (!this.plugin) return { exists: false };

    try {
      // Use the SAME sanitization logic as DataManager
      const safeFileName = this.sanitizeFileName(fileName);

      const folder = normalizePath(this.plugin.settings.storageFolder);
      const filePath = normalizePath(`${folder}/${safeFileName}.md`);

      // Use proper Obsidian API to check file existence
      const existingFile = this.app.vault.getAbstractFileByPath(filePath);

      // Ensure it's actually a file, not a folder
      const exists = existingFile instanceof TFile;

      this.plugin.logger.debug(`File existence check: ${safeFileName}.md -> ${exists}`);

      return { exists, path: filePath };
    } catch (error) {
      this.plugin.logger.error('Error checking file existence:', error);
      return { exists: false };
    }
  }

  // Helper to sanitize filename - MUST match DataManager.createSafeFileName()
  private sanitizeFileName(fileName: string): string {
    return fileName
      .replace(/[<>:"/\\|?*]/g, '') // Remove invalid filename characters
      .replace(/\s+/g, ' ') // Normalize spaces
      .replace(/^\s+|\s+$/g, '') // Trim whitespace
      .substring(0, 100) // Limit length
      .replace(/\.$/, ''); // Remove trailing period if present
  }

  private async saveFoodFile(
    food: UnifiedFoodResult,
    fileName: string,
    defaultServing?: number
  ): Promise<void> {
    if (!this.plugin) return;

    // Extract nutrition data from the food result
    let calories = 0;
    let protein = 0;
    let fat = 0;
    let carbs = 0;
    let fiber = 0;
    let sugars = 0;
    let salt = 0;

    // For Open Food Facts, we have direct access to nutrition data
    // Fixed: Use proper typing instead of any
    if (food.source === 'openfoodfacts' && food.raw && typeof food.raw === 'object') {
      const offData = food.raw as Record<string, unknown>;
      calories = (offData.calories as number) || 0;
      protein = (offData.protein as number) || 0;
      fat = (offData.fat as number) || 0;
      carbs = (offData.carbs as number) || 0;
      fiber = (offData.fiber as number) || 0;
      sugars = (offData.sugars as number) || 0;
      salt = (offData.salt as number) || 0;
    } else {
      // Parse nutrition data from description for other sources
      if (food.description) {
        const caloriesMatch = food.description.match(/Calories:\s*(\d+(?:\.\d+)?)/i);
        const proteinMatch = food.description.match(/Protein:\s*(\d+(?:\.\d+)?)g/i);
        const fatMatch = food.description.match(/Fat:\s*(\d+(?:\.\d+)?)g/i);
        const carbsMatch = food.description.match(/Carbs:\s*(\d+(?:\.\d+)?)g/i);

        calories = caloriesMatch ? parseFloat(caloriesMatch[1]) : 0;
        protein = proteinMatch ? parseFloat(proteinMatch[1]) : 0;
        fat = fatMatch ? parseFloat(fatMatch[1]) : 0;
        carbs = carbsMatch ? parseFloat(carbsMatch[1]) : 0;
      }
    }

    const servingSize = food.gramsServing || 100;

    // Resolve micronutrients for this food. USDA and Open Food Facts attach
    // canonical per-100g data to the search result; FatSecret only exposes it
    // via a detail lookup, so fetch it on demand here.
    let micronutrients: Record<string, number> = {};
    if (food.micronutrients && typeof food.micronutrients === 'object') {
      micronutrients = { ...food.micronutrients };
    }
    if (
      Object.keys(micronutrients).length === 0 &&
      food.source === 'fatsecret' &&
      food.raw &&
      typeof food.raw === 'object'
    ) {
      const foodId = (food.raw as Record<string, unknown>).food_id;
      const fsKey = this.plugin.settings.fatSecretApiKey?.trim();
      const fsSecret = this.plugin.settings.fatSecretApiSecret?.trim();
      if (foodId && fsKey && fsSecret) {
        try {
          const fsMicros = await fetchFatSecretMicronutrients(
            this.app,
            String(foodId),
            fsKey,
            fsSecret
          );
          if (fsMicros) micronutrients = fsMicros.micronutrients;
        } catch (microErr) {
          this.plugin.logger.error('Error fetching FatSecret micronutrients:', microErr);
        }
      }
    }
    // Source values are per 100g; rescale to the stored serving size so they
    // match the macros and the scaling done by extractMicronutrients().
    if (Object.keys(micronutrients).length > 0 && servingSize !== 100) {
      const microScale = servingSize / 100;
      const rescaled: Record<string, number> = {};
      for (const [k, v] of Object.entries(micronutrients)) rescaled[k] = v * microScale;
      micronutrients = rescaled;
    }

    // Create the markdown content
    const fdcId =
      food.source === 'usda' && food.raw && typeof food.raw === 'object' && 'fdcId' in food.raw
        ? (food.raw as Record<string, unknown>).fdcId
        : '';

    // Sanitize filename for actual file creation
    const safeFileName = this.sanitizeFileName(fileName);

    let frontmatter = `---
calories: ${calories}
protein: ${protein}
fat: ${fat}
carbs: ${carbs}
serving_size: ${servingSize}g${defaultServing ? `\ndefault_serving_size: ${defaultServing}g` : ''}
source: ${food.source}`;

    // Add source-specific metadata
    if (food.source === 'usda') {
      frontmatter += `\nfdc_id: ${fdcId}\ndata_type: ${food.dataType || ''}`;
    } else if (food.source === 'openfoodfacts') {
      const offCode =
        food.raw && typeof food.raw === 'object' && 'code' in food.raw
          ? (food.raw as Record<string, unknown>).code
          : '';
      frontmatter += `\noff_code: ${offCode}`;

      if (fiber) frontmatter += `\nfiber: ${fiber}`;
      if (sugars) frontmatter += `\nsugars: ${sugars}`;
      if (salt) frontmatter += `\nsalt: ${salt}`;
    }

    if (food.brandName) frontmatter += `\nbrand: ${food.brandName}`;
    if (food.nutritionGrade) frontmatter += `\nnutrition_grade: ${food.nutritionGrade}`;
    if (food.novaGroup) frontmatter += `\nnova_group: ${food.novaGroup}`;
    if (food.dataQuality) frontmatter += `\ndata_quality: ${food.dataQuality}`;

    // Add micronutrient keys (read back by extractMicronutrients()).
    for (const microKey of MICRONUTRIENT_KEYS) {
      const microValue = micronutrients[microKey];
      if (microValue == null || !Number.isFinite(microValue) || microValue === 0) continue;
      frontmatter += `\n${microKey}: ${formatMicroAmount(microValue)}`;
    }

    frontmatter += `\ncreated: ${new Date().toISOString()}
---

# ${fileName}

${food.description}

## Nutritional Information (per ${servingSize}g)
- **Calories:** ${calories} kcal
- **Protein:** ${protein}g
- **Fat:** ${fat}g
- **Carbohydrates:** ${carbs}g`;

    if (fiber) frontmatter += `\n- **Fiber:** ${fiber}g`;
    if (sugars) frontmatter += `\n- **Sugars:** ${sugars}g`;
    if (salt) frontmatter += `\n- **Salt:** ${salt}g`;

    // Readable micronutrient breakdown for any nutrients that were resolved.
    const microKeysPresent = MICRONUTRIENT_KEYS.filter(
      (k) =>
        micronutrients[k] != null && Number.isFinite(micronutrients[k]) && micronutrients[k] !== 0
    );
    if (microKeysPresent.length > 0) {
      frontmatter += `\n\n## Micronutrients (per ${servingSize}g)`;
      for (const microKey of microKeysPresent) {
        const def = MICRONUTRIENT_MAP[microKey];
        const microLabel = def ? def.label : microKey;
        const microUnit = def ? def.unit : '';
        frontmatter += `\n- **${microLabel}:** ${formatMicroAmount(micronutrients[microKey])}${microUnit}`;
      }
    }

    let sourceText = '';
    if (food.source === 'usda') {
      sourceText = 'USDA FoodData Central';
    } else if (food.source === 'openfoodfacts') {
      sourceText = 'Open Food Facts (Community Database)';
    } else {
      sourceText = 'FatSecret';
    }

    frontmatter += `\n\n**Source:** ${sourceText}`;
    if (food.brandName) frontmatter += `\n**Brand:** ${food.brandName}`;
    if (food.nutritionGrade)
      frontmatter += `\n**Nutrition Grade:** ${food.nutritionGrade.toUpperCase()} (Nutri-Score)`;
    if (food.novaGroup) {
      const novaLabels = [
        '',
        'Unprocessed or minimally processed',
        'Processed culinary ingredients',
        'Processed foods',
        'Ultra-processed foods',
      ];
      frontmatter += `\n**Processing Level:** NOVA ${food.novaGroup} (${novaLabels[food.novaGroup]})`;
    }
    if (defaultServing && defaultServing !== servingSize) {
      frontmatter += `\n**Default Serving Size:** ${defaultServing}g`;
    }
    if (food.categories) frontmatter += `\n**Categories:** ${food.categories}`;
    if (food.ingredients) frontmatter += `\n\n**Ingredients:** ${food.ingredients}`;

    // Add data quality notice for Open Food Facts
    if (food.source === 'openfoodfacts' && food.dataQuality !== 'high') {
      frontmatter += `\n\n> **Note:** This data comes from the Open Food Facts community database. Please verify nutrition information if accuracy is critical for your needs.`;
    }

    const folderPath = normalizePath(this.plugin.settings.storageFolder);

    // Ensure folder exists
    const folder = this.app.vault.getFolderByPath(folderPath);
    if (!folder) {
      await this.app.vault.createFolder(folderPath);
    }

    const filePath = normalizePath(`${folderPath}/${safeFileName}.md`);

    try {
      // Use proper Obsidian API for file creation
      await this.app.vault.create(filePath, frontmatter);

      let successMessage = `Food item "${fileName}" saved successfully!`;
      if (defaultServing && defaultServing !== servingSize) {
        successMessage += ` Default serving: ${defaultServing}g`;
      }
      new Notice(successMessage);

      // Update the food object with the saved file name
      food.name = fileName;

      // Invalidate cache to make new file immediately available
      this.plugin.dataManager.invalidateFileCache();
    } catch (error) {
      if ((error as Error).message?.includes('already exists')) {
        throw new Error('File already exists. Please choose a different name.');
      }
      throw error;
    }
  }

  private setupInfiniteScroll(searchTerm: string): void {
    // Store current search term
    this.currentSearchTerm = searchTerm;

    // Remove existing scroll listener if it exists
    if (this.scrollHandler) {
      this.resultsContainer.removeEventListener('scroll', this.scrollHandler);
    }

    // Create new scroll handler
    // Fixed: Prefix unused parameter with underscore
    this.scrollHandler = (_event: Event) => {
      this.handleScroll();
    };

    // Add new scroll listener
    this.component.registerDomEvent(this.resultsContainer, 'scroll', this.scrollHandler);
  }

  private handleScroll = async () => {
    if (this.isLoadingMore || !this.hasMoreResults || this.isBarcodeSearch) return;

    const container = this.resultsContainer;
    const scrollTop = container.scrollTop;
    const scrollHeight = container.scrollHeight;
    const clientHeight = container.clientHeight;

    // Load more when user scrolls to within 100px of bottom
    if (scrollTop + clientHeight >= scrollHeight - 100) {
      await this.loadMoreResults(this.currentSearchTerm);
    }
  };

  private async loadMoreResults(searchTerm: string): Promise<void> {
    if (this.isLoadingMore || !this.hasMoreResults || !this.plugin || this.isBarcodeSearch) return;

    this.isLoadingMore = true;
    this.currentPage++;

    try {
      const settings = this.plugin.settings;
      let newResults: UnifiedFoodResult[] = [];

      if (this.currentTab === 'openfoodfacts') {
        // Load more Open Food Facts results
        if (settings.openFoodFactsEnabled !== false) {
          const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';
          const offLanguage =
            settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

          const { searchOpenFoodFacts } = await import('../../core/openFoodFacts');
          const offResults = await searchOpenFoodFacts(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            offLanguage
          );

          newResults = offResults.map((item) => ({
            id: `off_${item.code}`,
            name: item.productName,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'openfoodfacts' as const,
            brandName: item.brands,
            nutritionGrade: item.nutritionGrade,
            novaGroup: item.novaGroup,
            dataQuality: item.dataQuality,
            completeness: item.completeness,
            ecoscore: item.ecoscore,
            imageUrl: item.imageUrl,
            categories: item.categories,
            ingredients: item.ingredientsText,
            micronutrients: item.micronutrients,
            raw: item,
          }));
        }
      } else if (this.currentTab === 'usda-foundation') {
        // Foundation foods don't typically support pagination well, disable
        this.hasMoreResults = false;
        return;
      } else if (this.currentTab === 'usda-branded') {
        // Load more branded results
        if (settings.usdaEnabled && settings.usdaApiKey) {
          const usdaResults = await searchFoods(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            settings.usdaApiKey
          );
          newResults = usdaResults
            .filter((item) => item.isBranded)
            .map((item) => ({
              id: `usda_${item.fdcId}`,
              name: item.description,
              description: item.displayDescription,
              gramsServing: item.gramsServing,
              source: 'usda' as const,
              brandName: item.brandName,
              isFoundation: item.isFoundation,
              isBranded: item.isBranded,
              isSrLegacy: item.isSrLegacy,
              dataType: item.dataType,
              micronutrients: item.micronutrients,
              raw: item,
            }));
        }
      } else if (this.currentTab === 'usda-legacy') {
        // Load more legacy results
        if (settings.usdaEnabled && settings.usdaApiKey) {
          const usdaResults = await searchFoods(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            settings.usdaApiKey
          );
          newResults = usdaResults
            .filter((item) => item.isSrLegacy)
            .map((item) => ({
              id: `usda_${item.fdcId}`,
              name: item.description,
              description: item.displayDescription,
              gramsServing: item.gramsServing,
              source: 'usda' as const,
              brandName: item.brandName,
              isFoundation: item.isFoundation,
              isBranded: item.isBranded,
              isSrLegacy: item.isSrLegacy,
              dataType: item.dataType,
              micronutrients: item.micronutrients,
              raw: item,
            }));
        }
      } else if (this.currentTab === 'fatsecret') {
        // Load more FatSecret results ONLY
        if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
          // Import FatSecret search function directly
          const { searchFatSecret } = await import('../../core/search');

          newResults = await searchFatSecret(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            settings.fatSecretApiKey,
            settings.fatSecretApiSecret
          );
        }
      } else if (this.currentTab === 'all') {
        // Load more from all sources
        const sources: {
          fatSecret?: { enabled: boolean; apiKey: string; apiSecret: string };
          usda?: { enabled: boolean; apiKey: string };
          openFoodFacts?: { enabled: boolean };
        } = {};

        if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
          sources.fatSecret = {
            enabled: true,
            apiKey: settings.fatSecretApiKey,
            apiSecret: settings.fatSecretApiSecret,
          };
        }
        if (settings.usdaEnabled && settings.usdaApiKey) {
          sources.usda = {
            enabled: true,
            apiKey: settings.usdaApiKey,
          };
        }
        if (settings.openFoodFactsEnabled !== false) {
          sources.openFoodFacts = {
            enabled: true,
          };
        }

        const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';
        const offLanguage =
          settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

        newResults = await searchAllSources(
          this.app,
          searchTerm,
          this.currentPage,
          this.maxResults,
          sources,
          offLanguage
        );
      }

      if (newResults.length > 0) {
        // Filter out duplicates based on ID
        const existingIds = new Set(this.allResults.map((r) => r.id));
        const uniqueNewResults = newResults.filter((r) => !existingIds.has(r.id));

        if (uniqueNewResults.length > 0) {
          this.allResults.push(...uniqueNewResults);
          this.results = this.allResults;
          this.hasMoreResults = newResults.length > 0;

          // Update Fuse index with new results
          const allFoodDocs: FoodDoc[] = this.allResults.map(unifiedResultToFoodDoc);
          buildFuseIndex(this.currentTab, allFoodDocs);

          // Re-render with new results
          this.renderResults(searchTerm);
          this.storeResultsInCache(searchTerm);
        } else {
          // No new unique results, stop pagination
          this.hasMoreResults = false;
        }
      } else {
        this.hasMoreResults = false;
      }
    } catch (error) {
      this.hasMoreResults = false;
    } finally {
      this.isLoadingMore = false;
    }
  }
}

// Enhanced FileNameModal with default serving size option
class FileNameModal extends Modal {
  private fileNameInput: HTMLInputElement;
  private defaultServingInput: HTMLInputElement;
  private submitButton: HTMLElement;
  private component: Component;
  private isSubmitting = false;

  constructor(
    app: App,
    private defaultName: string,
    private originalServingSize: number, // The serving size from the API result
    private onSubmit: (fileName: string, defaultServing?: number) => Promise<boolean>, // Updated signature
    private plugin?: MacrosPlugin
  ) {
    super(app);
    this.component = new Component();
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.addClass('file-name-modal');

    // Fixed: Prefix unused variables with underscore
    const _header = contentEl.createEl('h2', {
      text: 'Save Food Item',
      cls: 'modal-title',
    });

    const _description = contentEl.createEl('p', {
      text: 'Please enter a name and default serving size for this food item:',
      cls: 'modal-description',
    });

    // Input container
    const inputContainer = contentEl.createDiv({ cls: 'modal-content' });

    // File name input section
    const nameSection = inputContainer.createDiv({ cls: 'setting-item' });
    const nameInfo = nameSection.createDiv({ cls: 'setting-item-info' });
    nameInfo.createDiv({
      text: 'File Name:',
      cls: 'setting-item-name',
    });

    const nameControl = nameSection.createDiv({ cls: 'setting-item-control' });
    this.fileNameInput = nameControl.createEl('input', {
      type: 'text',
      cls: 'mod-text',
      value: this.defaultName,
    });

    // Default serving size input section
    const servingSection = inputContainer.createDiv({ cls: 'setting-item' });
    const servingInfo = servingSection.createDiv({ cls: 'setting-item-info' });
    servingInfo.createDiv({
      text: 'Default Serving Size (grams):',
      cls: 'setting-item-name',
    });
    servingInfo.createDiv({
      text: `Optional: Set a custom default serving size for when you add this food to your macros. If not set, it will use ${this.originalServingSize}g from the API.`,
      cls: 'setting-item-description',
    });

    const servingControl = servingSection.createDiv({ cls: 'setting-item-control' });
    this.defaultServingInput = servingControl.createEl('input', {
      type: 'number',
      cls: 'mod-text',
      value: this.originalServingSize.toString(),
      attr: {
        min: '1',
        step: '0.1',
        placeholder: this.originalServingSize.toString(),
      },
    });

    // Button container
    const buttonContainer = contentEl.createDiv({ cls: 'modal-button-container' });

    const cancelButton = buttonContainer.createEl('button', {
      text: 'Cancel',
      cls: 'mod-button',
    });

    this.submitButton = buttonContainer.createEl('button', {
      text: 'Save',
      cls: 'mod-button mod-cta',
    });

    // Event handlers
    this.component.registerDomEvent(cancelButton, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(this.submitButton, 'click', async () => {
      await this.handleSubmit();
    });

    this.component.registerDomEvent(this.fileNameInput, 'keydown', async (event: KeyboardEvent) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        // Move to serving size input
        this.defaultServingInput.focus();
      } else if (event.key === 'Escape') {
        this.close();
      }
    });

    this.component.registerDomEvent(
      this.defaultServingInput,
      'keydown',
      async (event: KeyboardEvent) => {
        if (event.key === 'Enter') {
          event.preventDefault();
          await this.handleSubmit();
        } else if (event.key === 'Escape') {
          this.close();
        }
      }
    );

    // Auto-focus and select text
    window.setTimeout(() => {
      this.fileNameInput.focus();
      this.fileNameInput.select();
    }, 50);
  }

  private async handleSubmit(): Promise<void> {
    // Prevent double submission
    if (this.isSubmitting) return;

    const fileName = this.fileNameInput.value.trim();
    const defaultServingStr = this.defaultServingInput.value.trim();

    if (!fileName) {
      new Notice('Please enter a file name.');
      this.fileNameInput.focus();
      return;
    }

    // Validate serving size
    const defaultServing = parseFloat(defaultServingStr);
    if (isNaN(defaultServing) || defaultServing <= 0) {
      new Notice('Please enter a valid serving size greater than 0.');
      this.defaultServingInput.focus();
      return;
    }

    // Disable button during submission
    this.isSubmitting = true;
    (this.submitButton as HTMLButtonElement).disabled = true;
    this.submitButton.textContent = 'Saving...';

    try {
      // Pass both filename and default serving size
      const shouldClose = await this.onSubmit(fileName, defaultServing);
      if (shouldClose) {
        this.close();
      }
    } catch (error) {
      new Notice(`Error: ${(error as Error).message}`);
    } finally {
      // Re-enable button
      this.isSubmitting = false;
      (this.submitButton as HTMLButtonElement).disabled = false;
      this.submitButton.textContent = 'Save';
    }
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { Modal, Notice, normalizePath, Component } from 'obsidian';
import { parseGrams, processNutritionalData, findMatchingFoodFile } from '../../utils';
import { MealTemplate } from '../../settings/StorageService';
import MacrosPlugin from '../../main';
import { CustomServingSizeModal } from './CustomServingSizeModal';
import { t } from '../../lang/I18nManager';

export class AddFoodToMealModal extends Modal {
  plugin: MacrosPlugin;
  meal: MealTemplate;
  files: string[] = [];
  itemListEl: HTMLElement | null = null;
  private component: Component;

  constructor(plugin: MacrosPlugin, meal: MealTemplate) {
    super(plugin.app);
    this.plugin = plugin;
    this.meal = meal;
    this.component = new Component();
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.createEl('h2', { text: t('meals.addTo.title') + ` "${this.meal.name}"` });

    const row = contentEl.createDiv({ cls: 'add-food-row' });
    const folder = normalizePath(this.plugin.settings.storageFolder);
    const fileList = this.app.vault.getFiles().filter((f) => f.path.startsWith(folder));
    this.files = fileList.map((f) => f.name.replace(/\.md$/, ''));

    const dropdown = row.createEl('select');
    dropdown.createEl('option', { text: `-- ${t('food.search.placeholder')} --`, value: '' });
    this.files.forEach((fname) => {
      const option = dropdown.createEl('option');
      option.value = fname;
      option.text = fname;
    });

    const addBtn = row.createEl('button', {
      text: t('general.add') + ' ' + t('food.search.title').toLowerCase(),
    });
    this.component.registerDomEvent(addBtn, 'click', async () => {
      const selected = dropdown.value;
      if (selected && !this.meal.items.some((item) => item.startsWith(selected))) {
        const matchingFile = findMatchingFoodFile(fileList, selected);
        if (!matchingFile) {
          new Notice(t('errors.fileNotFound'));
          return;
        }

        const nutrition = processNutritionalData(this.app, matchingFile);
        if (!nutrition || !nutrition.serving) {
          new Notice(t('errors.noNutritionData'));
          return;
        }

        const defaultServing = parseGrams(nutrition.serving);
        if (isNaN(defaultServing)) {
          new Notice(t('errors.invalidServing'));
          return;
        }

        new CustomServingSizeModal(
          this.app,
          selected,
          defaultServing,
          async (customServing: number) => {
            this.meal.items.push(`${selected}:${customServing}g`);
            await this.plugin.saveSettings();
            this.refreshItemList();
            new Notice(t('notifications.itemsAdded', { count: '1' }));
          },
          this.plugin
        ).open();
      } else {
        new Notice(t('validation.selectAtLeastOne'));
      }
    });

    this.itemListEl = contentEl.createEl('ul');
    this.itemListEl.classList.add('meal-item-list');
    this.refreshItemList();

    const finishBtn = contentEl.createEl('button', { text: t('general.close') });
    this.component.registerDomEvent(finishBtn, 'click', () => {
      this.close();
      this.plugin.nutritionalSettingTab.display();
    });
  }

  private refreshItemList() {
    if (!this.itemListEl) return;
    this.itemListEl.empty();
    const list = this.itemListEl;
    this.meal.items.forEach((item, index) => {
      const li = list.createEl('li');
      const span = li.createEl('span', { text: item });
      span.classList.add('meal-item-label');

      const removeBtn = li.createEl('button', { text: '├ù' });
      removeBtn.classList.add('mod-button', 'mod-warning', 'remove-meal-item-button');

      this.component.registerDomEvent(removeBtn, 'click', async () => {
        this.meal.items.splice(index, 1);
        await this.plugin.saveSettings();
        this.refreshItemList();
        new Notice(t('general.remove') + ` "${item}" ${t('general.from')} ${this.meal.name}`);
      });
    });
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { Modal, Notice, normalizePath, Component } from 'obsidian';
import { parseGrams, processNutritionalData } from '../../utils';
import { MealTemplate } from '../../settings/StorageService';
import MacrosPlugin from '../../main';
import { CustomServingSizeModal } from './CustomServingSizeModal';
import { t } from '../../lang/I18nManager';
import { convertEnergyUnit } from '../../utils/energyUtils';

interface FoodItemData {
  name: string;
  file: import('obsidian').TFile;
  nutrition?: {
    calories: number;
    protein: number;
    fat: number;
    carbs: number;
    serving: string;
  };
  isSelected: boolean;
  customServing?: number;
}

export class AddMealTemplateModal extends Modal {
  plugin: MacrosPlugin;
  private component: Component;

  // UI elements
  private mealNameInput: HTMLInputElement;
  private searchInput: HTMLInputElement;
  private foodsContainer: HTMLElement;
  private selectedItemsContainer: HTMLElement;
  private createButton: HTMLElement;

  // Data
  private newMealName = '';
  private allFoods: FoodItemData[] = [];
  private filteredFoods: FoodItemData[] = [];

  constructor(plugin: MacrosPlugin) {
    super(plugin.app);
    this.plugin = plugin;
    this.component = new Component();
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.addClass('enhanced-meal-template-modal');

    // Load and prepare data
    await this.loadData();

    // Create the interface
    this.createHeader();
    this.createMealNameSection();
    this.createSearchBar();
    this.createFoodsSection();
    this.createSelectedItemsSection();
    this.createActionButtons();

    // Initial render
    this.filterAndRender('');
    this.updateSelectedItemsDisplay();

    // Focus on meal name input
    this.mealNameInput.focus();
  }

  private async loadData(): Promise<void> {
    // Load all food items
    const folder = normalizePath(this.plugin.settings.storageFolder);
    const fileList = this.app.vault.getFiles().filter((f) => f.path.startsWith(folder));

    this.allFoods = await Promise.all(
      fileList.map(async (file): Promise<FoodItemData> => {
        const name = file.name.replace(/\.md$/, '');
        const nutrition = processNutritionalData(this.app, file);

        return {
          name,
          file,
          nutrition: nutrition
            ? {
                calories: nutrition.calories,
                protein: nutrition.protein,
                fat: nutrition.fat,
                carbs: nutrition.carbs,
                serving: nutrition.serving || '100g',
              }
            : undefined,
          isSelected: false,
        };
      })
    );

    // Sort foods alphabetically
    this.allFoods.sort((a, b) =>
      a.name.localeCompare(b.name, 'en-US', {
        sensitivity: 'base',
        numeric: true,
        ignorePunctuation: true,
      })
    );
  }

  private createHeader(): void {
    const header = this.contentEl.createDiv({ cls: 'modal-header macros-modal-header' });
    header.createEl('h2', {
      text: t('meals.create.title'),
      cls: 'modal-title macros-modal-title',
    });
    header.createEl('p', {
      text: t('meals.create.description'),
      cls: 'modal-description macros-modal-description',
    });
  }

  private createMealNameSection(): void {
    const nameSection = this.contentEl.createDiv({ cls: 'meal-name-section' });

    const _label = nameSection.createEl('label', {
      text: t('meals.create.nameLabel'),
      cls: 'meal-name-label',
    });

    this.mealNameInput = nameSection.createEl('input', {
      type: 'text',
      cls: 'meal-name-input',
      attr: { placeholder: t('meals.create.namePlaceholder') },
    });

    // Add validation and update functionality
    this.component.registerDomEvent(this.mealNameInput, 'input', () => {
      this.newMealName = this.mealNameInput.value.trim();
      this.updateCreateButtonState();
    });

    this.component.registerDomEvent(this.mealNameInput, 'keydown', (event: KeyboardEvent) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        if (this.newMealName) {
          this.searchInput.focus();
        }
      }
    });
  }

  private createSearchBar(): void {
    const searchContainer = this.contentEl.createDiv({
      cls: 'search-container macros-search-container',
    });

    const searchWrapper = searchContainer.createDiv({
      cls: 'search-wrapper macros-search-wrapper',
    });
    searchWrapper.createEl('span', { cls: 'search-icon macros-search-icon', text: '­ƒöì' });

    this.searchInput = searchWrapper.createEl('input', {
      type: 'text',
      cls: 'search-input macros-search-input',
      attr: { placeholder: t('meals.create.searchPlaceholder') },
    });

    // Add search functionality
    this.component.registerDomEvent(this.searchInput, 'input', () => {
      const query = this.searchInput.value;
      this.filterAndRender(query);
    });
  }

  private createFoodsSection(): void {
    const sectionContainer = this.contentEl.createDiv({ cls: 'foods-section' });

    const sectionHeader = sectionContainer.createDiv({ cls: 'section-header' });
    sectionHeader.createEl('h3', { text: t('meals.create.availableFoods'), cls: 'section-title' });

    this.foodsContainer = sectionContainer.createDiv({ cls: 'foods-container' });
  }

  private filterAndRender(query: string): void {
    const searchTerm = query.toLowerCase().trim();

    // Filter foods
    this.filteredFoods = this.allFoods.filter((food) =>
      food.name.toLowerCase().includes(searchTerm)
    );

    // Render filtered results
    this.renderFoods();
  }

  private renderFoods(): void {
    this.foodsContainer.empty();

    if (this.filteredFoods.length === 0) {
      this.foodsContainer.createDiv({
        cls: 'no-results macros-no-results',
        text: t('meals.create.noResults'),
      });
      return;
    }

    this.filteredFoods.forEach((food) => {
      const foodCard = this.foodsContainer.createDiv({ cls: 'food-card' });

      // Food name
      const foodHeader = foodCard.createDiv({ cls: 'food-header' });
      foodHeader.createEl('h3', { text: food.name, cls: 'food-name' });

      // Enhanced nutrition info with kJ support
      if (food.nutrition) {
        const nutritionInfo = foodCard.createDiv({ cls: 'nutrition-info macros-nutrition-info' });

        // Enhanced calorie display with kJ support
        const currentEnergyUnit = this.plugin.settings.energyUnit;
        const calorieSpan = nutritionInfo.createEl('span', {
          cls: 'nutrition-item macros-nutrition-item calories',
        });

        if (currentEnergyUnit === 'kJ') {
          const kjValue = convertEnergyUnit(food.nutrition.calories, 'kcal', 'kJ');
          calorieSpan.textContent = `${kjValue.toFixed(1)} kJ`;
          // Add tooltip showing both units
          calorieSpan.setAttribute(
            'title',
            `${food.nutrition.calories.toFixed(1)} kcal = ${kjValue.toFixed(1)} kJ`
          );
        } else {
          calorieSpan.textContent = `${food.nutrition.calories.toFixed(1)} kcal`;
        }

        nutritionInfo.createEl('span', {
          text: `${food.nutrition.protein.toFixed(1)}g ${t('table.headers.protein').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item protein',
        });
        nutritionInfo.createEl('span', {
          text: `${food.nutrition.fat.toFixed(1)}g ${t('table.headers.fat').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item fat',
        });
        nutritionInfo.createEl('span', {
          text: `${food.nutrition.carbs.toFixed(1)}g ${t('table.headers.carbs').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item carbs',
        });

        // Serving size
        const servingInfo = foodCard.createDiv({ cls: 'serving-info' });
        const servingText = food.customServing
          ? t('meals.create.customServing', { serving: food.customServing.toString() })
          : t('meals.create.defaultServing', { serving: food.nutrition.serving });
        servingInfo.createEl('span', {
          text: servingText,
          cls: 'serving-size',
        });
      }

      // Action buttons container
      const buttonContainer = foodCard.createDiv({
        cls: 'button-container macros-button-container',
      });

      if (food.isSelected) {
        // Remove button
        const removeButton = buttonContainer.createEl('button', {
          text: t('meals.create.remove'),
          cls: 'remove-button',
          attr: { type: 'button' },
        });

        // Edit serving button (if nutrition data available)
        if (food.nutrition) {
          const editButton = buttonContainer.createEl('button', {
            text: t('meals.create.editServing'),
            cls: 'edit-button',
            attr: { type: 'button' },
          });

          this.component.registerDomEvent(editButton, 'click', () => {
            this.editFoodServing(food);
          });
        }

        this.component.registerDomEvent(removeButton, 'click', () => {
          this.removeFood(food);
        });

        foodCard.addClass('selected');
      } else {
        // Add button
        const addButton = buttonContainer.createEl('button', {
          text: t('meals.create.addToMeal'),
          cls: 'add-button',
          attr: { type: 'button' },
        });

        this.component.registerDomEvent(addButton, 'click', () => {
          this.addFood(food);
        });
      }
    });
  }

  private async addFood(food: FoodItemData): Promise<void> {
    if (!food.nutrition) {
      new Notice(t('validation.noNutritionData'));
      return;
    }

    const defaultServing = parseGrams(food.nutrition.serving);

    new CustomServingSizeModal(
      this.app,
      food.name,
      defaultServing,
      async (customServing: number) => {
        // Update the food item
        food.isSelected = true;
        food.customServing = customServing;

        this.updateUI();
        new Notice(t('notifications.itemsAdded', { count: '1' }));
      },
      this.plugin
    ).open();
  }

  private removeFood(food: FoodItemData): void {
    // Update the food item
    food.isSelected = false;
    food.customServing = undefined;

    this.updateUI();
    new Notice(t('general.remove') + ` ${food.name}`);
  }

  private editFoodServing(food: FoodItemData): void {
    if (!food.nutrition || !food.customServing) return;

    new CustomServingSizeModal(
      this.app,
      food.name,
      food.customServing,
      async (newServing: number) => {
        // Update the food item
        food.customServing = newServing;

        this.updateUI();
        new Notice(t('general.success'));
      },
      this.plugin
    ).open();
  }

  private updateUI(): void {
    this.renderFoods();
    this.updateSelectedItemsDisplay();
    this.updateCreateButtonState();
  }

  private createSelectedItemsSection(): void {
    const selectedSection = this.contentEl.createDiv({ cls: 'selected-items-section' });

    const header = selectedSection.createDiv({ cls: 'selected-header' });
    header.createEl('h3', { text: t('meals.create.selectedItems'), cls: 'selected-title' });

    this.selectedItemsContainer = selectedSection.createDiv({ cls: 'selected-items-container' });
  }

  private updateSelectedItemsDisplay(): void {
    this.selectedItemsContainer.empty();

    const selectedFoods = this.allFoods.filter((food) => food.isSelected);

    if (selectedFoods.length === 0) {
      this.selectedItemsContainer.createDiv({
        cls: 'no-selected-items',
        text: t('meals.create.noSelectedItems'),
      });
    } else {
      selectedFoods.forEach((food) => {
        const itemTag = this.selectedItemsContainer.createDiv({ cls: 'selected-item-tag' });

        const displayText = food.customServing ? `${food.name}:${food.customServing}g` : food.name;

        itemTag.createEl('span', { text: displayText, cls: 'item-text' });

        const removeButton = itemTag.createEl('button', {
          text: '├ù',
          cls: 'remove-item-button',
          attr: { type: 'button' },
        });

        this.component.registerDomEvent(removeButton, 'click', () => {
          this.removeFood(food);
        });
      });
    }
  }

  private updateCreateButtonState(): void {
    if (!this.createButton) return;

    const hasName = this.newMealName.length > 0;
    const hasItems = this.allFoods.some((food) => food.isSelected);
    const canCreate = hasName && hasItems;

    if (canCreate) {
      this.createButton.removeClass('disabled');
      (this.createButton as HTMLButtonElement).disabled = false;
    } else {
      this.createButton.addClass('disabled');
      (this.createButton as HTMLButtonElement).disabled = true;
    }
  }

  private createActionButtons(): void {
    const buttonContainer = this.contentEl.createDiv({
      cls: 'action-buttons macros-action-buttons',
    });

    const cancelButton = buttonContainer.createEl('button', {
      text: t('general.cancel'),
      cls: 'cancel-button',
      attr: { type: 'button' },
    });

    this.createButton = buttonContainer.createEl('button', {
      text: t('meals.create.create'),
      cls: 'create-button disabled',
      attr: { type: 'button' },
    });

    (this.createButton as HTMLButtonElement).disabled = true;

    this.component.registerDomEvent(cancelButton, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(this.createButton, 'click', async () => {
      await this.createMealTemplate();
    });
  }

  private async createMealTemplate(): Promise<void> {
    // Validate meal name
    if (!this.newMealName) {
      new Notice(t('validation.enterMealName'));
      this.mealNameInput.focus();
      return;
    }

    // Check for duplicate names
    const existingMeal = this.plugin.settings.mealTemplates.find(
      (m: MealTemplate) => m.name.toLowerCase() === this.newMealName.toLowerCase()
    );

    if (existingMeal) {
      new Notice(t('validation.duplicateMealName'));
      this.mealNameInput.focus();
      return;
    }

    // Get selected foods
    const selectedFoods = this.allFoods.filter((food) => food.isSelected);

    if (selectedFoods.length === 0) {
      new Notice(t('validation.selectAtLeastOne'));
      return;
    }

    // Create the meal template
    const newMeal: MealTemplate = {
      name: this.newMealName,
      items: selectedFoods.map((food) =>
        food.customServing ? `${food.name}:${food.customServing}g` : food.name
      ),
    };

    // Add to settings
    this.plugin.settings.mealTemplates.push(newMeal);
    await this.plugin.saveSettings();

    new Notice(
      t('notifications.mealTemplateCreated', {
        name: this.newMealName,
        count: selectedFoods.length.toString(),
      })
    );

    this.close();

    // Refresh the settings display
    this.plugin.nutritionalSettingTab.display();
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

// EditMealTemplateModal.ts - Enhanced with kJ support
export class EditMealTemplateModal extends Modal {
  plugin: MacrosPlugin;
  meal: MealTemplate;
  private component: Component;

  // UI elements
  private searchInput: HTMLInputElement;
  private foodsContainer: HTMLElement;
  private selectedItemsContainer: HTMLElement;
  private saveButton: HTMLElement;

  // Data
  private allFoods: FoodItemData[] = [];
  private filteredFoods: FoodItemData[] = [];

  constructor(plugin: MacrosPlugin, meal: MealTemplate) {
    super(plugin.app);
    this.plugin = plugin;
    this.meal = meal;
    this.component = new Component();
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.addClass('enhanced-meal-template-modal');

    // Load and prepare data
    await this.loadData();

    // Create the interface
    this.createHeader();
    this.createSearchBar();
    this.createFoodsSection();
    this.createSelectedItemsSection();
    this.createActionButtons();

    // Initial render
    this.filterAndRender('');
    this.updateSelectedItemsDisplay();
  }

  private async loadData(): Promise<void> {
    // Load all food items
    const folder = normalizePath(this.plugin.settings.storageFolder);
    const fileList = this.app.vault.getFiles().filter((f) => f.path.startsWith(folder));

    this.allFoods = await Promise.all(
      fileList.map(async (file): Promise<FoodItemData> => {
        const name = file.name.replace(/\.md$/, '');
        const nutrition = processNutritionalData(this.app, file);

        // Check if this food is already in the meal template
        const existingItem = this.meal.items.find((item) => {
          const itemName = item.includes(':') ? item.split(':')[0].trim() : item.trim();
          return itemName.toLowerCase() === name.toLowerCase();
        });

        let customServing: number | undefined;
        if (existingItem && existingItem.includes(':')) {
          customServing = parseGrams(existingItem.split(':')[1]);
        }

        return {
          name,
          file,
          nutrition: nutrition
            ? {
                calories: nutrition.calories,
                protein: nutrition.protein,
                fat: nutrition.fat,
                carbs: nutrition.carbs,
                serving: nutrition.serving || '100g',
              }
            : undefined,
          isSelected: !!existingItem,
          customServing,
        };
      })
    );

    // Sort foods alphabetically
    this.allFoods.sort((a, b) =>
      a.name.localeCompare(b.name, 'en-US', {
        sensitivity: 'base',
        numeric: true,
        ignorePunctuation: true,
      })
    );
  }

  private createHeader(): void {
    const header = this.contentEl.createDiv({ cls: 'modal-header macros-modal-header' });
    header.createEl('h2', {
      text: t('meals.edit.title', { mealName: this.meal.name }),
      cls: 'modal-title macros-modal-title',
    });
    header.createEl('p', {
      text: t('meals.edit.description'),
      cls: 'modal-description macros-modal-description',
    });
  }

  private createSearchBar(): void {
    const searchContainer = this.contentEl.createDiv({
      cls: 'search-container macros-search-container',
    });

    const searchWrapper = searchContainer.createDiv({
      cls: 'search-wrapper macros-search-wrapper',
    });
    searchWrapper.createEl('span', { cls: 'search-icon macros-search-icon', text: '­ƒöì' });

    this.searchInput = searchWrapper.createEl('input', {
      type: 'text',
      cls: 'search-input macros-search-input',
      attr: { placeholder: t('meals.create.searchPlaceholder') },
    });

    // Add search functionality
    this.component.registerDomEvent(this.searchInput, 'input', () => {
      const query = this.searchInput.value;
      this.filterAndRender(query);
    });
  }

  private createFoodsSection(): void {
    const sectionContainer = this.contentEl.createDiv({ cls: 'foods-section' });

    const sectionHeader = sectionContainer.createDiv({ cls: 'section-header' });
    sectionHeader.createEl('h3', { text: t('meals.create.availableFoods'), cls: 'section-title' });

    this.foodsContainer = sectionContainer.createDiv({ cls: 'foods-container' });
  }

  private filterAndRender(query: string): void {
    const searchTerm = query.toLowerCase().trim();

    // Filter foods
    this.filteredFoods = this.allFoods.filter((food) =>
      food.name.toLowerCase().includes(searchTerm)
    );

    // Render filtered results
    this.renderFoods();
  }

  private renderFoods(): void {
    this.foodsContainer.empty();

    if (this.filteredFoods.length === 0) {
      this.foodsContainer.createDiv({
        cls: 'no-results macros-no-results',
        text: t('meals.create.noResults'),
      });
      return;
    }

    this.filteredFoods.forEach((food) => {
      const foodCard = this.foodsContainer.createDiv({ cls: 'food-card' });

      // Food name
      const foodHeader = foodCard.createDiv({ cls: 'food-header' });
      foodHeader.createEl('h3', { text: food.name, cls: 'food-name' });

      // Enhanced nutrition info with kJ support
      if (food.nutrition) {
        const nutritionInfo = foodCard.createDiv({ cls: 'nutrition-info macros-nutrition-info' });

        // Enhanced calorie display with kJ support
        const currentEnergyUnit = this.plugin.settings.energyUnit;
        const calorieSpan = nutritionInfo.createEl('span', {
          cls: 'nutrition-item macros-nutrition-item calories',
        });

        if (currentEnergyUnit === 'kJ') {
          const kjValue = convertEnergyUnit(food.nutrition.calories, 'kcal', 'kJ');
          calorieSpan.textContent = `${kjValue.toFixed(1)} kJ`;
          // Add tooltip showing both units
          calorieSpan.setAttribute(
            'title',
            `${food.nutrition.calories.toFixed(1)} kcal = ${kjValue.toFixed(1)} kJ`
          );
        } else {
          calorieSpan.textContent = `${food.nutrition.calories.toFixed(1)} kcal`;
        }

        nutritionInfo.createEl('span', {
          text: `${food.nutrition.protein.toFixed(1)}g ${t('table.headers.protein').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item protein',
        });
        nutritionInfo.createEl('span', {
          text: `${food.nutrition.fat.toFixed(1)}g ${t('table.headers.fat').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item fat',
        });
        nutritionInfo.createEl('span', {
          text: `${food.nutrition.carbs.toFixed(1)}g ${t('table.headers.carbs').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item carbs',
        });

        // Serving size - Enhanced with proper translation keys
        const servingInfo = foodCard.createDiv({ cls: 'serving-info' });
        const servingText = food.customServing
          ? `Custom: ${food.customServing}g`
          : `Default: ${food.nutrition.serving}`;
        servingInfo.createEl('span', {
          text: servingText,
          cls: 'serving-size',
        });
      }

      // Action buttons container
      const buttonContainer = foodCard.createDiv({
        cls: 'button-container macros-button-container',
      });

      if (food.isSelected) {
        // Remove button
        const removeButton = buttonContainer.createEl('button', {
          text: t('meals.create.remove'),
          cls: 'remove-button',
          attr: { type: 'button' },
        });

        // Edit serving button (if nutrition data available)
        if (food.nutrition) {
          const editButton = buttonContainer.createEl('button', {
            text: t('meals.create.editServing'),
            cls: 'edit-button',
            attr: { type: 'button' },
          });

          this.component.registerDomEvent(editButton, 'click', () => {
            this.editFoodServing(food);
          });
        }

        this.component.registerDomEvent(removeButton, 'click', () => {
          this.removeFood(food);
        });

        foodCard.addClass('selected');
      } else {
        // Add button
        const addButton = buttonContainer.createEl('button', {
          text: t('meals.create.addToMeal'),
          cls: 'add-button',
          attr: { type: 'button' },
        });

        this.component.registerDomEvent(addButton, 'click', () => {
          this.addFood(food);
        });
      }
    });
  }

  private async addFood(food: FoodItemData): Promise<void> {
    if (!food.nutrition) {
      new Notice(t('validation.noNutritionData'));
      return;
    }

    const defaultServing = parseGrams(food.nutrition.serving);

    new CustomServingSizeModal(
      this.app,
      food.name,
      defaultServing,
      async (customServing: number) => {
        // Update the food item
        food.isSelected = true;
        food.customServing = customServing;

        // Add to meal template
        const itemString = `${food.name}:${customServing}g`;
        this.meal.items.push(itemString);

        await this.plugin.saveSettings();
        this.updateUI();

        new Notice(t('notifications.itemsAdded', { count: '1' }));
      },
      this.plugin
    ).open();
  }

  private async removeFood(food: FoodItemData): Promise<void> {
    // Update the food item
    food.isSelected = false;
    food.customServing = undefined;

    // Remove from meal template
    this.meal.items = this.meal.items.filter((item) => {
      const itemName = item.includes(':') ? item.split(':')[0].trim() : item.trim();
      return itemName.toLowerCase() !== food.name.toLowerCase();
    });

    await this.plugin.saveSettings();
    this.updateUI();

    new Notice(`${t('general.remove')} ${food.name}`);
  }

  private async editFoodServing(food: FoodItemData): Promise<void> {
    if (!food.nutrition || !food.customServing) return;

    new CustomServingSizeModal(
      this.app,
      food.name,
      food.customServing,
      async (newServing: number) => {
        // Update the food item
        food.customServing = newServing;

        // Update meal template
        const itemIndex = this.meal.items.findIndex((item) => {
          const itemName = item.includes(':') ? item.split(':')[0].trim() : item.trim();
          return itemName.toLowerCase() === food.name.toLowerCase();
        });

        if (itemIndex !== -1) {
          this.meal.items[itemIndex] = `${food.name}:${newServing}g`;
        }

        await this.plugin.saveSettings();
        this.updateUI();

        new Notice(t('general.success'));
      },
      this.plugin
    ).open();
  }

  private updateUI(): void {
    this.renderFoods();
    this.updateSelectedItemsDisplay();
  }

  private createSelectedItemsSection(): void {
    const selectedSection = this.contentEl.createDiv({ cls: 'selected-items-section' });

    const header = selectedSection.createDiv({ cls: 'selected-header' });
    header.createEl('h3', { text: t('meals.create.selectedItems'), cls: 'selected-title' });

    this.selectedItemsContainer = selectedSection.createDiv({ cls: 'selected-items-container' });
  }

  private updateSelectedItemsDisplay(): void {
    this.selectedItemsContainer.empty();

    const selectedFoods = this.allFoods.filter((food) => food.isSelected);

    if (selectedFoods.length === 0) {
      this.selectedItemsContainer.createDiv({
        cls: 'no-selected-items',
        text: t('meals.create.noSelectedItems'),
      });
    } else {
      selectedFoods.forEach((food) => {
        const itemTag = this.selectedItemsContainer.createDiv({ cls: 'selected-item-tag' });

        const displayText = food.customServing ? `${food.name}:${food.customServing}g` : food.name;

        itemTag.createEl('span', { text: displayText, cls: 'item-text' });

        const removeButton = itemTag.createEl('button', {
          text: '├ù',
          cls: 'remove-item-button',
          attr: { type: 'button' },
        });

        this.component.registerDomEvent(removeButton, 'click', () => {
          this.removeFood(food);
        });
      });
    }

    // Update save button state
    if (this.saveButton) {
      const hasItems = selectedFoods.length > 0;
      if (hasItems) {
        this.saveButton.removeClass('disabled');
        (this.saveButton as HTMLButtonElement).disabled = false;
      } else {
        this.saveButton.addClass('disabled');
        (this.saveButton as HTMLButtonElement).disabled = true;
      }
    }
  }

  private createActionButtons(): void {
    const buttonContainer = this.contentEl.createDiv({
      cls: 'action-buttons macros-action-buttons',
    });

    const cancelButton = buttonContainer.createEl('button', {
      text: t('general.cancel'),
      cls: 'cancel-button',
      attr: { type: 'button' },
    });

    this.saveButton = buttonContainer.createEl('button', {
      text: t('meals.edit.saveChanges'),
      cls: 'save-button',
      attr: { type: 'button' },
    });

    this.component.registerDomEvent(cancelButton, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(this.saveButton, 'click', async () => {
      await this.plugin.saveSettings();
      new Notice(t('notifications.mealTemplateUpdated', { name: this.meal.name }));
      this.close();

      // Refresh the settings display
      this.plugin.nutritionalSettingTab.display();
    });
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { App, Modal, Notice, TFile, normalizePath, Component } from 'obsidian';
import { parseGrams, processNutritionalData } from '../../utils';
import { MealTemplate } from '../../settings/StorageService';
import MacrosPlugin from '../../main';
import { CustomServingSizeModal } from './CustomServingSizeModal';
import { AddMealTemplateModal } from './AddMealTemplateModal';
import { t } from '../../lang/I18nManager';
import { convertEnergyUnit } from '../../utils/energyUtils';

interface FoodItemData {
  name: string;
  file: TFile;
  nutrition?: {
    calories: number;
    protein: number;
    fat: number;
    carbs: number;
    serving: string;
  };
}

interface MealNutritionData {
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
  itemCount: number;
}

export class AddToMacrosModal extends Modal {
  plugin: MacrosPlugin;
  tableId: string;
  onDone: () => Promise<void>;
  selectedItems: string[] = [];
  private component: Component;

  // UI elements
  private searchInput!: HTMLInputElement;
  private searchClearButton!: HTMLElement;
  private mealsContainer!: HTMLElement;
  private foodsContainer!: HTMLElement;
  private groupContainer!: HTMLElement;
  private selectedItemsContainer!: HTMLElement;
  private confirmButton!: HTMLElement;
  private mealsTab!: HTMLElement;
  private foodsTab!: HTMLElement;
  private groupTab!: HTMLElement;

  // Group creation elements
  private groupNameInput!: HTMLInputElement;
  private groupFoodsContainer!: HTMLElement;
  private groupSelectedItems: string[] = [];

  // Data
  private allMeals: MealTemplate[] = [];
  private mealNutritionData: Map<string, MealNutritionData> = new Map();
  private allFoods: FoodItemData[] = [];
  private filteredMeals: MealTemplate[] = [];
  private filteredFoods: FoodItemData[] = [];
  private filteredGroupFoods: FoodItemData[] = [];

  constructor(app: App, plugin: MacrosPlugin, tableId: string, onDone: () => Promise<void>) {
    super(app);
    this.plugin = plugin;
    this.tableId = tableId;
    this.onDone = onDone;
    this.component = new Component();
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.addClass('enhanced-add-to-macros-modal');

    try {
      // Load and prepare data
      await this.loadData();

      // Create the interface
      this.createHeader();
      this.createSearchBar();
      this.createTabsAndContent();
      this.createSelectedItemsSection();
      this.createActionButtons();

      // Initial render
      this.filterAndRender('');
      this.updateSelectedItemsDisplay();

      // Auto-focus search input
      window.setTimeout(() => {
        if (this.searchInput) {
          this.searchInput.focus();
          this.searchInput.setSelectionRange(0, 0);
        }
      }, 150);
    } catch (error) {
      // Without this guard, any error thrown above (e.g. while loading a
      // malformed meal template) leaves a completely blank modal with no
      // indication of what went wrong. Surface the problem instead.
      console.error('[Macros] Failed to open "Add to Macros" modal:', error);
      contentEl.empty();
      contentEl.addClass('enhanced-add-to-macros-modal');
      const errorBox = contentEl.createDiv({ cls: 'macros-modal-error' });
      errorBox.createEl('h2', { text: t('meals.addTo.title') });
      errorBox.createEl('p', {
        text: error instanceof Error ? error.message : String(error),
      });
    }
  }

  private async loadData(): Promise<void> {
    // Load meal templates. Normalize each entry defensively: a single malformed
    // template (a non-object entry, a missing/non-string `name`, or a
    // missing/`null`/non-array `items`) must not be able to throw and blank the
    // entire modal. Also guard against `mealTemplates` itself being absent or
    // not an array (the settings load is only a shallow merge with defaults).
    const rawMeals = Array.isArray(this.plugin.settings.mealTemplates)
      ? this.plugin.settings.mealTemplates
      : [];

    this.allMeals = rawMeals
      .filter((meal): meal is MealTemplate => meal != null && typeof meal === 'object')
      .map((meal) => ({
        ...meal,
        name: typeof meal.name === 'string' ? meal.name : '',
        items: Array.isArray(meal.items)
          ? meal.items.filter((item): item is string => typeof item === 'string')
          : [],
      }))
      .sort((a, b) =>
        a.name.localeCompare(b.name, 'en-US', {
          sensitivity: 'base',
          numeric: true,
          ignorePunctuation: true,
        })
      );

    // Calculate nutrition data for each meal
    await this.calculateMealNutrition();

    // Load food items
    const folder = normalizePath(this.plugin.settings.storageFolder);
    const fileList = this.app.vault.getFiles().filter((f: TFile) => f.path.startsWith(folder));

    this.allFoods = await Promise.all(
      fileList.map(async (file): Promise<FoodItemData> => {
        const name = file.name.replace(/\.md$/, '');
        const nutrition = processNutritionalData(this.app, file);

        return {
          name,
          file,
          nutrition: nutrition
            ? {
                calories: nutrition.calories,
                protein: nutrition.protein,
                fat: nutrition.fat,
                carbs: nutrition.carbs,
                serving: nutrition.serving || '100g',
              }
            : undefined,
        };
      })
    );

    // Sort foods alphabetically
    this.allFoods.sort((a, b) =>
      a.name.localeCompare(b.name, 'en-US', {
        sensitivity: 'base',
        numeric: true,
        ignorePunctuation: true,
      })
    );
  }

  private async calculateMealNutrition(): Promise<void> {
    for (const meal of this.allMeals) {
      let totalCalories = 0;
      let totalProtein = 0;
      let totalFat = 0;
      let totalCarbs = 0;
      let validItemCount = 0;

      for (const item of meal.items) {
        let foodName = item;
        let quantity = 100; // default

        if (item.includes(':')) {
          const parts = item.split(':').map((s) => s.trim());
          foodName = parts[0];
          quantity = parseGrams(parts[1]) || 100;
        }

        // Find the food file
        const folder = normalizePath(this.plugin.settings.storageFolder);
        const fileList = this.app.vault.getFiles().filter((f: TFile) => f.path.startsWith(folder));
        const matchingFile = fileList.find(
          (f) => f.name.replace(/\.md$/, '').toLowerCase() === foodName.toLowerCase()
        );

        if (matchingFile) {
          const nutrition = processNutritionalData(this.app, matchingFile, quantity);
          if (nutrition) {
            totalCalories += nutrition.calories;
            totalProtein += nutrition.protein;
            totalFat += nutrition.fat;
            totalCarbs += nutrition.carbs;
            validItemCount++;
          }
        }
      }

      this.mealNutritionData.set(meal.name, {
        calories: totalCalories,
        protein: totalProtein,
        fat: totalFat,
        carbs: totalCarbs,
        itemCount: validItemCount,
      });
    }
  }

  private createHeader(): void {
    const header = this.contentEl.createDiv({ cls: 'modal-header macros-modal-header' });
    header.createEl('h2', { text: t('meals.addTo.title'), cls: 'modal-title macros-modal-title' });
    header.createEl('p', {
      text: t('meals.addTo.description'),
      cls: 'modal-description macros-modal-description',
    });
  }

  private createSearchBar(): void {
    const searchContainer = this.contentEl.createDiv({
      cls: 'search-container macros-search-container',
    });

    const searchWrapper = searchContainer.createDiv({
      cls: 'search-wrapper macros-search-wrapper',
    });
    searchWrapper.createEl('span', { cls: 'search-icon macros-search-icon', text: '­ƒöì' });

    this.searchInput = searchWrapper.createEl('input', {
      type: 'text',
      cls: 'search-input macros-search-input',
      attr: { placeholder: t('meals.addTo.searchPlaceholder') },
    });

    // Create clear button
    this.searchClearButton = searchWrapper.createEl('button', {
      cls: 'search-clear-button macros-search-clear-button',
      attr: {
        type: 'button',
        title: t('general.clear'),
        'aria-label': t('general.clear'),
      },
    });
    this.searchClearButton.innerHTML = 'Ô£ò';

    // Initially hide the clear button
    this.searchClearButton.style.display = 'none';

    // Add search functionality
    this.component.registerDomEvent(this.searchInput, 'input', () => {
      const query = this.searchInput.value;

      // Show/hide clear button based on input content
      if (query.length > 0) {
        this.searchClearButton.style.display = 'flex';
      } else {
        this.searchClearButton.style.display = 'none';
      }

      this.filterAndRender(query);
    });

    // Add clear button functionality
    this.component.registerDomEvent(this.searchClearButton, 'click', (e: Event) => {
      e.preventDefault();
      e.stopPropagation();

      this.searchInput.value = '';
      this.searchClearButton.style.display = 'none';
      this.searchInput.focus();
      this.filterAndRender('');
    });

    // Handle keyboard navigation for clear button and existing functionality
    this.component.registerDomEvent(this.searchInput, 'keydown', (e: KeyboardEvent) => {
      // Handle Escape key to clear search
      if (e.key === 'Escape' && this.searchInput.value.length > 0) {
        e.preventDefault();
        this.searchInput.value = '';
        this.searchClearButton.style.display = 'none';
        this.filterAndRender('');
        return;
      }

      // Handle tab navigation between tabs
      if (e.ctrlKey || e.metaKey) {
        if (e.key === 'Tab') {
          e.preventDefault();
          if (e.shiftKey) {
            this.switchToPreviousTab();
          } else {
            this.switchToNextTab();
          }
        }
      }
    });
  }

  private createTabsAndContent(): void {
    const contentContainer = this.contentEl.createDiv({ cls: 'content-container' });

    // Get tab order from settings
    const tabOrder = this.plugin.settings.addToMacrosTabOrder;

    // Create perfectly centered tabs container
    const tabsContainer = contentContainer.createDiv({ cls: 'tabs-container centered-tabs' });

    // Initialize tab references
    const tabElements: { [key: string]: HTMLElement } = {};

    // Create tabs in the order specified by settings
    tabOrder.forEach((tabKey, index) => {
      const isFirst = index === 0;

      switch (tabKey) {
        case 'meals':
          tabElements.meals = this.createTab(
            tabsContainer,
            t('meals.addTo.mealTemplates'),
            isFirst
          );
          break;
        case 'foods':
          tabElements.foods = this.createTab(
            tabsContainer,
            t('meals.addTo.individualFoods'),
            isFirst
          );
          break;
        case 'group':
          tabElements.group = this.createTab(tabsContainer, t('meals.addTo.createGroup'), isFirst);
          break;
      }
    });

    // Assign tab references based on order
    this.mealsTab = tabElements.meals;
    this.foodsTab = tabElements.foods;
    this.groupTab = tabElements.group;

    // Create content areas
    const contentArea = contentContainer.createDiv({ cls: 'content-area macros-content-area' });

    // Create content containers and show the first one by default
    const firstTab = tabOrder[0];

    // Always create all containers, but only show the first one
    this.mealsContainer = contentArea.createDiv({
      cls: `items-container meals-container ${firstTab === 'meals' ? 'active' : ''}`,
    });
    this.foodsContainer = contentArea.createDiv({
      cls: `items-container foods-container ${firstTab === 'foods' ? 'active' : ''}`,
    });
    this.groupContainer = contentArea.createDiv({
      cls: `items-container group-container ${firstTab === 'group' ? 'active' : ''}`,
    });

    // Setup group creation content
    this.setupGroupCreationContent();

    // Tab switching
    this.component.registerDomEvent(this.mealsTab, 'click', () => {
      this.switchTab('meals');
    });

    this.component.registerDomEvent(this.foodsTab, 'click', () => {
      this.switchTab('foods');
    });

    this.component.registerDomEvent(this.groupTab, 'click', () => {
      this.switchTab('group');
    });

    // Add keyboard navigation for tabs
    [this.mealsTab, this.foodsTab, this.groupTab].forEach((tab, index) => {
      this.component.registerDomEvent(tab, 'keydown', (e: KeyboardEvent) => {
        this.handleTabKeyboardNavigation(e, index);
      });
    });
  }

  private createTab(container: HTMLElement, text: string, isActive: boolean): HTMLElement {
    const tab = container.createEl('button', {
      text: text,
      cls: `tab-button macros-tab-button ${isActive ? 'active' : ''}`,
    });
    return tab;
  }

  private setupGroupCreationContent(): void {
    // Group name input section
    const groupNameSection = this.groupContainer.createDiv({ cls: 'group-name-section' });

    groupNameSection.createEl('label', {
      text: t('meals.addTo.groupName'),
      cls: 'group-name-label',
    });

    this.groupNameInput = groupNameSection.createEl('input', {
      type: 'text',
      cls: 'group-name-input',
      attr: { placeholder: t('meals.addTo.groupNamePlaceholder') },
    });

    // Add validation and update functionality - re-render group foods when name changes
    this.component.registerDomEvent(this.groupNameInput, 'input', () => {
      this.renderGroupFoods(); // Re-render to update click handlers and state
      this.updateConfirmButtonState();
    });

    // Food selection for group
    const groupFoodSection = this.groupContainer.createDiv({ cls: 'group-food-section' });

    groupFoodSection.createEl('h3', {
      text: t('meals.addTo.selectFoodsForGroup'),
      cls: 'group-food-title',
    });

    this.groupFoodsContainer = groupFoodSection.createDiv({ cls: 'group-foods-container' });
  }

  private switchTab(activeTab: 'meals' | 'foods' | 'group'): void {
    // Update tab buttons
    this.mealsTab.classList.toggle('active', activeTab === 'meals');
    this.foodsTab.classList.toggle('active', activeTab === 'foods');
    this.groupTab.classList.toggle('active', activeTab === 'group');

    // Update content visibility
    this.mealsContainer.classList.toggle('active', activeTab === 'meals');
    this.foodsContainer.classList.toggle('active', activeTab === 'foods');
    this.groupContainer.classList.toggle('active', activeTab === 'group');

    // Handle search input focus and filtering
    window.setTimeout(() => {
      if (this.searchInput) {
        if (activeTab === 'group') {
          // For group tab, focus on group name input instead
          this.groupNameInput.focus();
        } else {
          this.searchInput.focus();
        }
      }
    }, 50);

    // If switching to group tab, render group foods
    if (activeTab === 'group') {
      this.renderGroupFoods();
    }
  }

  private switchToNextTab(): void {
    const tabOrder = this.plugin.settings.addToMacrosTabOrder;
    const currentActiveIndex = this.getCurrentActiveTabIndex();
    const nextIndex = (currentActiveIndex + 1) % tabOrder.length;
    const nextTab = tabOrder[nextIndex];

    this.switchTab(nextTab);
    this.getTabElement(nextTab)?.focus();
  }

  private switchToPreviousTab(): void {
    const tabOrder = this.plugin.settings.addToMacrosTabOrder;
    const currentActiveIndex = this.getCurrentActiveTabIndex();
    const prevIndex = (currentActiveIndex - 1 + tabOrder.length) % tabOrder.length;
    const prevTab = tabOrder[prevIndex];

    this.switchTab(prevTab);
    this.getTabElement(prevTab)?.focus();
  }

  private getCurrentActiveTabIndex(): number {
    if (this.mealsTab?.classList.contains('active'))
      return this.plugin.settings.addToMacrosTabOrder.indexOf('meals');
    if (this.foodsTab?.classList.contains('active'))
      return this.plugin.settings.addToMacrosTabOrder.indexOf('foods');
    if (this.groupTab?.classList.contains('active'))
      return this.plugin.settings.addToMacrosTabOrder.indexOf('group');
    return 0;
  }

  private getTabElement(tabKey: string): HTMLElement | null {
    switch (tabKey) {
      case 'meals':
        return this.mealsTab;
      case 'foods':
        return this.foodsTab;
      case 'group':
        return this.groupTab;
      default:
        return null;
    }
  }

  private handleTabKeyboardNavigation(e: KeyboardEvent, tabIndex: number): void {
    const tabOrder = this.plugin.settings.addToMacrosTabOrder;

    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      const tabKey = tabOrder[tabIndex];
      this.switchTab(tabKey);

      window.setTimeout(() => {
        if (tabKey === 'group') {
          this.groupNameInput.focus();
        } else {
          this.searchInput.focus();
        }
      }, 100);
    } else if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
      e.preventDefault();
      if (e.key === 'ArrowRight') {
        this.switchToNextTab();
      } else {
        this.switchToPreviousTab();
      }
    }
  }

  private filterAndRender(query: string): void {
    const searchTerm = query.toLowerCase().trim();

    // Filter meals
    this.filteredMeals = this.allMeals.filter(
      (meal) =>
        meal.name.toLowerCase().includes(searchTerm) ||
        meal.items.some((item) => item.toLowerCase().includes(searchTerm))
    );

    // Filter foods
    this.filteredFoods = this.allFoods.filter((food) =>
      food.name.toLowerCase().includes(searchTerm)
    );

    // Filter group foods (for group creation)
    this.filteredGroupFoods = this.allFoods.filter((food) =>
      food.name.toLowerCase().includes(searchTerm)
    );

    // Render filtered results
    this.renderMeals();
    this.renderFoods();
    this.renderGroupFoods();
  }

  private renderMeals(): void {
    this.mealsContainer.empty();

    // Create header section with action button
    const headerSection = this.mealsContainer.createDiv({ cls: 'meals-header-section' });

    const createMealButton = headerSection.createEl('button', {
      text: '+ ' + t('settings.meals.create'),
      cls: 'create-meal-template-button mod-cta',
    });

    this.component.registerDomEvent(createMealButton, 'click', () => {
      // Open the Add Meal Template Modal
      const addMealModal = new AddMealTemplateModal(this.plugin);

      // When the modal closes, refresh the meals list
      addMealModal.onClose = () => {
        // Reload meal data and re-render
        this.loadData().then(() => {
          this.filterAndRender(this.searchInput.value);
        });
      };

      addMealModal.open();
    });

    if (this.filteredMeals.length === 0) {
      this.mealsContainer.createDiv({
        cls: 'no-results macros-no-results',
        text: t('meals.create.noResults'),
      });
      return;
    }

    this.filteredMeals.forEach((meal) => {
      const mealCard = this.mealsContainer.createDiv({ cls: 'meal-card' });

      // Meal header
      const mealHeader = mealCard.createDiv({ cls: 'meal-header' });
      mealHeader.createEl('h3', { text: meal.name, cls: 'meal-name' });
      mealHeader.createEl('span', {
        text: t('table.meal.items', { count: meal.items.length.toString() }),
        cls: 'meal-count',
      });

      // Add nutrition information matching individual foods styling exactly
      const mealNutrition = this.mealNutritionData.get(meal.name);
      if (mealNutrition) {
        const nutritionInfo = mealCard.createDiv({ cls: 'nutrition-info macros-nutrition-info' });

        // Use consistent styling with individual food cards - separate spans with background colors
        const currentEnergyUnit = this.plugin.settings.energyUnit;
        const calorieSpan = nutritionInfo.createEl('span', {
          cls: 'nutrition-item macros-nutrition-item calories',
        });

        if (currentEnergyUnit === 'kJ') {
          const kjValue = convertEnergyUnit(mealNutrition.calories, 'kcal', 'kJ');
          calorieSpan.textContent = `${kjValue.toFixed(1)} kJ`;
          calorieSpan.setAttribute(
            'title',
            `${mealNutrition.calories.toFixed(1)} kcal = ${kjValue.toFixed(1)} kJ`
          );
        } else {
          calorieSpan.textContent = `${mealNutrition.calories.toFixed(1)} kcal`;
        }

        nutritionInfo.createEl('span', {
          text: `${mealNutrition.protein.toFixed(1)}g ${t('table.headers.protein').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item protein',
        });
        nutritionInfo.createEl('span', {
          text: `${mealNutrition.fat.toFixed(1)}g ${t('table.headers.fat').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item fat',
        });
        nutritionInfo.createEl('span', {
          text: `${mealNutrition.carbs.toFixed(1)}g ${t('table.headers.carbs').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item carbs',
        });

        // Serving size info to match individual foods
        const servingInfo = mealCard.createDiv({ cls: 'serving-info' });
        servingInfo.createEl('span', {
          text: `Total for meal`,
          cls: 'serving-size',
        });
      }

      // Meal items preview (moved below nutrition info)
      const itemsPreview = mealCard.createDiv({ cls: 'meal-items-preview' });
      const previewItems = meal.items.slice(0, 3);
      previewItems.forEach((item) => {
        itemsPreview.createEl('span', { text: item, cls: 'preview-item' });
      });

      if (meal.items.length > 3) {
        itemsPreview.createEl('span', {
          text: `+${meal.items.length - 3} ${t('general.more')}`,
          cls: 'preview-more',
        });
      }

      // Add button
      const addButton = mealCard.createEl('button', {
        text: t('meals.addTo.addMeal'),
        cls: 'add-button meal-add-button',
      });

      this.component.registerDomEvent(addButton, 'click', () => {
        this.addMeal(meal);
      });

      // Add selection state
      const mealValue = `interactive:meal:${meal.name}`;
      if (this.selectedItems.includes(mealValue)) {
        mealCard.addClass('selected');
        addButton.textContent = t('meals.addTo.added');
        addButton.addClass('selected');
      }
    });
  }

