  private showCommentModal(target: CommentTarget, onCommentUpdate: () => Promise<void>): void {
    const modal = new CommentModal(
      this.plugin.app,
      this.plugin,
      target.currentComment,
      target.type,
      target.name,
      async (newComment: string) => {
        await this.updateComment(target, newComment);
        await onCommentUpdate();
      }
    );

    modal.open();
  }

  private showTimestampModal(target: CommentTarget, onCommentUpdate: () => Promise<void>): void {
    const currentTimestamp = this.parseTimestampFromLine(target.macroLine);

    const modal = new TimestampModal(
      this.plugin.app,
      this.plugin,
      currentTimestamp,
      target.type,
      target.name,
      async (newTimestamp: string) => {
        await this.updateTimestamp(target, newTimestamp);
        await onCommentUpdate();
      }
    );

    modal.open();
  }

  private showToleranceModal(target: CommentTarget, onCommentUpdate: () => Promise<void>): void {
    const currentTolerance = this.getToleranceData(target.name);

    const modal = new ToleranceModal(
      this.plugin.app,
      this.plugin,
      currentTolerance,
      target.type,
      target.name,
      async (newTolerance: ToleranceData | null) => {
        await this.updateTolerance(target, newTolerance);
        await onCommentUpdate();
      }
    );

    modal.open();
  }

  private async removeComment(
    target: CommentTarget,
    onCommentUpdate: () => Promise<void>
  ): Promise<void> {
    try {
      await this.updateComment(target, '');
      await onCommentUpdate();
    } catch (error) {
      this.plugin.logger.error('Error removing comment:', error);
      throw error;
    }
  }

  private async removeTimestamp(
    target: CommentTarget,
    onCommentUpdate: () => Promise<void>
  ): Promise<void> {
    try {
      await this.updateTimestamp(target, '');
      await onCommentUpdate();
    } catch (error) {
      this.plugin.logger.error('Error removing timestamp:', error);
      throw error;
    }
  }

  private async removeTolerance(
    target: CommentTarget,
    onCommentUpdate: () => Promise<void>
  ): Promise<void> {
    try {
      await this.updateTolerance(target, null);
      await onCommentUpdate();
    } catch (error) {
      this.plugin.logger.error('Error removing tolerance:', error);
      throw error;
    }
  }

  private async updateComment(target: CommentTarget, newComment: string): Promise<void> {
    try {
      const context = await this.plugin.dataManager.getDocumentContext(target.macrosId);

      if (!context || context.allLines.length === 0) {
        throw new Error('Could not load macros data');
      }

      const updatedLines = [...context.allLines];
      let lineFound = false;

      if (target.type === 'meal') {
        for (let i = 0; i < updatedLines.length; i++) {
          const line = updatedLines[i];
          if (line.toLowerCase().startsWith('meal:') || line.toLowerCase().startsWith('group:')) {
            const prefix = line.toLowerCase().startsWith('meal:') ? 'meal:' : 'group:';
            const baseName = this.removeCommentFromLine(
              this.removeTimestampFromLine(line.substring(prefix.length).trim())
            );
            const cleanTargetName = this.removeCommentFromLine(
              this.removeTimestampFromLine(target.name)
            );

            if (baseName.toLowerCase() === cleanTargetName.toLowerCase()) {
              const newLine = this.addCommentToLine(line, newComment);
              updatedLines[i] = newLine;
              lineFound = true;
              break;
            }
          }
        }
      } else {
        for (let i = 0; i < updatedLines.length; i++) {
          const line = updatedLines[i];

          if (line.startsWith('-')) {
            const itemText = line.substring(1).trim();
            const baseFoodName = this.extractFoodName(
              this.removeCommentFromLine(this.removeTimestampFromLine(itemText))
            );
            const cleanTargetName = this.removeCommentFromLine(
              this.removeTimestampFromLine(target.name)
            );

            if (baseFoodName.toLowerCase() === cleanTargetName.toLowerCase()) {
              const newItemText = this.addCommentToLine(itemText, newComment);
              const newLine = `- ${newItemText}`;
              updatedLines[i] = newLine;
              lineFound = true;
              break;
            }
          } else if (
            !line.toLowerCase().startsWith('meal:') &&
            !line.toLowerCase().startsWith('group:') &&
            !line.toLowerCase().startsWith('id:')
          ) {
            const baseFoodName = this.extractFoodName(
              this.removeCommentFromLine(this.removeTimestampFromLine(line))
            );
            const cleanTargetName = this.removeCommentFromLine(
              this.removeTimestampFromLine(target.name)
            );

            if (baseFoodName.toLowerCase() === cleanTargetName.toLowerCase()) {
              const newLine = this.addCommentToLine(line, newComment);
              updatedLines[i] = newLine;
              lineFound = true;
              break;
            }
          }
        }
      }

      if (!lineFound) {
        throw new Error(`Could not find ${target.type} "${target.name}" in macros block`);
      }

      const success = await this.plugin.dataManager.updateMacrosBlock(
        target.macrosId,
        updatedLines
      );

      if (!success) {
        throw new Error('Failed to update macros block');
      }
    } catch (error) {
      this.plugin.logger.error('Error updating comment:', error);
      throw error;
    }
  }

  private async updateTimestamp(target: CommentTarget, newTimestamp: string): Promise<void> {
    try {
      const context = await this.plugin.dataManager.getDocumentContext(target.macrosId);

      if (!context || context.allLines.length === 0) {
        throw new Error('Could not load macros data');
      }

      const updatedLines = [...context.allLines];
      let lineFound = false;

      if (target.type === 'meal') {
        for (let i = 0; i < updatedLines.length; i++) {
          const line = updatedLines[i];
          if (line.toLowerCase().startsWith('meal:') || line.toLowerCase().startsWith('group:')) {
            const prefix = line.toLowerCase().startsWith('meal:') ? 'meal:' : 'group:';
            const baseName = this.removeCommentFromLine(
              this.removeTimestampFromLine(line.substring(prefix.length).trim())
            );
            const cleanTargetName = this.removeCommentFromLine(
              this.removeTimestampFromLine(target.name)
            );

            if (baseName.toLowerCase() === cleanTargetName.toLowerCase()) {
              const newLine = this.addTimestampToLine(line, newTimestamp);
              updatedLines[i] = newLine;
              lineFound = true;
              break;
            }
          }
        }
      } else {
        for (let i = 0; i < updatedLines.length; i++) {
          const line = updatedLines[i];

          if (line.startsWith('-')) {
            const itemText = line.substring(1).trim();
            const baseFoodName = this.extractFoodName(
              this.removeCommentFromLine(this.removeTimestampFromLine(itemText))
            );
            const cleanTargetName = this.removeCommentFromLine(
              this.removeTimestampFromLine(target.name)
            );

            if (baseFoodName.toLowerCase() === cleanTargetName.toLowerCase()) {
              const newItemText = this.addTimestampToLine(itemText, newTimestamp);
              const newLine = `- ${newItemText}`;
              updatedLines[i] = newLine;
              lineFound = true;
              break;
            }
          } else if (
            !line.toLowerCase().startsWith('meal:') &&
            !line.toLowerCase().startsWith('group:') &&
            !line.toLowerCase().startsWith('id:')
          ) {
            const baseFoodName = this.extractFoodName(
              this.removeCommentFromLine(this.removeTimestampFromLine(line))
            );
            const cleanTargetName = this.removeCommentFromLine(
              this.removeTimestampFromLine(target.name)
            );

            if (baseFoodName.toLowerCase() === cleanTargetName.toLowerCase()) {
              const newLine = this.addTimestampToLine(line, newTimestamp);
              updatedLines[i] = newLine;
              lineFound = true;
              break;
            }
          }
        }
      }

      if (!lineFound) {
        throw new Error(`Could not find ${target.type} "${target.name}" in macros block`);
      }

      const success = await this.plugin.dataManager.updateMacrosBlock(
        target.macrosId,
        updatedLines
      );

      if (!success) {
        throw new Error('Failed to update macros block');
      }
    } catch (error) {
      this.plugin.logger.error('Error updating timestamp:', error);
      throw error;
    }
  }

  private async updateTolerance(
    target: CommentTarget,
    newTolerance: ToleranceData | null
  ): Promise<void> {
    try {
      if (!this.plugin.settings.foodTolerances) {
        this.plugin.settings.foodTolerances = {};
      }

      const foodKey = target.name.toLowerCase();

      if (newTolerance === null) {
        delete this.plugin.settings.foodTolerances[foodKey];
      } else {
        this.plugin.settings.foodTolerances[foodKey] = newTolerance;
      }

      await this.plugin.saveSettings();
    } catch (error) {
      this.plugin.logger.error('Error updating tolerance:', error);
      throw error;
    }
  }

  private extractFoodName(line: string): string {
    if (line.includes(':')) {
      return line.split(':')[0].trim();
    }
    return line.trim();
  }

  createCommentTarget(
    element: HTMLElement,
    macrosId: string,
    type: 'meal' | 'food-item'
  ): CommentTarget | null {
    try {
      if (type === 'meal') {
        const headerLabel = element.querySelector('.header-label');
        if (!headerLabel) return null;

        const mealName = headerLabel.textContent?.trim() || '';
        const macroLine = element.dataset.macroLine || '';
        const currentComment = this.parseCommentFromLine(macroLine);

        return {
          type: 'meal',
          name: mealName,
          macroLine,
          macrosId,
          currentComment,
        };
      } else {
        const foodName = element.dataset.foodName || '';
        const macroLine = element.dataset.macroLine || '';
        const currentComment = this.parseCommentFromLine(macroLine);

        return {
          type: 'food-item',
          name: foodName,
          macroLine,
          macrosId,
          currentComment,
        };
      }
    } catch (error) {
      this.plugin.logger.error('Error creating comment target:', error);
      return null;
    }
  }
}

import { App, Modal, Notice, Component } from 'obsidian';
import MacrosPlugin from '../../main';
import { t } from '../../lang/I18nManager';

export class CustomServingSizeModal extends Modal {
  foodName: string;
  defaultServing: number;
  onSubmit: (customServing: number) => void;
  private component: Component;
  private plugin?: MacrosPlugin;

  constructor(
    app: App,
    foodName: string,
    defaultServing: number,
    onSubmit: (customServing: number) => void,
    plugin?: MacrosPlugin
  ) {
    super(app);
    this.foodName = foodName;
    this.defaultServing = defaultServing;
    this.onSubmit = onSubmit;
    this.component = new Component();
    this.plugin = plugin;
  }

  onOpen() {
    const { contentEl } = this;

    // Add mobile-friendly class to the modal
    contentEl.addClass('custom-serving-modal');

    // Create header element directly without storing in unused variable
    contentEl.createEl('h2', {
      text: t('food.customServing.title', { foodName: this.foodName }),
      cls: 'custom-serving-modal-title',
    });

    // Try to get the default serving size from the food file if plugin is available
    let suggestedServing = this.defaultServing;
    let isUsingCustomDefault = false;

    if (this.plugin) {
      const foodFile = this.plugin.dataManager.findFoodFile(this.foodName);
      if (foodFile) {
        const cache = this.plugin.app.metadataCache.getFileCache(foodFile);
        if (cache?.frontmatter) {
          const defaultServingSize: unknown = cache.frontmatter['default_serving_size'];
          if (defaultServingSize) {
            // Parse the default serving size (remove 'g' suffix if present)
            const parsedDefaultServing = parseFloat(
              String(defaultServingSize).replace(/g$/i, '')
            );
            if (!isNaN(parsedDefaultServing) && parsedDefaultServing > 0) {
              suggestedServing = parsedDefaultServing;
              isUsingCustomDefault = true;
            }
          }
        }
      }
    }

    // Create description with information about the serving size
    let descriptionText = t('food.customServing.description', {
      defaultServing: this.defaultServing.toString(),
    });

    if (isUsingCustomDefault && suggestedServing !== this.defaultServing) {
      descriptionText = `Using your custom default serving size: ${suggestedServing}g (original: ${this.defaultServing}g)`;
    }

    contentEl.createEl('p', {
      text: descriptionText,
      cls: 'custom-serving-modal-description',
    });

    // Create input container for better mobile layout
    const inputContainer = contentEl.createDiv({ cls: 'custom-serving-input-container' });

    const inputEl = inputContainer.createEl('input', {
      type: 'number',
      cls: 'custom-serving-input',
    });
    inputEl.placeholder = `${suggestedServing}`;
    inputEl.value = `${suggestedServing}`;

    const handleSubmit = () => {
      const value = parseFloat(inputEl.value);
      if (isNaN(value) || value <= 0) {
        new Notice(t('validation.invalidServing'));
      } else {
        this.onSubmit(value);
        this.close();
      }
    };

    this.component.registerDomEvent(inputEl, 'keydown', (event: KeyboardEvent) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        handleSubmit();
      } else if (event.key === 'Escape') {
        this.close();
      }
    });

    // Create button container for better mobile layout
    const buttonContainer = contentEl.createDiv({ cls: 'custom-serving-button-container' });

    const submitBtn = buttonContainer.createEl('button', {
      text: t('food.customServing.submit'),
      cls: 'custom-serving-submit-btn mod-cta',
    });

    this.component.registerDomEvent(submitBtn, 'click', handleSubmit);

    // If using custom default, add a reset button
    if (isUsingCustomDefault && suggestedServing !== this.defaultServing) {
      const resetBtn = buttonContainer.createEl('button', {
        text: `Reset to Original (${this.defaultServing}g)`,
        cls: 'custom-serving-reset-btn mod-button',
      });

      this.component.registerDomEvent(resetBtn, 'click', () => {
        inputEl.value = this.defaultServing.toString();
        inputEl.focus();
        inputEl.select();
      });
    }

    // Focus input after a small delay to ensure proper rendering
    window.setTimeout(() => {
      inputEl.focus();
      inputEl.select();
    }, 100);
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { Modal, Notice, normalizePath, Component } from 'obsidian';
import { parseGrams, processNutritionalData } from '../../utils';
import { MealTemplate } from '../../settings/StorageService';
import MacrosPlugin from '../../main';
import { CustomServingSizeModal } from './CustomServingSizeModal';
import { t } from '../../lang/I18nManager';
import { convertEnergyUnit } from '../../utils/energyUtils';

interface FoodItemData {
  name: string;
  file: import('obsidian').TFile;
  nutrition?: {
    calories: number;
    protein: number;
    fat: number;
    carbs: number;
    serving: string;
  };
  isSelected: boolean;
  customServing?: number;
}

export class EditMealTemplateModal extends Modal {
  plugin: MacrosPlugin;
  meal: MealTemplate;
  private component: Component;

  // UI elements
  private searchInput: HTMLInputElement;
  private foodsContainer: HTMLElement;
  private selectedItemsContainer: HTMLElement;
  private saveButton: HTMLElement;

  // Data
  private allFoods: FoodItemData[] = [];
  private filteredFoods: FoodItemData[] = [];

  constructor(plugin: MacrosPlugin, meal: MealTemplate) {
    super(plugin.app);
    this.plugin = plugin;
    this.meal = meal;
    this.component = new Component();
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.addClass('enhanced-meal-template-modal');

    // Load and prepare data
    await this.loadData();

    // Create the interface
    this.createHeader();
    this.createSearchBar();
    this.createFoodsSection();
    this.createSelectedItemsSection();
    this.createActionButtons();

    // Initial render
    this.filterAndRender('');
    this.updateSelectedItemsDisplay();
  }

  private async loadData(): Promise<void> {
    // Load all food items
    const folder = normalizePath(this.plugin.settings.storageFolder);
    const fileList = this.app.vault.getFiles().filter((f) => f.path.startsWith(folder));

    this.allFoods = await Promise.all(
      fileList.map(async (file): Promise<FoodItemData> => {
        const name = file.name.replace(/\.md$/, '');
        const nutrition = processNutritionalData(this.app, file);

        // Check if this food is already in the meal template
        const existingItem = this.meal.items.find((item) => {
          const itemName = item.includes(':') ? item.split(':')[0].trim() : item.trim();
          return itemName.toLowerCase() === name.toLowerCase();
        });

        let customServing: number | undefined;
        if (existingItem && existingItem.includes(':')) {
          customServing = parseGrams(existingItem.split(':')[1]);
        }

        return {
          name,
          file,
          nutrition: nutrition
            ? {
                calories: nutrition.calories,
                protein: nutrition.protein,
                fat: nutrition.fat,
                carbs: nutrition.carbs,
                serving: nutrition.serving || '100g',
              }
            : undefined,
          isSelected: !!existingItem,
          customServing,
        };
      })
    );

    // Sort foods alphabetically
    this.allFoods.sort((a, b) =>
      a.name.localeCompare(b.name, 'en-US', {
        sensitivity: 'base',
        numeric: true,
        ignorePunctuation: true,
      })
    );
  }

  private createHeader(): void {
    const header = this.contentEl.createDiv({ cls: 'modal-header macros-modal-header' });
    header.createEl('h2', {
      text: t('meals.edit.title', { mealName: this.meal.name }),
      cls: 'modal-title macros-modal-title',
    });
    header.createEl('p', {
      text: t('meals.edit.description'),
      cls: 'modal-description macros-modal-description',
    });
  }

  private createSearchBar(): void {
    const searchContainer = this.contentEl.createDiv({
      cls: 'search-container macros-search-container',
    });

    const searchWrapper = searchContainer.createDiv({
      cls: 'search-wrapper macros-search-wrapper',
    });
    searchWrapper.createEl('span', { cls: 'search-icon macros-search-icon', text: '­ƒöì' });

    this.searchInput = searchWrapper.createEl('input', {
      type: 'text',
      cls: 'search-input macros-search-input',
      attr: { placeholder: t('meals.create.searchPlaceholder') },
    });

    // Add search functionality
    this.component.registerDomEvent(this.searchInput, 'input', () => {
      const query = this.searchInput.value;
      this.filterAndRender(query);
    });
  }

  private createFoodsSection(): void {
    const sectionContainer = this.contentEl.createDiv({ cls: 'foods-section' });

    const sectionHeader = sectionContainer.createDiv({ cls: 'section-header' });
    sectionHeader.createEl('h3', { text: t('meals.create.availableFoods'), cls: 'section-title' });

    this.foodsContainer = sectionContainer.createDiv({ cls: 'foods-container' });
  }

  private filterAndRender(query: string): void {
    const searchTerm = query.toLowerCase().trim();

    // Filter foods
    this.filteredFoods = this.allFoods.filter((food) =>
      food.name.toLowerCase().includes(searchTerm)
    );

    // Render filtered results
    this.renderFoods();
  }

  private renderFoods(): void {
    this.foodsContainer.empty();

    if (this.filteredFoods.length === 0) {
      this.foodsContainer.createDiv({
        cls: 'no-results macros-no-results',
        text: t('meals.create.noResults'),
      });
      return;
    }

    this.filteredFoods.forEach((food) => {
      const foodCard = this.foodsContainer.createDiv({ cls: 'food-card' });

      // Food name
      const foodHeader = foodCard.createDiv({ cls: 'food-header' });
      foodHeader.createEl('h3', { text: food.name, cls: 'food-name' });

      // Enhanced nutrition info with kJ support
      if (food.nutrition) {
        const nutritionInfo = foodCard.createDiv({ cls: 'nutrition-info macros-nutrition-info' });

        // Enhanced calorie display with kJ support
        const currentEnergyUnit = this.plugin.settings.energyUnit;
        const calorieSpan = nutritionInfo.createEl('span', {
          cls: 'nutrition-item macros-nutrition-item calories',
        });

        if (currentEnergyUnit === 'kJ') {
          const kjValue = convertEnergyUnit(food.nutrition.calories, 'kcal', 'kJ');
          calorieSpan.textContent = `${kjValue.toFixed(1)} kJ`;
          // Add tooltip showing both units
          calorieSpan.setAttribute(
            'title',
            `${food.nutrition.calories.toFixed(1)} kcal = ${kjValue.toFixed(1)} kJ`
          );
        } else {
          calorieSpan.textContent = `${food.nutrition.calories.toFixed(1)} kcal`;
        }

        nutritionInfo.createEl('span', {
          text: `${food.nutrition.protein.toFixed(1)}g ${t('table.headers.protein').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item protein',
        });
        nutritionInfo.createEl('span', {
          text: `${food.nutrition.fat.toFixed(1)}g ${t('table.headers.fat').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item fat',
        });
        nutritionInfo.createEl('span', {
          text: `${food.nutrition.carbs.toFixed(1)}g ${t('table.headers.carbs').toLowerCase()}`,
          cls: 'nutrition-item macros-nutrition-item carbs',
        });

        // Serving size
        const servingInfo = foodCard.createDiv({ cls: 'serving-info' });
        const servingText = food.customServing
          ? t('meals.create.customServing', { serving: food.customServing.toString() })
          : t('meals.create.defaultServing', { serving: food.nutrition.serving });
        servingInfo.createEl('span', {
          text: servingText,
          cls: 'serving-size',
        });
      }

      // Action buttons container
      const buttonContainer = foodCard.createDiv({
        cls: 'button-container macros-button-container',
      });

      if (food.isSelected) {
        // Remove button
        const removeButton = buttonContainer.createEl('button', {
          text: t('meals.create.remove'),
          cls: 'remove-button',
          attr: { type: 'button' },
        });

        // Edit serving button (if nutrition data available)
        if (food.nutrition) {
          const editButton = buttonContainer.createEl('button', {
            text: t('meals.create.editServing'),
            cls: 'edit-button',
            attr: { type: 'button' },
        });

          this.component.registerDomEvent(editButton, 'click', () => {
            this.editFoodServing(food);
          });
        }

        this.component.registerDomEvent(removeButton, 'click', () => {
          this.removeFood(food);
        });

        foodCard.addClass('selected');
      } else {
        // Add button
        const addButton = buttonContainer.createEl('button', {
          text: t('meals.create.addToMeal'),
          cls: 'add-button',
          attr: { type: 'button' },
        });

        this.component.registerDomEvent(addButton, 'click', () => {
          this.addFood(food);
        });
      }
    });
  }

  private async addFood(food: FoodItemData): Promise<void> {
    if (!food.nutrition) {
      new Notice(t('validation.noNutritionData'));
      return;
    }

    const defaultServing = parseGrams(food.nutrition.serving);

    new CustomServingSizeModal(
      this.app,
      food.name,
      defaultServing,
      async (customServing: number) => {
        // Update the food item
        food.isSelected = true;
        food.customServing = customServing;

        // Add to meal template
        const itemString = `${food.name}:${customServing}g`;
        this.meal.items.push(itemString);

        await this.plugin.saveSettings();
        this.updateUI();

        new Notice(t('notifications.itemsAdded', { count: '1' }));
      },
      this.plugin
    ).open();
  }

  private async removeFood(food: FoodItemData): Promise<void> {
    // Update the food item
    food.isSelected = false;
    food.customServing = undefined;

    // Remove from meal template
    this.meal.items = this.meal.items.filter((item) => {
      const itemName = item.includes(':') ? item.split(':')[0].trim() : item.trim();
      return itemName.toLowerCase() !== food.name.toLowerCase();
    });

    await this.plugin.saveSettings();
    this.updateUI();

    new Notice(`${t('general.remove')} ${food.name}`);
  }

  private async editFoodServing(food: FoodItemData): Promise<void> {
    if (!food.nutrition || !food.customServing) return;

    new CustomServingSizeModal(
      this.app,
      food.name,
      food.customServing,
      async (newServing: number) => {
        // Update the food item
        food.customServing = newServing;

        // Update meal template
        const itemIndex = this.meal.items.findIndex((item) => {
          const itemName = item.includes(':') ? item.split(':')[0].trim() : item.trim();
          return itemName.toLowerCase() === food.name.toLowerCase();
        });

        if (itemIndex !== -1) {
          this.meal.items[itemIndex] = `${food.name}:${newServing}g`;
        }

        await this.plugin.saveSettings();
        this.updateUI();

        new Notice(t('general.success'));
      },
      this.plugin
    ).open();
  }

  private updateUI(): void {
    this.renderFoods();
    this.updateSelectedItemsDisplay();
  }

  private createSelectedItemsSection(): void {
    const selectedSection = this.contentEl.createDiv({ cls: 'selected-items-section' });

    const header = selectedSection.createDiv({ cls: 'selected-header' });
    header.createEl('h3', { text: t('meals.create.selectedItems'), cls: 'selected-title' });

    this.selectedItemsContainer = selectedSection.createDiv({ cls: 'selected-items-container' });
  }

  private updateSelectedItemsDisplay(): void {
    this.selectedItemsContainer.empty();

    const selectedFoods = this.allFoods.filter((food) => food.isSelected);

    if (selectedFoods.length === 0) {
      this.selectedItemsContainer.createDiv({
        cls: 'no-selected-items',
        text: t('meals.create.noSelectedItems'),
      });
    } else {
      selectedFoods.forEach((food) => {
        const itemTag = this.selectedItemsContainer.createDiv({ cls: 'selected-item-tag' });

        const displayText = food.customServing ? `${food.name}:${food.customServing}g` : food.name;

        itemTag.createEl('span', { text: displayText, cls: 'item-text' });

        const removeButton = itemTag.createEl('button', {
          text: '├ù',
          cls: 'remove-item-button',
          attr: { type: 'button' },
        });

        this.component.registerDomEvent(removeButton, 'click', () => {
          this.removeFood(food);
        });
      });
    }

    // Update save button state
    if (this.saveButton) {
      const hasItems = selectedFoods.length > 0;
      if (hasItems) {
        this.saveButton.removeClass('disabled');
        (this.saveButton as HTMLButtonElement).disabled = false;
      } else {
        this.saveButton.addClass('disabled');
        (this.saveButton as HTMLButtonElement).disabled = true;
      }
    }
  }

  private createActionButtons(): void {
    const buttonContainer = this.contentEl.createDiv({
      cls: 'action-buttons macros-action-buttons',
    });

    const cancelButton = buttonContainer.createEl('button', {
      text: t('general.cancel'),
      cls: 'cancel-button',
      attr: { type: 'button' },
        });

    this.saveButton = buttonContainer.createEl('button', {
      text: t('meals.edit.saveChanges'),
      cls: 'save-button',
      attr: { type: 'button' },
        });

    this.component.registerDomEvent(cancelButton, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(this.saveButton, 'click', async () => {
      await this.plugin.saveSettings();
      new Notice(t('notifications.mealTemplateUpdated', { name: this.meal.name }));
      this.close();

      // Refresh the settings display
      this.plugin.nutritionalSettingTab.display();
    });
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { App, Modal, Component } from 'obsidian';
import MacrosPlugin from '../../main';
import { LiveFoodSearchModal } from '../live-search/LiveSearchModal';
import { ManualFoodEntryModal } from './ManualFoodEntryModal';
import { UnifiedFoodResult } from '../../core/search';
import { t } from '../../lang/I18nManager';

/**
 * Modal that presents the user with options to either use live search
 * (FatSecret, USDA, and/or Open Food Facts) or manually enter food data
 */
export class FoodEntrySelectionModal extends Modal {
  private plugin: MacrosPlugin;
  private onFoodSelected: (item: UnifiedFoodResult | import('../../core/api').FoodItem) => void;
  private component: Component;

  constructor(
    app: App,
    plugin: MacrosPlugin,
    onFoodSelected: (item: UnifiedFoodResult | import('../../core/api').FoodItem) => void
  ) {
    super(app);
    this.plugin = plugin;
    this.onFoodSelected = onFoodSelected;
    this.component = new Component();
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.addClass('food-entry-selection-modal');

    // Create header
    contentEl.createEl('h2', {
      text: t('food.entry.title'),
      cls: 'modal-title macros-modal-title',
    });

    contentEl.createEl('p', {
      text: t('food.entry.description'),
      cls: 'modal-description macros-modal-description',
    });

    // Create button container
    const buttonContainer = contentEl.createDiv({ cls: 'food-entry-options' });

    // Live Search Option
    const liveSearchOption = buttonContainer.createDiv({
      cls: 'food-entry-option live-search-option',
    });

    const liveSearchIcon = liveSearchOption.createDiv({ cls: 'option-icon' });
    liveSearchIcon.innerHTML = '­ƒöì'; // Search icon

    const liveSearchContent = liveSearchOption.createDiv({ cls: 'option-content' });
    liveSearchContent.createEl('h3', { text: t('food.entry.liveSearch') });
    liveSearchContent.createEl('p', {
      text: t('food.entry.liveSearchDesc'),
    });

    const liveSearchFooter = liveSearchOption.createDiv({ cls: 'option-footer' });

    // Check available data sources
    const availableSources = this.getAvailableDataSources();
    const sourceNames = availableSources.map((source) => source.name);

    // Always show as available since Open Food Facts is always available
    liveSearchFooter.createEl('span', {
      text: `Ô£à ${sourceNames.join(' + ')} available`,
      cls: 'status-indicator macros-status-indicator status-success',
    });

    // Manual Entry Option
    const manualEntryOption = buttonContainer.createDiv({
      cls: 'food-entry-option manual-entry-option',
    });

    const manualEntryIcon = manualEntryOption.createDiv({ cls: 'option-icon' });
    manualEntryIcon.innerHTML = 'Ô£Å´©Å'; // Edit icon

    const manualEntryContent = manualEntryOption.createDiv({ cls: 'option-content' });
    manualEntryContent.createEl('h3', { text: t('food.entry.manualEntry') });
    manualEntryContent.createEl('p', {
      text: t('food.entry.manualEntryDesc'),
    });

    const manualEntryFooter = manualEntryOption.createDiv({ cls: 'option-footer' });
    manualEntryFooter.createEl('span', {
      text: t('food.entry.alwaysAvailable'),
      cls: 'status-indicator macros-status-indicator status-success',
    });

    // Add click handlers
    this.component.registerDomEvent(liveSearchOption, 'click', () => {
      this.handleLiveSearchClick();
    });

    this.component.registerDomEvent(manualEntryOption, 'click', () => {
      this.handleManualEntryClick();
    });

    // Add hover effects
    this.component.registerDomEvent(liveSearchOption, 'mouseenter', () => {
      liveSearchOption.addClass('option-hover');
    });

    this.component.registerDomEvent(liveSearchOption, 'mouseleave', () => {
      liveSearchOption.removeClass('option-hover');
    });

    this.component.registerDomEvent(manualEntryOption, 'mouseenter', () => {
      manualEntryOption.addClass('option-hover');
    });

    this.component.registerDomEvent(manualEntryOption, 'mouseleave', () => {
      manualEntryOption.removeClass('option-hover');
    });

    // Focus on live search by default since it's always available now
    liveSearchOption.focus();
  }

  /**
   * Get available data sources for display
   */
  private getAvailableDataSources(): Array<{ name: string; enabled: boolean }> {
    const sources = [];

    // Open Food Facts is always available (no credentials needed)
    if (this.plugin.settings.openFoodFactsEnabled !== false) {
      sources.push({ name: 'Open Food Facts', enabled: true });
    }

    // FatSecret (requires credentials)
    const hasFatSecret =
      this.plugin.settings.fatSecretEnabled &&
      this.plugin.settings.fatSecretApiKey &&
      this.plugin.settings.fatSecretApiSecret;
    if (hasFatSecret) {
      sources.push({ name: 'FatSecret', enabled: true });
    }

    // USDA (requires API key)
    const hasUsda = this.plugin.settings.usdaEnabled && this.plugin.settings.usdaApiKey;
    if (hasUsda) {
      sources.push({ name: 'USDA', enabled: true });
    }

    // If no sources are configured (shouldn't happen since OFF is default),
    // still show Open Food Facts as available
    if (sources.length === 0) {
      sources.push({ name: 'Open Food Facts', enabled: true });
    }

    return sources;
  }

  private handleLiveSearchClick(): void {
    try {
      // Since Open Food Facts is always available, we can always proceed
      // Close this modal and open live search
      this.close();

      // The LiveFoodSearchModal handles multiple APIs internally
      // We pass the legacy parameters for backward compatibility, but the modal
      // will use the plugin settings to determine which APIs to use
      const fallbackKey = this.plugin.settings.fatSecretApiKey || '';
      const fallbackSecret = this.plugin.settings.fatSecretApiSecret || '';

      new LiveFoodSearchModal(
        this.app,
        fallbackKey,
        fallbackSecret,
        this.onFoodSelected,
        this.plugin
      ).open();
    } catch (error) {
      this.plugin.logger.error('Error opening live search:', error);

      const errorEl = this.contentEl.createDiv({
        cls: 'api-error-message macros-api-error-message',
        text: t('errors.apiConnectionFailed'),
      });

      window.setTimeout(() => {
        if (errorEl.parentNode) {
          errorEl.parentNode.removeChild(errorEl);
        }
      }, 5000);
    }
  }

  private handleManualEntryClick(): void {
    // Close this modal and open manual entry
    this.close();

    new ManualFoodEntryModal(this.app, this.plugin, this.onFoodSelected).open();
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { App, Modal, Component } from 'obsidian';
import { extractServingSize } from '../../utils/nutritionUtils';
import { fetchFoodData, FoodItem } from '../../core/api';
import MacrosPlugin from '../../main';
import { t } from '../../lang/I18nManager';

export class FoodResultsModal extends Modal {
  currentPage = 0;
  maxResults = 25;
  results: FoodItem[] = [];
  selectedIndex = -1;
  private component: Component;
  private plugin: MacrosPlugin;

  constructor(
    public app: App,
    public searchTerm: string,
    public apiKey: string,
    public apiSecret: string,
    public onSelect: (item: FoodItem) => void,
    plugin?: MacrosPlugin
  ) {
    super(app);
    this.plugin = plugin;
    this.component = new Component();
  }

  async loadPage(page: number) {
    this.currentPage = page;
    this.results = await fetchFoodData(
      this.app,
      this.searchTerm,
      page,
      this.maxResults,
      this.apiKey,
      this.apiSecret
    );
    this.renderContent();
  }

  onOpen() {
    this.loadPage(0);

    // Add document-level event handling - register with component for cleanup
    this.component.registerDomEvent(activeDocument, 'keydown', this.handleKeyNav);
  }

  onClose() {
    // Component cleanup will handle the document event listener
    this.component.unload();
    this.contentEl.empty();
  }

  handleKeyNav = (event: KeyboardEvent) => {
    if (this.results.length === 0) return;

    if (event.key === 'ArrowDown') {
      this.selectedIndex = (this.selectedIndex + 1) % this.results.length;
      this.renderContent();
      event.preventDefault();
    } else if (event.key === 'ArrowUp') {
      this.selectedIndex = (this.selectedIndex - 1 + this.results.length) % this.results.length;
      this.renderContent();
      event.preventDefault();
    } else if (event.key === 'Enter' && this.selectedIndex >= 0) {
      this.onSelect(this.results[this.selectedIndex]);
      this.close();
    }
  };

  // Helper function to safely escape regex special characters
  escapeRegExp(string: string): string {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  renderContent() {
    const { contentEl } = this;
    contentEl.empty();

    // Create dynamic header with page information
    contentEl.createEl('h2', {
      text: t('food.search.results', {
        searchTerm: this.searchTerm,
        page: (this.currentPage + 1).toString(),
      }),
    });

    if (this.results.length === 0) {
      contentEl.createEl('p', { text: t('food.search.noResults') });
    } else {
      const normalizedQuery = this.searchTerm.toLowerCase();
      const escapedSearchTerm = this.escapeRegExp(this.searchTerm);

      this.results
        .filter((food) => food.food_name.toLowerCase().includes(normalizedQuery))
        .forEach((food, index) => {
          const foodDiv = contentEl.createDiv({ cls: 'food-result-item' });

          // Split the food name by the search term for highlighting
          const regex = new RegExp(`(${escapedSearchTerm})`, 'gi');
          const parts = food.food_name.split(regex);

          parts.forEach((part) => {
            if (part.toLowerCase() === this.searchTerm.toLowerCase()) {
              foodDiv.createEl('strong', { text: part });
            } else if (part) {
              foodDiv.createSpan({ text: part });
            }
          });

          // Add the serving size
          const servingSize = extractServingSize(food.food_description);
          const servingSpan = foodDiv.createSpan();
          servingSpan.textContent = ` - ${servingSize}`;

          if (index === this.selectedIndex) {
            foodDiv.addClass('highlighted-result');
          }

          this.component.registerDomEvent(foodDiv, 'click', () => {
            this.onSelect(food);
            this.close();
          });
        });
    }

    const navDiv = contentEl.createDiv({ cls: 'food-nav' });

    if (this.currentPage > 0) {
      const prevBtn = navDiv.createEl('button', { text: `< ${t('general.previous')}` });
      prevBtn.addClass('mod-button');

      this.component.registerDomEvent(prevBtn, 'click', () => this.loadPage(this.currentPage - 1));
    }

    navDiv.createEl('span', { text: ` ${t('general.page')} ${this.currentPage + 1} ` });

    if (this.results.length === this.maxResults) {
      const nextBtn = navDiv.createEl('button', { text: `${t('general.next')} >` });
      nextBtn.addClass('mod-button');

      this.component.registerDomEvent(nextBtn, 'click', () => this.loadPage(this.currentPage + 1));
    }
  }
}

