  private updateStatusSection(): void {
    // Update the header count
    const header = this.statusContainer.querySelector('.added-items-title');
    if (header) {
      header.textContent = `${t('food.manual.addedItems')} (${this.addedItems.length})`;
    }

    // Show/hide status section based on items
    if (this.addedItems.length > 0) {
      this.statusContainer.style.display = 'block';
      this.updateAddedItemsDisplay();
    } else {
      this.statusContainer.style.display = 'none';
    }
  }

  /**
   * Build the optional, collapsible micronutrient entry section.
   * Users pick a micronutrient from the dropdown and add an input field for it.
   */
  private createMicronutrientSection(formContainer: HTMLElement): void {
    const section = formContainer.createDiv({ cls: 'micronutrient-entry-section' });

    // Collapsible header
    const header = section.createDiv({ cls: 'micronutrient-entry-header' });
    const toggleIcon = header.createSpan({ cls: 'micronutrient-entry-toggle', text: 'ÔûÂ' });
    header.createSpan({
      cls: 'micronutrient-entry-title',
      text: t('food.manual.micronutrients.title'),
    });

    const body = section.createDiv({ cls: 'micronutrient-entry-body' });
    body.style.display = 'none';

    let expanded = false;
    const toggle = () => {
      expanded = !expanded;
      body.style.display = expanded ? 'block' : 'none';
      toggleIcon.textContent = expanded ? 'Ôû╝' : 'ÔûÂ';
    };
    this.component.registerDomEvent(header, 'click', toggle);

    body.createEl('p', {
      text: t('food.manual.micronutrients.description'),
      cls: 'form-description-text',
    });

    // Picker row: dropdown + add button
    const pickerRow = body.createDiv({ cls: 'micronutrient-picker-row' });

    this.microSelect = pickerRow.createEl('select', {
      cls: 'form-input macros-form-input micronutrient-select',
    });

    const addBtn = pickerRow.createEl('button', {
      text: t('food.manual.micronutrients.addField'),
      cls: 'mod-button micronutrient-add-btn',
    });

    this.refreshMicronutrientDropdown();

    this.component.registerDomEvent(addBtn, 'click', () => {
      const key = this.microSelect.value;
      if (key) {
        this.addMicronutrientField(key);
      }
    });

    // Container for added micronutrient fields
    this.microFieldsContainer = body.createDiv({ cls: 'micronutrient-fields-container' });
  }

  /**
   * Rebuild the dropdown options to exclude already-added micronutrients,
   * grouped by category.
   */
  private refreshMicronutrientDropdown(): void {
    if (!this.microSelect) return;
    this.microSelect.empty();

    const available = MICRONUTRIENTS.filter((def) => !this.micronutrientInputs.has(def.key));

    if (available.length === 0) {
      const opt = this.microSelect.createEl('option', {
        text: t('food.manual.micronutrients.allAdded'),
        value: '',
      });
      opt.disabled = true;
      this.microSelect.disabled = true;
      return;
    }

    this.microSelect.disabled = false;

    const categories: { id: MicronutrientCategory; labelKey: string }[] = [
      { id: 'vitamin', labelKey: 'settings.micronutrients.categoryVitamins' },
      { id: 'mineral', labelKey: 'settings.micronutrients.categoryMinerals' },
      { id: 'other', labelKey: 'settings.micronutrients.categoryOther' },
    ];

    for (const category of categories) {
      const defs = available.filter((d) => d.category === category.id);
      if (defs.length === 0) continue;

      const optgroup = this.microSelect.createEl('optgroup');
      optgroup.label = t(category.labelKey);

      for (const def of defs) {
        const opt = optgroup.createEl('option', {
          text: `${def.label} (${def.unit})`,
          value: def.key,
        });
        // Some Obsidian/Electron versions need explicit value assignment
        opt.value = def.key;
      }
    }
  }

  /**
   * Add an input row for the given micronutrient key.
   */
  private addMicronutrientField(key: string): void {
    if (this.micronutrientInputs.has(key)) return;
    const def = MICRONUTRIENTS.find((d) => d.key === key);
    if (!def) return;

    const row = this.microFieldsContainer.createDiv({
      cls: 'form-group macros-form-group micronutrient-field-row',
    });
    row.dataset.microKey = key;

    row.createEl('label', {
      text: `${def.label} (${def.unit})`,
      cls: 'form-label macros-form-label',
    });

    const inputWrapper = row.createDiv({ cls: 'micronutrient-input-wrapper' });

    const input = inputWrapper.createEl('input', {
      type: 'number',
      cls: 'form-input macros-form-input',
      attr: {
        placeholder: '0',
        min: '0',
        step: '0.01',
      },
    });

    const removeBtn = inputWrapper.createEl('button', {
      text: '├ù',
      cls: 'remove-item-btn micronutrient-remove-btn',
      attr: { title: t('general.remove') },
    });

    this.component.registerDomEvent(removeBtn, 'click', () => {
      this.removeMicronutrientField(key);
    });

    // Support Enter-to-save like the other inputs
    this.component.registerDomEvent(input, 'keydown', (e: KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        if (e.ctrlKey || e.metaKey) {
          this.handleAddMore();
        } else {
          this.handleSave();
        }
      }
    });

    this.micronutrientInputs.set(key, input);
    this.refreshMicronutrientDropdown();
    input.focus();
  }

  /**
   * Remove the input row for a micronutrient key.
   */
  private removeMicronutrientField(key: string): void {
    const input = this.micronutrientInputs.get(key);
    if (input) {
      const row = input.closest('.micronutrient-field-row');
      if (row) row.remove();
    }
    this.micronutrientInputs.delete(key);
    this.refreshMicronutrientDropdown();
  }

  /**
   * Collect the entered micronutrient values (skipping blanks / invalid).
   */
  private collectMicronutrients(): { key: string; value: number }[] {
    const result: { key: string; value: number }[] = [];
    // Preserve catalogue order for stable output
    for (const def of MICRONUTRIENTS) {
      const input = this.micronutrientInputs.get(def.key);
      if (!input) continue;
      const raw = input.value.trim();
      if (raw === '') continue;
      const value = parseFloat(raw);
      if (!isNaN(value) && value >= 0) {
        result.push({ key: def.key, value });
      }
    }
    return result;
  }

  private setupEnergyConversion(): void {
    // Convert from kcal to kJ
    this.component.registerDomEvent(this.caloriesInput, 'input', () => {
      const kcalValue = parseFloat(this.caloriesInput.value);
      if (!isNaN(kcalValue) && kcalValue >= 0) {
        const kjValue = convertEnergyUnit(kcalValue, 'kcal', 'kJ');
        this.kjInput.value = kjValue.toFixed(1);
      } else if (this.caloriesInput.value === '') {
        this.kjInput.value = '';
      }
    });

    // Convert from kJ to kcal
    this.component.registerDomEvent(this.kjInput, 'input', () => {
      const kjValue = parseFloat(this.kjInput.value);
      if (!isNaN(kjValue) && kjValue >= 0) {
        const kcalValue = convertEnergyUnit(kjValue, 'kJ', 'kcal');
        this.caloriesInput.value = kcalValue.toFixed(1);
      } else if (this.kjInput.value === '') {
        this.caloriesInput.value = '';
      }
    });
  }

  private createActionButtons(container: HTMLElement): void {
    const buttonContainer = container.createDiv({
      cls: 'button-container macros-button-container',
    });

    const cancelBtn = buttonContainer.createEl('button', {
      text: this.addedItems.length > 0 ? t('food.manual.finishAdding') : t('general.cancel'),
      cls: 'mod-button',
    });

    // Only show "Add More" button if we already have items or user has started entering data
    const addMoreBtn = buttonContainer.createEl('button', {
      text: t('food.manual.addAndContinue'),
      cls: 'mod-button',
    });

    const saveBtn = buttonContainer.createEl('button', {
      text: this.addedItems.length > 0 ? t('food.manual.addThisItem') : t('food.manual.save'),
      cls: 'mod-button mod-cta',
    });

    // Event handlers
    this.component.registerDomEvent(cancelBtn, 'click', () => {
      if (this.addedItems.length > 0) {
        new Notice(t('food.manual.allItemsSaved', { count: this.addedItems.length.toString() }));
      }
      this.close();
    });

    this.component.registerDomEvent(addMoreBtn, 'click', () => {
      this.handleAddMore();
    });

    this.component.registerDomEvent(saveBtn, 'click', () => {
      this.handleSave();
    });

    // Handle Enter key submission
    const handleEnterKey = (e: KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        if (e.ctrlKey || e.metaKey) {
          this.handleAddMore();
        } else {
          this.handleSave();
        }
      }
    };

    // Add Enter key handler to all inputs
    [
      this.foodNameInput,
      this.servingSizeInput,
      this.defaultServingSizeInput,
      this.caloriesInput,
      this.kjInput,
      this.proteinInput,
      this.fatInput,
      this.carbsInput,
    ].forEach((input) => {
      this.component.registerDomEvent(input, 'keydown', handleEnterKey);
    });
  }

  private async validateForm(): Promise<{ isValid: boolean; errors: string[] }> {
    const errors: string[] = [];

    if (!this.foodNameInput.value.trim()) {
      errors.push(t('validation.required'));
    }

    const servingSize = parseFloat(this.servingSizeInput.value);
    if (isNaN(servingSize) || servingSize <= 0) {
      errors.push(t('validation.invalidServing'));
    }

    // Validate default serving size if provided
    const defaultServingStr = this.defaultServingSizeInput.value.trim();
    if (defaultServingStr) {
      const defaultServing = parseFloat(defaultServingStr);
      if (isNaN(defaultServing) || defaultServing <= 0) {
        errors.push('Invalid default serving size. Must be greater than 0 or left empty.');
      }
    }

    const calories = parseFloat(this.caloriesInput.value);
    if (isNaN(calories) || calories < 0) {
      errors.push(t('validation.invalidNumber'));
    }

    const protein = parseFloat(this.proteinInput.value);
    if (isNaN(protein) || protein < 0) {
      errors.push(t('validation.invalidNumber'));
    }

    const fat = parseFloat(this.fatInput.value);
    if (isNaN(fat) || fat < 0) {
      errors.push(t('validation.invalidNumber'));
    }

    const carbs = parseFloat(this.carbsInput.value);
    if (isNaN(carbs) || carbs < 0) {
      errors.push(t('validation.invalidNumber'));
    }

    // Check if food name already exists
    const foodName = this.foodNameInput.value.trim();
    const folderPath = normalizePath(this.plugin.settings.storageFolder);
    const fileName = `${foodName}.md`;
    const filePath = normalizePath(`${folderPath}/${fileName}`);

    try {
      const existingFile = this.plugin.app.vault.getAbstractFileByPath(filePath);
      if (existingFile) {
        errors.push(t('validation.duplicateName', { name: foodName }));
      }
    } catch (error) {
      // File doesn't exist, which is expected
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  private async handleSave(): Promise<void> {
    try {
      const validation = await this.validateForm();
      if (!validation.isValid) {
        this.showValidationErrors(validation.errors);
        return;
      }

      await this.saveCurrentItem();

      if (this.addedItems.length === 1) {
        new Notice(t('notifications.foodSaved', { fileName: this.addedItems[0] }));
        this.close();
      } else {
        new Notice(t('food.manual.allItemsSaved', { count: this.addedItems.length.toString() }));
        this.close();
      }
    } catch (error) {
      this.plugin.logger.error('Error saving food item:', error);
      new Notice(
        t('notifications.foodSaveError', {
          error: (error as Error).message || t('errors.unknownError'),
        })
      );
    }
  }

  private async handleAddMore(): Promise<void> {
    try {
      const validation = await this.validateForm();
      if (!validation.isValid) {
        this.showValidationErrors(validation.errors);
        return;
      }

      await this.saveCurrentItem();
      this.clearForm();
      this.updateButtonText();
      this.updateStatusSection();

      this.foodNameInput.focus();
      new Notice(t('food.manual.itemSavedReadyForNext'));
    } catch (error) {
      this.plugin.logger.error('Error saving food item:', error);
      new Notice(
        t('notifications.foodSaveError', {
          error: (error as Error).message || t('errors.unknownError'),
        })
      );
    }
  }

  private async saveCurrentItem(): Promise<void> {
    const foodName = this.foodNameInput.value.trim();
    const servingSize = parseFloat(this.servingSizeInput.value);
    const defaultServingStr = this.defaultServingSizeInput.value.trim();
    const calories = parseFloat(this.caloriesInput.value);
    const kj = parseFloat(this.kjInput.value);
    const protein = parseFloat(this.proteinInput.value);
    const fat = parseFloat(this.fatInput.value);
    const carbs = parseFloat(this.carbsInput.value);

    // Parse default serving size if provided
    const defaultServing = defaultServingStr ? parseFloat(defaultServingStr) : null;

    const fileName = `${foodName}.md`;
    let frontmatter = `---
calories: ${calories}
kj: ${kj}
protein: ${protein}
fat: ${fat}
carbs: ${carbs}
serving_size: ${servingSize}g`;

    // Collect optional micronutrient values
    const micronutrients = this.collectMicronutrients();
    for (const micro of micronutrients) {
      frontmatter += `\n${micro.key}: ${micro.value}`;
    }

    // Add default serving size if provided and different from serving size
    if (defaultServing && defaultServing !== servingSize) {
      frontmatter += `\ndefault_serving_size: ${defaultServing}g`;
    }

    frontmatter += `
source: manual_entry
created: ${new Date().toISOString()}
---

# ${foodName}

## Nutritional Information (per ${servingSize}g)
- **${t('food.manual.calories')}:** ${calories} kcal
- **${t('food.manual.energy')}:** ${kj} kJ
- **${t('food.manual.protein')}:** ${protein}g
- **${t('food.manual.fat')}:** ${fat}g
- **${t('food.manual.carbs')}:** ${carbs}g`;

    // Add micronutrient details to the body if any were provided
    if (micronutrients.length > 0) {
      frontmatter += `\n\n## ${t('food.manual.micronutrients.bodyHeading')} (per ${servingSize}g)`;
      for (const micro of micronutrients) {
        const def = MICRONUTRIENTS.find((d) => d.key === micro.key);
        const label = def ? def.label : micro.key;
        const unit = def ? def.unit : '';
        frontmatter += `\n- **${label}:** ${micro.value}${unit}`;
      }
    }

    // Add default serving size note if different from nutritional serving
    if (defaultServing && defaultServing !== servingSize) {
      frontmatter += `\n\n**Default Serving Size:** ${defaultServing}g (when adding to macros)`;
    }

    const folderPath = normalizePath(this.plugin.settings.storageFolder);
    const folder = this.plugin.app.vault.getFolderByPath(folderPath);
    if (!folder) {
      await this.plugin.app.vault.createFolder(folderPath);
    }

    const filePath = normalizePath(`${folderPath}/${fileName}`);
    await this.plugin.app.vault.create(filePath, frontmatter);

    this.addedItems.push(foodName);
    this.plugin.dataManager.invalidateFileCache();
  }

  private clearForm(): void {
    this.foodNameInput.value = '';
    this.servingSizeInput.value = '100'; // Reset to default 100g instead of empty
    this.defaultServingSizeInput.value = '';
    this.caloriesInput.value = '';
    this.kjInput.value = '';
    this.proteinInput.value = '';
    this.fatInput.value = '';
    this.carbsInput.value = '';

    // Clear any optional micronutrient fields that were added
    if (this.microFieldsContainer) {
      this.microFieldsContainer.empty();
    }
    this.micronutrientInputs.clear();
    this.refreshMicronutrientDropdown();

    const errorContainer = this.contentEl.querySelector('.validation-errors');
    if (errorContainer) {
      errorContainer.remove();
    }
  }

  private updateButtonText(): void {
    const saveBtn = this.contentEl.querySelector('.mod-cta');
    const cancelBtn = this.contentEl.querySelector('.mod-button');

    if (saveBtn) {
      saveBtn.textContent =
        this.addedItems.length > 0 ? t('food.manual.addThisItem') : t('food.manual.save');
    }

    if (cancelBtn) {
      cancelBtn.textContent =
        this.addedItems.length > 0 ? t('food.manual.finishAdding') : t('general.cancel');
    }
  }

  private showValidationErrors(errors: string[]): void {
    const existingErrorContainer = this.contentEl.querySelector('.validation-errors');
    if (existingErrorContainer) {
      existingErrorContainer.remove();
    }

    const formContainer = this.contentEl.querySelector('.manual-entry-form');
    if (formContainer) {
      const errorsDiv = formContainer.createDiv({ cls: 'validation-errors' });
      errors.forEach((error) => {
        errorsDiv.createEl('p', { text: error, cls: 'error-message macros-error-message' });
      });
    }
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { Modal, Setting, ButtonComponent } from 'obsidian';
import MacrosPlugin from '../../main';
import { TFile } from 'obsidian';
import { t } from '../../lang/I18nManager';

interface AffectedFile {
  file: TFile;
  matches: Array<{
    line: number;
    content: string;
    preview: string;
  }>;
}

/**
 * RenameConfirmationModal
 * -----------------------
 * Modal for confirming food name rename operations and selecting which files to update.
 */
export class RenameConfirmationModal extends Modal {
  private plugin: MacrosPlugin;
  private oldName: string;
  private newName: string;
  private affectedFiles: AffectedFile[];
  private onConfirm: (selectedFiles: AffectedFile[]) => Promise<void>;
  private onCancel?: () => Promise<void>;
  private selectedFiles: Set<string> = new Set();
  private createBackupCheckbox: HTMLInputElement | null = null;

  constructor(
    plugin: MacrosPlugin,
    oldName: string,
    newName: string,
    affectedFiles: AffectedFile[],
    onConfirm: (selectedFiles: AffectedFile[]) => Promise<void>,
    onCancel?: () => Promise<void>
  ) {
    super(plugin.app);
    this.plugin = plugin;
    this.oldName = oldName;
    this.newName = newName;
    this.affectedFiles = affectedFiles;
    this.onConfirm = onConfirm;
    this.onCancel = onCancel;

    // Initially select all files
    this.affectedFiles.forEach(({ file }) => {
      this.selectedFiles.add(file.path);
    });
  }

  onOpen(): void {
    const { contentEl } = this;
    contentEl.empty();

    // Title
    contentEl.createEl('h2', { text: t('rename.title') });

    // Summary section
    const summaryEl = contentEl.createDiv({ cls: 'rename-summary' });

    summaryEl.createEl('p', {
      text: t('rename.summary', {
        oldName: this.oldName,
        newName: this.newName,
      }),
    });

    summaryEl.createEl('p', {
      text: t('rename.filesAffected', { count: this.affectedFiles.length }),
      cls: 'rename-files-count',
    });

    // Files list section
    const filesSection = contentEl.createDiv({ cls: 'rename-files-section' });
    filesSection.createEl('h3', {
      text: t('rename.filesAffected', { count: this.affectedFiles.length }),
    });

    const filesList = filesSection.createDiv({ cls: 'rename-files-list' });

    this.affectedFiles.forEach(({ file, matches }) => {
      const fileItem = filesList.createDiv({ cls: 'rename-file-item' });

      // File checkbox and name
      const fileHeader = fileItem.createDiv({ cls: 'rename-file-header' });

      const checkbox = fileHeader.createEl('input', {
        type: 'checkbox',
        cls: 'rename-file-checkbox',
      });
      checkbox.checked = this.selectedFiles.has(file.path);
      checkbox.addEventListener('change', () => {
        if (checkbox.checked) {
          this.selectedFiles.add(file.path);
        } else {
          this.selectedFiles.delete(file.path);
        }
        this.updateButtonStates();
      });

      fileHeader.createEl('span', {
        text: file.path,
        cls: 'rename-file-path',
      });

      fileHeader.createEl('span', {
        text: `(${matches.length} ${matches.length === 1 ? 'match' : 'matches'})`,
        cls: 'rename-match-count',
      });

      // Preview section
      const previewSection = fileItem.createDiv({ cls: 'rename-preview-section' });

      // Fixed: Prefix unused parameter with underscore
      matches.slice(0, 3).forEach((match, _index) => {
        const previewItem = previewSection.createDiv({ cls: 'rename-preview-item' });

        previewItem.createEl('div', {
          text: `${t('rename.previewBefore')}: ${match.preview}`,
          cls: 'rename-preview-before',
        });

        const afterPreview = match.preview.replace(
          new RegExp(
            this.escapeRegExp(this.oldName),
            this.plugin.settings.caseSensitiveFoodMatch ? 'g' : 'gi'
          ),
          this.newName
        );

        previewItem.createEl('div', {
          text: `${t('rename.previewAfter')}: ${afterPreview}`,
          cls: 'rename-preview-after',
        });
      });

      if (matches.length > 3) {
        previewSection.createEl('div', {
          text: `... and ${matches.length - 3} more matches`,
          cls: 'rename-more-matches',
        });
      }
    });

    // Options section
    const optionsSection = contentEl.createDiv({ cls: 'rename-options-section' });

    new Setting(optionsSection)
      .setName(t('rename.backup'))
      .setDesc('Create backup before modifying files')
      .addToggle((toggle) => {
        toggle.setValue(this.plugin.settings.backupOnRename);
        this.createBackupCheckbox = toggle.toggleEl.querySelector('input');
        toggle.onChange(async (value) => {
          // Update the setting temporarily for this operation
          this.plugin.settings.backupOnRename = value;
        });
      });

    // Action buttons
    const buttonContainer = contentEl.createDiv({ cls: 'rename-button-container' });

    const replaceButton = new ButtonComponent(buttonContainer)
      .setButtonText(t('rename.replace'))
      .setCta()
      .onClick(() => this.handleReplace());

    // Fixed: Prefix unused variables with underscore
    const _skipButton = new ButtonComponent(buttonContainer)
      .setButtonText(t('rename.skip'))
      .onClick(() => this.close());

    const _cancelButton = new ButtonComponent(buttonContainer)
      .setButtonText(t('rename.cancel'))
      .onClick(() => this.handleCancel());

    // Store button references for state updates
    this.replaceButton = replaceButton;
    this.updateButtonStates();

    // Add CSS styles
    this.addStyles();
  }

  private replaceButton: ButtonComponent | null = null;

  private updateButtonStates(): void {
    if (this.replaceButton) {
      const hasSelection = this.selectedFiles.size > 0;
      this.replaceButton.setDisabled(!hasSelection);
    }
  }

  private async handleReplace(): Promise<void> {
    const selectedFileObjects = this.affectedFiles.filter(({ file }) =>
      this.selectedFiles.has(file.path)
    );

    if (selectedFileObjects.length === 0) {
      return;
    }

    this.close();
    await this.onConfirm(selectedFileObjects);
  }

  private async handleCancel(): Promise<void> {
    this.close();
    if (this.onCancel) {
      await this.onCancel();
    }
  }

  private escapeRegExp(string: string): string {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  private addStyles(): void {
    const styleEl = activeDocument.createElement('style');
    styleEl.textContent = `
      .rename-summary {
        margin-bottom: 1rem;
        padding: 1rem;
        background: var(--background-secondary);
        border-radius: 4px;
      }

      .rename-files-count {
        font-weight: 600;
        color: var(--text-accent);
      }

      .rename-files-section {
        margin-bottom: 1rem;
      }

      .rename-files-list {
        max-height: 300px;
        overflow-y: auto;
        border: 1px solid var(--background-modifier-border);
        border-radius: 4px;
      }

      .rename-file-item {
        border-bottom: 1px solid var(--background-modifier-border);
        padding: 0.75rem;
      }

      .rename-file-item:last-child {
        border-bottom: none;
      }

      .rename-file-header {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-bottom: 0.5rem;
      }

      .rename-file-checkbox {
        margin: 0;
      }

      .rename-file-path {
        font-weight: 500;
        flex: 1;
      }

      .rename-match-count {
        color: var(--text-muted);
        font-size: 0.9em;
      }

      .rename-preview-section {
        margin-left: 1.5rem;
        font-size: 0.9em;
      }

      .rename-preview-item {
        margin-bottom: 0.25rem;
      }

      .rename-preview-before {
        color: var(--text-error);
        font-family: var(--font-monospace);
      }

      .rename-preview-after {
        color: var(--text-success);
        font-family: var(--font-monospace);
      }

      .rename-more-matches {
        color: var(--text-muted);
        font-style: italic;
        margin-top: 0.25rem;
      }

      .rename-options-section {
        margin-bottom: 1rem;
        padding-top: 1rem;
        border-top: 1px solid var(--background-modifier-border);
      }

      .rename-button-container {
        display: flex;
        gap: 0.5rem;
        justify-content: flex-end;
        padding-top: 1rem;
        border-top: 1px solid var(--background-modifier-border);
      }
    `;
    activeDocument.head.appendChild(styleEl);

    // Clean up styles when modal closes
    this.onClose = () => {
      activeDocument.head.removeChild(styleEl);
    };
  }

  onClose(): void {
    const { contentEl } = this;
    contentEl.empty();
  }
}

import { App, Modal, Notice, Component } from 'obsidian';
import MacrosPlugin from '../../main';
import { t } from '../../lang/I18nManager';

export class TimestampModal extends Modal {
  private plugin: MacrosPlugin;
  private onSubmit: (timestamp: string) => Promise<void>;
  private component: Component;
  private currentTimestamp: string;
  private isEditing: boolean;
  private targetType: 'meal' | 'food-item';
  private targetName: string;

  constructor(
    app: App,
    plugin: MacrosPlugin,
    currentTimestamp: string,
    targetType: 'meal' | 'food-item',
    targetName: string,
    onSubmit: (timestamp: string) => Promise<void>
  ) {
    super(app);
    this.plugin = plugin;
    this.currentTimestamp = currentTimestamp;
    this.isEditing = currentTimestamp.length > 0;
    this.targetType = targetType;
    this.targetName = targetName;
    this.onSubmit = onSubmit;
    this.component = new Component();
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.addClass('timestamp-modal');

    // Create header
    const header = contentEl.createEl('div', {
      cls: 'modal-header macros-modal-header timestamp-modal-header',
    });
    const title = this.isEditing
      ? this.targetType === 'meal'
        ? t('timestamps.editMealTimestamp')
        : t('timestamps.editItemTimestamp')
      : this.targetType === 'meal'
        ? t('timestamps.addMealTimestamp')
        : t('timestamps.addItemTimestamp');

    header.createEl('h2', {
      text: title,
      cls: 'timestamp-modal-title',
    });

    // Create description
    const description = contentEl.createEl('div', {
      cls: 'modal-description macros-modal-description timestamp-modal-description',
    });
    const descriptionText =
      this.targetType === 'meal'
        ? t('timestamps.mealDescription', { mealName: this.targetName })
        : t('timestamps.itemDescription', { itemName: this.targetName });

    description.createEl('p', {
      text: descriptionText,
      cls: 'timestamp-description-text',
    });

    // Create input container
    const inputContainer = contentEl.createDiv({ cls: 'timestamp-input-container' });

    const inputLabel = inputContainer.createEl('label', {
      text: t('timestamps.timeLabel'),
      cls: 'timestamp-input-label',
    });

    // Create time input with current time as default
    const timeInput = inputContainer.createEl('input', {
      type: 'time',
      cls: 'timestamp-input-time',
    });

    // Set initial value
    if (this.currentTimestamp) {
      timeInput.value = this.currentTimestamp;
    } else {
      // Default to current time
      const now = new Date();
      const hours = now.getHours().toString().padStart(2, '0');
      const minutes = now.getMinutes().toString().padStart(2, '0');
      timeInput.value = `${hours}:${minutes}`;
    }

    // Add quick time buttons
    const quickTimeContainer = inputContainer.createDiv({ cls: 'quick-time-container' });
    quickTimeContainer.createEl('label', {
      text: t('timestamps.quickTimes'),
      cls: 'quick-time-label',
    });

    const quickTimeButtons = quickTimeContainer.createDiv({ cls: 'quick-time-buttons' });

    // Breakfast, Lunch, Dinner presets
    const presets = [
      { label: t('timestamps.breakfast'), time: '08:00' },
      { label: t('timestamps.lunch'), time: '12:00' },
      { label: t('timestamps.dinner'), time: '18:00' },
      { label: t('timestamps.now'), time: this.getCurrentTime() },
    ];

    presets.forEach(({ label, time }) => {
      const btn = quickTimeButtons.createEl('button', {
        text: label,
        cls: 'quick-time-btn',
        type: 'button',
      });

      this.component.registerDomEvent(btn, 'click', () => {
        timeInput.value = time;
        timeInput.focus();
      });
    });

    // Button container
    const buttonContainer = contentEl.createDiv({
      cls: 'timestamp-button-container macros-button-container',
    });

    const cancelBtn = buttonContainer.createEl('button', {
      text: t('general.cancel'),
      cls: 'mod-button timestamp-cancel-btn',
    });

    const saveBtn = buttonContainer.createEl('button', {
      text: this.isEditing ? t('timestamps.updateTimestamp') : t('timestamps.addTimestamp'),
      cls: 'mod-button mod-cta timestamp-save-btn',
    });

    // If editing, add a remove button
    if (this.isEditing) {
      const removeBtn = buttonContainer.createEl('button', {
        text: t('timestamps.removeTimestamp'),
        cls: 'mod-button mod-warning timestamp-remove-btn',
      });

      this.component.registerDomEvent(removeBtn, 'click', async () => {
        try {
          await this.onSubmit(''); // Empty string removes the timestamp
          new Notice(t('timestamps.timestampRemoved'));
          this.close();
        } catch (error) {
          this.plugin.logger.error('Error removing timestamp:', error);
          new Notice(t('timestamps.removeError', { error: (error as Error).message }));
        }
      });
    }

    // Event handlers
    this.component.registerDomEvent(cancelBtn, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(saveBtn, 'click', async () => {
      const timestamp = timeInput.value.trim();

      if (!timestamp) {
        new Notice(t('timestamps.invalidTime'));
        return;
      }

      // Validate time format
      if (!/^([01]?[0-9]|2[0-3]):[0-5][0-9]$/.test(timestamp)) {
        new Notice(t('timestamps.invalidTime'));
        return;
      }

      try {
        await this.onSubmit(timestamp);
        const successMsg = timestamp
          ? this.isEditing
            ? t('timestamps.timestampUpdated')
            : t('timestamps.timestampAdded')
          : t('timestamps.timestampRemoved');
        new Notice(successMsg);
        this.close();
      } catch (error) {
        this.plugin.logger.error('Error saving timestamp:', error);
        new Notice(t('timestamps.saveError', { error: (error as Error).message }));
      }
    });

    // Handle Enter key (save) and Escape key (cancel)
    this.component.registerDomEvent(timeInput, 'keydown', (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        saveBtn.click();
      } else if (e.key === 'Escape') {
        this.close();
      }
    });

    // Focus and select the time input
    window.setTimeout(() => {
      timeInput.focus();
      timeInput.select();
    }, 100);
  }

  private getCurrentTime(): string {
    const now = new Date();
    const hours = now.getHours().toString().padStart(2, '0');
    const minutes = now.getMinutes().toString().padStart(2, '0');
    return `${hours}:${minutes}`;
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { App, Modal, Notice, Component } from 'obsidian';
import MacrosPlugin from '../../main';
import { t } from '../../lang/I18nManager';

export interface ToleranceData {
  severity: '­ƒö┤' | '­ƒƒá' | '­ƒƒí';
  symptoms: string;
  dateAdded: string;
}

export class ToleranceModal extends Modal {
  private plugin: MacrosPlugin;
  private onSubmit: (tolerance: ToleranceData | null) => Promise<void>;
  private component: Component;
  private currentTolerance: ToleranceData | null;
  private isEditing: boolean;
  private targetType: 'meal' | 'food-item';
  private targetName: string;

  constructor(
    app: App,
    plugin: MacrosPlugin,
    currentTolerance: ToleranceData | null,
    targetType: 'meal' | 'food-item',
    targetName: string,
    onSubmit: (tolerance: ToleranceData | null) => Promise<void>
  ) {
    super(app);
    this.plugin = plugin;
    this.currentTolerance = currentTolerance;
    this.isEditing = currentTolerance !== null;
    this.targetType = targetType;
    this.targetName = targetName;
    this.onSubmit = onSubmit;
    this.component = new Component();
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.addClass('tolerance-modal');

    // Create header
    const header = contentEl.createEl('div', {
      cls: 'modal-header macros-modal-header tolerance-modal-header',
    });

    const title = this.isEditing
      ? this.targetType === 'meal'
        ? t('tolerances.editMealTolerance')
        : t('tolerances.editItemTolerance')
      : this.targetType === 'meal'
        ? t('tolerances.addMealTolerance')
        : t('tolerances.addItemTolerance');

    header.createEl('h2', {
      text: title,
      cls: 'tolerance-modal-title',
    });

    // Create description
    const description = contentEl.createEl('div', {
      cls: 'modal-description macros-modal-description tolerance-modal-description',
    });

    const descriptionText =
      this.targetType === 'meal'
        ? t('tolerances.mealDescription', { mealName: this.targetName })
        : t('tolerances.itemDescription', { itemName: this.targetName });

    description.createEl('p', {
      text: descriptionText,
      cls: 'tolerance-description-text',
    });

    // Create severity selection container
    const severityContainer = contentEl.createDiv({ cls: 'tolerance-severity-container' });

    // Fixed: Prefix unused variable with underscore
    const _severityLabel = severityContainer.createEl('label', {
      text: t('tolerances.severityLabel'),
      cls: 'tolerance-severity-label',
    });

    const severityOptions = severityContainer.createDiv({ cls: 'tolerance-severity-options' });

    // Severity options with descriptions
    const severities = [
      {
        value: '­ƒƒí' as const,
        label: t('tolerances.severityMild'),
        description: t('tolerances.severityMildDesc'),
      },
      {
        value: '­ƒƒá' as const,
        label: t('tolerances.severityModerate'),
        description: t('tolerances.severityModerateDesc'),
      },
      {
        value: '­ƒö┤' as const,
        label: t('tolerances.severitySevere'),
        description: t('tolerances.severitySevereDesc'),
      },
    ];

    let selectedSeverity: '­ƒö┤' | '­ƒƒá' | '­ƒƒí' = this.currentTolerance?.severity || null;

    severities.forEach(({ value, label, description }) => {
      const optionContainer = severityOptions.createDiv({ cls: 'tolerance-severity-option' });

      const option = optionContainer.createEl('button', {
        cls: `tolerance-severity-btn ${selectedSeverity === value ? 'selected' : ''}`,
        type: 'button',
      });

      // Fixed: Prefix unused variable with underscore
      const _iconSpan = option.createSpan({ cls: 'severity-icon', text: value });
      const textContainer = option.createDiv({ cls: 'severity-text' });
      textContainer.createSpan({ cls: 'severity-label', text: label });
      textContainer.createSpan({ cls: 'severity-description', text: description });

      this.component.registerDomEvent(option, 'click', () => {
        // Remove selected class from all options
        severityOptions.querySelectorAll('.tolerance-severity-btn').forEach((btn) => {
          btn.classList.remove('selected');
        });

        // Add selected class to clicked option
        option.classList.add('selected');
        selectedSeverity = value;
      });
    });

    // Create symptoms input container
    const symptomsContainer = contentEl.createDiv({ cls: 'tolerance-symptoms-container' });

    // Fixed: Prefix unused variable with underscore
    const _symptomsLabel = symptomsContainer.createEl('label', {
      text: t('tolerances.symptomsLabel'),
      cls: 'tolerance-symptoms-label',
    });

    const textarea = symptomsContainer.createEl('textarea', {
      cls: 'tolerance-symptoms-textarea',
      attr: {
        placeholder: t('tolerances.symptomsPlaceholder'),
        rows: '3',
        maxlength: '200',
      },
    });

    textarea.value = this.currentTolerance?.symptoms || '';

    // Character count
    const charCount = symptomsContainer.createEl('div', {
      cls: 'tolerance-char-count',
      text: `${textarea.value.length}/200`,
    });

    // Update character count on input
    this.component.registerDomEvent(textarea, 'input', () => {
      const length = textarea.value.length;
      charCount.textContent = `${length}/200`;

      if (length > 180) {
        charCount.addClass('char-count-warning');
      } else {
        charCount.removeClass('char-count-warning');
      }
    });

    // Button container
    const buttonContainer = contentEl.createDiv({
      cls: 'tolerance-button-container macros-button-container',
    });

    const cancelBtn = buttonContainer.createEl('button', {
      text: t('general.cancel'),
      cls: 'mod-button tolerance-cancel-btn',
    });

    const saveBtn = buttonContainer.createEl('button', {
      text: this.isEditing ? t('tolerances.updateTolerance') : t('tolerances.addTolerance'),
      cls: 'mod-button mod-cta tolerance-save-btn',
    });

    // If editing, add a remove button
    if (this.isEditing) {
      const removeBtn = buttonContainer.createEl('button', {
        text: t('tolerances.removeTolerance'),
        cls: 'mod-button mod-warning tolerance-remove-btn',
      });

      this.component.registerDomEvent(removeBtn, 'click', async () => {
        try {
          await this.onSubmit(null); // null removes the tolerance
          new Notice(t('tolerances.toleranceRemoved'));
          this.close();
        } catch (error) {
          this.plugin.logger.error('Error removing tolerance:', error);
          new Notice(t('tolerances.removeError', { error: (error as Error).message }));
        }
      });
    }

    // Event handlers
    this.component.registerDomEvent(cancelBtn, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(saveBtn, 'click', async () => {
      const symptoms = textarea.value.trim();

      if (symptoms.length > 200) {
        new Notice(t('tolerances.symptomsTooLong'));
        return;
      }

      if (symptoms.length === 0) {
        new Notice(t('tolerances.symptomsRequired'));
        return;
      }

      try {
        const toleranceData: ToleranceData = {
          severity: selectedSeverity,
          symptoms: symptoms,
          dateAdded: new Date().toISOString(),
        };

        await this.onSubmit(toleranceData);

        const successMsg = this.isEditing
          ? t('tolerances.toleranceUpdated')
          : t('tolerances.toleranceAdded');

        new Notice(successMsg);
        this.close();
      } catch (error) {
        this.plugin.logger.error('Error saving tolerance:', error);
        new Notice(t('tolerances.saveError', { error: (error as Error).message }));
      }
    });

    // Handle Enter key (Ctrl/Cmd + Enter to save)
    this.component.registerDomEvent(textarea, 'keydown', (e: KeyboardEvent) => {
      if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        saveBtn.click();
      } else if (e.key === 'Escape') {
        this.close();
      }
    });

    // Focus the textarea
    window.setTimeout(() => {
      textarea.focus();
      if (this.isEditing) {
        textarea.select();
      }
    }, 100);
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { Component, Modal, App, Notice } from 'obsidian';
import MacrosPlugin from '../main';
import {
  ZXingLoader,
  BarcodeUtils,
  MobilePermissionHandler,
  CameraDiagnostics,
} from './BarcodeUtils';

export interface BarcodeResult {
  code: string;
  format: string;
  confidence?: number;
}

// Enhanced ZXing interfaces to include BarcodeFormat
interface ZXingBarcodeFormat {
  EAN_13: unknown;
  EAN_8: unknown;
  UPC_A: unknown;
  UPC_E: unknown;
  CODE_128: unknown;
  CODE_39: unknown;
  CODE_93: unknown;
  ITF: unknown;
  CODABAR: unknown;
}

interface EnhancedZXingLibrary {
  BarcodeFormat?: ZXingBarcodeFormat;
  default?: EnhancedZXingLibrary;
}

interface ZXingCodeReader {
  decode?(target: HTMLCanvasElement | ImageData | unknown): Promise<ZXingResult>;
  decodeFromCanvas?(canvas: HTMLCanvasElement): Promise<ZXingResult>;
  decodeFromImageData?(imageData: ImageData): Promise<ZXingResult>;
  decodeFromImageElement?(img: HTMLImageElement): Promise<ZXingResult>;
  decodeFromImage?(img: HTMLImageElement): Promise<ZXingResult>;
  decodeFromVideoDevice?(
    deviceId: string | undefined,
    videoElement: HTMLVideoElement
  ): Promise<ZXingResult>;
  decodeBitmap?(imageData: ImageData): Promise<ZXingResult>;
  setHints?(hints: Map<string, unknown>): void;
}

interface ZXingResult {
  getText(): string;
  getBarcodeFormat(): { toString(): string };
  text?: string;
  code?: string;
  format?: string;
}

export class BarcodeScanner extends Component {
  public video: HTMLVideoElement | null = null;
  public canvas: HTMLCanvasElement | null = null;
  public context: CanvasRenderingContext2D | null = null;
  public codeReader: ZXingCodeReader | null = null;
  private stream: MediaStream | null = null;
  private scanning = false;
  private scanInterval: number | null = null;

  constructor(
    private app: App,
    private plugin: MacrosPlugin,
    private onBarcodeDetected: (result: BarcodeResult) => void,
    private onError: (error: string) => void
  ) {
    super();
  }

  async initializeCamera(): Promise<boolean> {
    try {
      this.plugin.logger.debug('Requesting camera permission...');

      const permissionResult = await MobilePermissionHandler.requestCameraPermission();

      if (!permissionResult.granted) {
        const instructions = MobilePermissionHandler.getPermissionInstructions();
        const errorMsg = `${permissionResult.error}\n\n${instructions}`;
        this.onError(errorMsg);
        return false;
      }

      if (!permissionResult.stream) {
        this.onError('Camera stream not available');
        return false;
      }

      this.stream = permissionResult.stream;
      this.plugin.logger.debug('Camera permission granted successfully');
      return true;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.plugin.logger.error('Camera initialization failed:', error);
      this.onError(`Unexpected camera error: ${errorMessage}`);
      return false;
    }
  }

  async startScanning(videoElement: HTMLVideoElement): Promise<void> {
    if (!this.stream) {
      throw new Error('Camera not initialized');
    }

    this.video = videoElement;
    this.video.srcObject = this.stream;

    await new Promise<void>((resolve, reject) => {
      if (!this.video) {
        reject(new Error('Video element not available'));
        return;
      }

      this.video.addEventListener('loadedmetadata', () => resolve());
      this.video.addEventListener('error', reject);
      this.video.play().catch(reject);
    });

    await this.initializeDecoder();
    this.scanning = true;
    this.startScanLoop();
  }

  private async initializeDecoder(): Promise<void> {
    try {
      this.plugin.logger.debug('Initializing ZXing decoder...');
      this.codeReader = await ZXingLoader.createCodeReader();

      // Configure the reader for better barcode detection
      if (this.codeReader.setHints) {
        const ZXing = (await ZXingLoader.loadZXing()) as EnhancedZXingLibrary;
        const hints = new Map<string, unknown>();

        // Try to enable all barcode formats
        const BarcodeFormat = ZXing.BarcodeFormat || (ZXing.default && ZXing.default.BarcodeFormat);

        if (BarcodeFormat) {
          hints.set('POSSIBLE_FORMATS', [
            BarcodeFormat.EAN_13,
            BarcodeFormat.EAN_8,
            BarcodeFormat.UPC_A,
            BarcodeFormat.UPC_E,
            BarcodeFormat.CODE_128,
            BarcodeFormat.CODE_39,
            BarcodeFormat.CODE_93,
            BarcodeFormat.ITF,
            BarcodeFormat.CODABAR,
          ]);
        }

        hints.set('TRY_HARDER', true);
        hints.set('ALSO_INVERTED', true);

        this.codeReader.setHints(hints);
      }

      this.plugin.logger.debug('ZXing decoder initialized successfully');
    } catch (error) {
      this.plugin.logger.error('Failed to load ZXing library:', error);
      throw new Error(
        'Barcode decoder library failed to load. Please check your internet connection and try again.'
      );
    }
  }

  private startScanLoop(): void {
    if (!this.video || !this.codeReader) return;

    if (!this.canvas) {
      this.canvas = activeDocument.createElement('canvas');
      this.context = this.canvas.getContext('2d', { willReadFrequently: true });
    }

    this.plugin.logger.debug('Starting barcode scan loop');
    let scanAttempts = 0;

    this.scanInterval = window.setInterval(async () => {
      if (!this.scanning || !this.video || !this.canvas || !this.context) {
        return;
      }

      scanAttempts++;
      if (scanAttempts % 10 === 0) {
        this.plugin.logger.debug('Scan attempt', {
          attempt: scanAttempts,
          videoWidth: this.video.videoWidth,
          videoHeight: this.video.videoHeight,
        });
      }

      try {
        // Check if video is ready
        if (this.video.videoWidth === 0 || this.video.videoHeight === 0) {
          if (scanAttempts % 20 === 0) {
            this.plugin.logger.debug('Video not ready yet, waiting...');
          }
          return;
        }

        // Ensure canvas has proper dimensions
        const width = this.video.videoWidth;
        const height = this.video.videoHeight;

        if (width === 0 || height === 0) {
          if (scanAttempts % 20 === 0) {
            this.plugin.logger.debug('Invalid video dimensions, skipping...');
          }
          return;
        }

        this.canvas.width = width;
        this.canvas.height = height;
        this.context.drawImage(this.video, 0, 0, width, height);

        // Try different ZXing API methods
        let result: ZXingResult | null = null;

        try {
          // Method 1: Try decodeFromCanvas (most common for browsers)
          if (this.codeReader && this.codeReader.decodeFromCanvas) {
            result = await this.codeReader.decodeFromCanvas(this.canvas);
          }
          // Method 2: Try decode with canvas (alternative syntax)
          else if (this.codeReader && this.codeReader.decode) {
            result = await this.codeReader.decode(this.canvas);
          }
          // Method 3: Try decodeFromImageData (newer versions)
          else if (this.codeReader && this.codeReader.decodeFromImageData) {
            const imageData = this.context.getImageData(0, 0, width, height);
            result = await this.codeReader.decodeFromImageData(imageData);
          }
          // Method 4: Try decodeBitmap (if that's what we have)
          else if (this.codeReader && this.codeReader.decodeBitmap) {
            const imageData = this.context.getImageData(0, 0, width, height);
            result = await this.codeReader.decodeBitmap(imageData);
          }
          // Method 5: Try decodeFromVideoDevice (for live video)
          else if (this.codeReader && this.codeReader.decodeFromVideoDevice) {
            result = await this.codeReader.decodeFromVideoDevice(undefined, this.video);
          } else {
            if (scanAttempts === 1) {
              this.plugin.logger.error('No suitable decode method found on codeReader');
            }
            return;
          }
        } catch (decodeError: unknown) {
          const error = decodeError as { name?: string; message?: string };
          if (error.name !== 'NotFoundException') {
            if (scanAttempts % 50 === 0) {
              this.plugin.logger.debug('Decode method error', {
                name: error.name,
                message: error.message,
              });
            }
          }
          return;
        }

        if (result) {
          this.plugin.logger.debug('Barcode detected', {
            code: result.getText ? result.getText() : result.text,
            format: result.getBarcodeFormat ? result.getBarcodeFormat() : result.format,
          });

          const barcodeResult: BarcodeResult = {
            code: result.getText ? result.getText() : result.text || result.code || String(result),
            format: result.getBarcodeFormat
              ? result.getBarcodeFormat().toString()
              : result.format || 'Unknown',
          };

          this.stopScanning();
          this.onBarcodeDetected(barcodeResult);
        }

        // Debug: Check if we're getting valid image data
        if (scanAttempts % 30 === 0) {
          const imageData = this.context.getImageData(0, 0, width, height);
          const avgBrightness = this.calculateAverageBrightness(imageData);
          this.plugin.logger.debug('Image data check', {
            width: imageData.width,
            height: imageData.height,
            avgBrightness: avgBrightness.toFixed(1),
          });
        }
      } catch (error: unknown) {
        const err = error as { name?: string; message?: string };
        if (err.name !== 'NotFoundException') {
          if (scanAttempts % 50 === 0) {
            this.plugin.logger.debug('Scan frame error', {
              name: err.name,
              message: err.message,
            });
          }
        }
        // NotFoundException is normal when no barcode is detected
      }
    }, 300);
  }

  private calculateAverageBrightness(imageData: ImageData): number {
    const data = imageData.data;
    let totalBrightness = 0;
    const pixelCount = data.length / 4;

    for (let i = 0; i < data.length; i += 4) {
      const r = data[i];
      const g = data[i + 1];
      const b = data[i + 2];
      const brightness = 0.299 * r + 0.587 * g + 0.114 * b;
      totalBrightness += brightness;
    }

    return totalBrightness / pixelCount;
  }

  stopScanning(): void {
    this.scanning = false;

    if (this.scanInterval) {
      window.clearInterval(this.scanInterval);
      this.scanInterval = null;
    }

    if (this.stream) {
      this.stream.getTracks().forEach((track) => track.stop());
      this.stream = null;
    }

    if (this.video) {
      this.video.srcObject = null;
      this.video = null;
    }
  }

  async scanImageFile(file: File): Promise<BarcodeResult | null> {
    try {
      this.plugin.logger.debug('Starting image scan', {
        fileName: file.name,
        fileType: file.type,
        fileSize: file.size,
      });

      if (!file.type.startsWith('image/')) {
        throw new Error('Please select a valid image file (JPG, PNG, etc.)');
      }

      if (file.size > 10 * 1024 * 1024) {
        throw new Error('Image file is too large. Please use an image smaller than 10MB.');
      }

      await this.initializeDecoder();

      return new Promise((resolve, reject) => {
        const img = new Image();
        const imageUrl = URL.createObjectURL(file);

        const timeoutId = window.setTimeout(() => {
          URL.revokeObjectURL(imageUrl);
          reject(new Error('Image loading timed out'));
        }, 15000);

        img.onload = async () => {
          window.clearTimeout(timeoutId);
          URL.revokeObjectURL(imageUrl);

          try {
            this.plugin.logger.debug('Image loaded successfully', {
              width: img.width,
              height: img.height,
            });
            const result = await this.scanImageWithOptimizedMethods(img);
            resolve(result);
          } catch (error) {
            this.plugin.logger.error('Error during image scanning:', error);
            reject(error);
          }
        };

        img.onerror = () => {
          window.clearTimeout(timeoutId);
          URL.revokeObjectURL(imageUrl);
          reject(new Error('Failed to load image file. Please try a different image format.'));
        };

        img.crossOrigin = 'anonymous';
        img.src = imageUrl;
      });
    } catch (error) {
      this.plugin.logger.error('Image scan setup error:', error);
      throw error;
    }
  }

  private async scanImageWithOptimizedMethods(
    img: HTMLImageElement
  ): Promise<BarcodeResult | null> {
    // Optimized scanning methods
    const methods = [
      // Method 1: Direct image scan (fastest)
      { name: 'Direct image scan', process: () => this.tryDirectImageScan(img) },

      // Method 2: Canvas 1:1 (most accurate for normal images)
      { name: 'Canvas 1:1', process: () => this.tryOptimizedCanvasScan(img, 1, false) },

      // Method 3: Canvas 2x scale (for small barcodes)
      { name: 'Canvas 2x scale', process: () => this.tryOptimizedCanvasScan(img, 2, false) },

      // Method 4: Canvas 0.5x scale (for large images)
      { name: 'Canvas 0.5x scale', process: () => this.tryOptimizedCanvasScan(img, 0.5, false) },

      // Method 5: High contrast processing
      {
        name: 'High contrast',
        process: () => this.tryOptimizedCanvasScan(img, 1, true, { contrast: 2.0 }),
      },

      // Method 6: Brightness adjustment
      {
        name: 'Brightness boost',
        process: () => this.tryOptimizedCanvasScan(img, 1, true, { brightness: 1.3 }),
      },

      // Method 7: Threshold processing
      {
        name: 'Binary threshold',
        process: () => this.tryOptimizedCanvasScan(img, 1, true, { threshold: 128 }),
      },
    ];

    for (const method of methods) {
      try {
        this.plugin.logger.debug('Trying method', { method: method.name });
        const result = await method.process();

        if (result) {
          this.plugin.logger.debug('Barcode found', {
            method: method.name,
            code: result.code,
          });
          return result;
        }
      } catch (error: unknown) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        this.plugin.logger.debug('Method failed', {
          method: method.name,
          error: errorMessage,
        });
      }
    }

    this.plugin.logger.debug('No barcode found after trying all optimized methods');
    return null;
  }

  private async tryDirectImageScan(img: HTMLImageElement): Promise<BarcodeResult | null> {
    try {
      let result: ZXingResult | null = null;

      // Try different ZXing methods for direct image scanning
      if (this.codeReader && this.codeReader.decodeFromImageElement) {
        result = await this.codeReader.decodeFromImageElement(img);
      } else if (this.codeReader && this.codeReader.decodeFromImage) {
        result = await this.codeReader.decodeFromImage(img);
      } else if (this.codeReader && this.codeReader.decode) {
        result = await this.codeReader.decode(img);
      }

      if (result) {
        return {
          code: result.getText(),
          format: result.getBarcodeFormat().toString(),
        };
      }
    } catch (error) {
      // Direct method failed, this is normal
    }
    return null;
  }

  private async tryOptimizedCanvasScan(
    img: HTMLImageElement,
    scale = 1,
    useProcessing = false,
    options: {
      contrast?: number;
      brightness?: number;
      threshold?: number;
    } = {}
  ): Promise<BarcodeResult | null> {
    // Create optimized canvas with willReadFrequently flag to suppress warnings
    const canvas = activeDocument.createElement('canvas');
    const ctx = canvas.getContext('2d', {
      willReadFrequently: true, // This fixes the Canvas2D warnings
    });

    if (!ctx) {
      throw new Error('Could not create canvas context');
    }

    const width = Math.floor(img.width * scale);
    const height = Math.floor(img.height * scale);

    canvas.width = width;
    canvas.height = height;

    // Configure canvas for optimal barcode scanning
    ctx.imageSmoothingEnabled = scale !== 1;
    ctx.imageSmoothingQuality = 'high';

    // Draw image to canvas
    ctx.drawImage(img, 0, 0, width, height);

    // Apply image processing if requested
    if (useProcessing) {
      this.applyOptimizedImageProcessing(ctx, width, height, options);
    }

    try {
      let result: ZXingResult | null = null;

      // Try different ZXing decode methods
      if (this.codeReader && this.codeReader.decodeFromCanvas) {
        result = await this.codeReader.decodeFromCanvas(canvas);
      } else if (this.codeReader && this.codeReader.decode) {
        result = await this.codeReader.decode(canvas);
      } else if (this.codeReader && this.codeReader.decodeFromImageData) {
        const imageData = ctx.getImageData(0, 0, width, height);
        result = await this.codeReader.decodeFromImageData(imageData);
      }

      if (result) {
        return {
          code: result.getText(),
          format: result.getBarcodeFormat().toString(),
        };
      }
    } catch (error) {
      // This method didn't work
    }

    return null;
  }

  private applyOptimizedImageProcessing(
    ctx: CanvasRenderingContext2D,
    width: number,
    height: number,
    options: {
      contrast?: number;
      brightness?: number;
      threshold?: number;
    }
  ): void {
    const imageData = ctx.getImageData(0, 0, width, height);
    const data = imageData.data;

    for (let i = 0; i < data.length; i += 4) {
      let r = data[i];
      let g = data[i + 1];
      let b = data[i + 2];

      // Apply brightness
      if (options.brightness && options.brightness !== 1) {
        r = Math.min(255, r * options.brightness);
        g = Math.min(255, g * options.brightness);
        b = Math.min(255, b * options.brightness);
      }

      // Apply contrast
      if (options.contrast && options.contrast !== 1) {
        r = Math.min(255, Math.max(0, (r - 128) * options.contrast + 128));
        g = Math.min(255, Math.max(0, (g - 128) * options.contrast + 128));
        b = Math.min(255, Math.max(0, (b - 128) * options.contrast + 128));
      }

      // Apply threshold (convert to binary)
      if (options.threshold !== undefined) {
        const gray = 0.299 * r + 0.587 * g + 0.114 * b;
        const thresholded = gray > options.threshold ? 255 : 0;
        r = g = b = thresholded;
      }

      data[i] = r;
      data[i + 1] = g;
      data[i + 2] = b;
      // Alpha channel stays the same
    }

    ctx.putImageData(imageData, 0, 0);
  }

  onunload(): void {
    this.stopScanning();
    super.onunload();
  }
}

export class BarcodeScannerModal extends Modal {
  private component: Component;
  private scanner: BarcodeScanner;
  private videoContainer: HTMLElement;
  private controlsContainer: HTMLElement;
  private statusElement: HTMLElement;
  private isScanning = false;
  private cameraButton: HTMLButtonElement;
  private uploadButton: HTMLButtonElement;
  private uploadInput: HTMLInputElement;

  constructor(
    app: App,
    private plugin: MacrosPlugin,
    private onBarcodeScanned: (barcode: string) => void
  ) {
    super(app);
    this.component = new Component();
  }

  onOpen(): void {
    const { contentEl } = this;
    contentEl.addClass('barcode-scanner-modal');

    contentEl.createEl('h2', {
      text: 'Scan Barcode',
      cls: 'barcode-scanner-header',
    });

    if (MobilePermissionHandler.shouldShowPermissionInstructions()) {
      const instructionsEl = contentEl.createDiv({
        cls: 'permission-instructions',
      });
      instructionsEl.createEl('p', {
        text: '­ƒô▒ Camera permission may be required.',
        cls: 'mobile-instruction',
      });
      instructionsEl.createEl('small', {
        text: MobilePermissionHandler.getPermissionInstructions(),
        cls: 'permission-help',
      });
    }

    this.statusElement = contentEl.createDiv({
      cls: 'barcode-scanner-status',
      text: 'Choose a scanning method below',
    });

    this.videoContainer = contentEl.createDiv({
      cls: 'barcode-scanner-video-container',
    });

    this.controlsContainer = contentEl.createDiv({
      cls: 'barcode-scanner-controls',
    });

    this.createControlsWithDiagnostics();
    this.initializeScanner();
  }

  private async createControlsWithDiagnostics(): Promise<void> {
    // Run camera diagnostics first
    const diagnostics = await CameraDiagnostics.checkCameraAvailability();

    if (!diagnostics.hasCamera) {
      // Show error message if no camera detected
      const errorDiv = this.controlsContainer.createDiv({
        cls: 'camera-error-message',
      });
      errorDiv.createEl('p', {
        text: 'ÔÜá´©Å No camera detected',
        cls: 'error-title',
      });
      errorDiv.createEl('p', {
        text: diagnostics.error || 'No cameras found on this device',
        cls: 'error-description',
      });
    } else {
      this.plugin.logger.debug('Camera diagnostics', {
        count: diagnostics.cameras.length,
        cameras: diagnostics.cameras,
      });

      // Test basic camera access
      const accessTest = await CameraDiagnostics.testBasicCameraAccess();

      if (!accessTest.success) {
        const warningDiv = this.controlsContainer.createDiv({
          cls: 'camera-warning-message',
        });
        warningDiv.createEl('p', {
          text: 'ÔÜá´©Å Camera access issue detected',
          cls: 'warning-title',
        });
        warningDiv.createEl('p', {
          text: accessTest.error || 'Camera permission or access issue',
          cls: 'warning-description',
        });

        // Add troubleshooting info
        const troubleshootDiv = warningDiv.createDiv({ cls: 'troubleshooting' });
        troubleshootDiv.createEl('p', { text: 'Troubleshooting steps:' });
        const list = troubleshootDiv.createEl('ul');
        list.createEl('li', { text: 'Check Windows Privacy Settings (Camera permissions)' });
        list.createEl('li', { text: 'Restart Obsidian' });
        list.createEl('li', { text: 'Try using "Upload Image" instead' });
        list.createEl('li', { text: 'Check if other apps can access your camera' });
      }
    }

    // Create the camera button
    this.cameraButton = this.controlsContainer.createEl('button', {
      text: diagnostics.hasCamera ? '­ƒôÀ Start Camera Scan' : '­ƒôÀ Camera Not Available',
      cls: 'mod-cta barcode-scan-camera-btn',
    });

    // Disable camera button if no camera detected
    if (!diagnostics.hasCamera) {
      this.cameraButton.disabled = true;
      this.cameraButton.title = 'No camera detected on this device';
    }

    this.component.registerDomEvent(this.cameraButton, 'click', async () => {
      if (this.isScanning) {
        this.stopCameraScanning();
      } else {
        await this.startCameraScanning();
      }
    });

    // Create other controls
    this.createOtherControls();
  }

  private createOtherControls(): void {
    this.uploadButton = this.controlsContainer.createEl('button', {
      text: '­ƒû╝´©Å Upload Image',
      cls: 'barcode-scan-upload-btn',
    });

    this.uploadInput = activeDocument.createElement('input');
    this.uploadInput.type = 'file';
    this.uploadInput.accept = 'image/*';
    this.uploadInput.capture = 'environment';
    this.uploadInput.style.display = 'none';

    this.component.registerDomEvent(this.uploadButton, 'click', () => {
      this.uploadInput.click();
    });

    this.component.registerDomEvent(this.uploadInput, 'change', async () => {
      const file = this.uploadInput.files?.[0];
      if (file) {
        await this.handleImageUpload(file);
      }
    });

    const manualBtn = this.controlsContainer.createEl('button', {
      text: 'Ô£Å´©Å Enter Manually',
      cls: 'barcode-scan-manual-btn',
    });

    this.component.registerDomEvent(manualBtn, 'click', () => {
      this.showManualEntry();
    });

    const closeBtn = this.controlsContainer.createEl('button', {
      text: 'Cancel',
      cls: 'barcode-scan-close-btn',
    });

    this.component.registerDomEvent(closeBtn, 'click', () => {
      this.close();
    });
  }

  private async initializeScanner(): Promise<void> {
    this.scanner = new BarcodeScanner(
      this.app,
      this.plugin,
      (result) => this.handleBarcodeDetected(result),
      (error) => this.handleScanError(error)
    );
  }

  private async startCameraScanning(): Promise<void> {
    if (this.isScanning) return;

    try {
      this.statusElement.textContent = 'Requesting camera access...';
      this.cameraButton.textContent = 'ÔÅ│ Initializing...';
      this.cameraButton.disabled = true;

      const cameraReady = await this.scanner.initializeCamera();

      if (!cameraReady) {
        this.cameraButton.textContent = '­ƒôÀ Start Camera Scan';
        this.cameraButton.disabled = false;
        return;
      }

      this.videoContainer.empty();

      const video = this.videoContainer.createEl('video', {
        cls: 'barcode-scanner-video',
        attr: {
          autoplay: 'true',
          muted: 'true',
          playsinline: 'true',
        },
      });

      this.statusElement.textContent = 'Point camera at barcode... Hold steady for best results.';

      await this.scanner.startScanning(video);
      this.isScanning = true;

      this.updateControlButtons(true);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.handleScanError(`Camera scanning failed: ${errorMessage}`);
      this.cameraButton.textContent = '­ƒôÀ Start Camera Scan';
      this.cameraButton.disabled = false;
    }
  }

  private stopCameraScanning(): void {
    if (!this.isScanning) return;

    this.scanner.stopScanning();
    this.isScanning = false;
    this.videoContainer.empty();
    this.statusElement.textContent = 'Camera scanning stopped. Choose another method or try again.';
    this.updateControlButtons(false);
  }

  private async handleImageUpload(file: File): Promise<void> {
    try {
      this.statusElement.textContent = `Scanning image: ${file.name}...`;
      this.uploadButton.textContent = 'ÔÅ│ Scanning...';
      this.uploadButton.disabled = true;

      const result = await this.scanner.scanImageFile(file);

      if (result) {
        this.handleBarcodeDetected(result);
      } else {
        this.statusElement.textContent =
          'No barcode found in image. Try a different image or use manual entry.';
      }
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
      this.handleScanError(`Image scan failed: ${errorMessage}`);
    } finally {
      this.uploadButton.textContent = '­ƒû╝´©Å Upload Image';
      this.uploadButton.disabled = false;
      this.uploadInput.value = '';
    }
  }

  private showManualEntry(): void {
    const modal = new ManualBarcodeEntryModal(this.app, (barcode) => {
      this.onBarcodeScanned(barcode);
      this.close();
    });

    modal.open();
    this.close();
  }

  private handleBarcodeDetected(result: BarcodeResult): void {
    this.plugin.logger.debug('Barcode scanned successfully', result);

    const validation = BarcodeUtils.validateBarcode(result.code);
    const displayCode = BarcodeUtils.formatBarcodeForDisplay(result.code);

    let message = `Barcode detected: ${displayCode}`;
    if (validation.format) {
      message += ` (${validation.format})`;
    }

    new Notice(message);

    this.onBarcodeScanned(result.code);
    this.close();
  }

  private handleScanError(error: string): void {
    this.plugin.logger.error('Barcode scan error:', error);
    this.statusElement.textContent = error;
    this.updateControlButtons(false);
  }

  private updateControlButtons(scanning: boolean): void {
    if (scanning) {
      this.cameraButton.textContent = 'ÔÅ╣´©Å Stop Scanning';
      this.cameraButton.disabled = false;
      this.uploadButton.disabled = true;
    } else {
      this.cameraButton.textContent = '­ƒôÀ Start Camera Scan';
      this.cameraButton.disabled = false;
      this.uploadButton.disabled = false;
    }
  }

  onClose(): void {
    if (this.scanner) {
      this.scanner.stopScanning();
      this.scanner.unload();
    }
    this.component.unload();
    this.contentEl.empty();
  }
}

class ManualBarcodeEntryModal extends Modal {
  private component: Component;
  private barcodeInput: HTMLInputElement;

  constructor(
    app: App,
    private onBarcodeEntered: (barcode: string) => void
  ) {
    super(app);
    this.component = new Component();
  }

  onOpen(): void {
    const { contentEl } = this;
    contentEl.addClass('manual-barcode-entry-modal');

    contentEl.createEl('h2', { text: 'Enter Barcode Manually' });

    contentEl.createEl('p', {
      text: 'Enter the numbers from the barcode (EAN/UPC codes are typically 8-13 digits):',
      cls: 'modal-description',
    });

    const inputContainer = contentEl.createDiv({ cls: 'barcode-input-container' });

    this.barcodeInput = inputContainer.createEl('input', {
      type: 'text',
      placeholder: 'e.g., 1234567890123',
      cls: 'barcode-manual-input',
    });

    const buttonContainer = contentEl.createDiv({ cls: 'modal-button-container' });

    const submitBtn = buttonContainer.createEl('button', {
      text: 'Search',
      cls: 'mod-cta',
    });

    const cancelBtn = buttonContainer.createEl('button', {
      text: 'Cancel',
    });

    this.component.registerDomEvent(submitBtn, 'click', () => this.handleSubmit());
    this.component.registerDomEvent(cancelBtn, 'click', () => this.close());
    this.component.registerDomEvent(this.barcodeInput, 'keydown', (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
        this.handleSubmit();
      } else if (e.key === 'Escape') {
        this.close();
      }
    });

    window.setTimeout(() => this.barcodeInput.focus(), 50);
  }

  private handleSubmit(): void {
    const barcode = this.barcodeInput.value.trim();

    if (!barcode) {
      new Notice('Please enter a barcode');
      return;
    }

    const validation = BarcodeUtils.validateBarcode(barcode);

    if (!validation.isValid) {
      new Notice('Please enter a valid barcode (8-14 digits)');
      return;
    }

    if (validation.checksumValid === false) {
      new Notice(`Warning: Barcode has invalid checksum, but searching anyway...`);
    }

    this.onBarcodeEntered(validation.normalizedCode || barcode);
    this.close();
  }

  onClose(): void {
    this.component.unload();
    this.contentEl.empty();
  }
}

// Define proper types for ZXing library components
interface ZXingLibrary {
  BrowserMultiFormatReader?: new () => ZXingCodeReader;
  MultiFormatReader?: new () => ZXingCodeReader;
  BrowserCodeReader?: new () => ZXingCodeReader;
  HTMLCanvasElementLuminanceSource?: new (canvas: HTMLCanvasElement) => unknown;
  BinaryBitmap?: new (binarizer: unknown) => unknown;
  HybridBinarizer?: new (source: unknown) => unknown;
  default?: ZXingLibrary;
}

interface ZXingCodeReader {
  decode?(target: HTMLCanvasElement | ImageData | unknown): Promise<ZXingResult>;
  decodeFromCanvas?(canvas: HTMLCanvasElement): Promise<ZXingResult>;
  decodeFromImageData?(imageData: ImageData): Promise<ZXingResult>;
  decodeFromImageElement?(img: HTMLImageElement): Promise<ZXingResult>;
  decodeFromImage?(img: HTMLImageElement): Promise<ZXingResult>;
  setHints?(hints: Map<string, unknown>): void;
}

interface ZXingResult {
  getText(): string;
  getBarcodeFormat(): { toString(): string };
}

// Extend Window interface for ZXing globals
declare global {
  interface Window {
    ZXing?: ZXingLibrary;
    ZXingLibrary?: ZXingLibrary;
    ZXingBrowser?: ZXingLibrary;
  }
}

export class ZXingLoader {
  private static instance: ZXingLibrary | null = null;
  private static loading: Promise<ZXingLibrary> | null = null;

  static async loadZXing(): Promise<ZXingLibrary> {
    if (this.instance) {
      return this.instance;
    }

    if (this.loading) {
      return this.loading;
    }

    this.loading = this.tryLoadZXing();

    try {
      this.instance = await this.loading;
      return this.instance;
    } finally {
      this.loading = null;
    }
  }

  private static async tryLoadZXing(): Promise<ZXingLibrary> {
    const loadMethods = [
      // Method 1: Try browser-specific import first
      async (): Promise<ZXingLibrary> => {
        const ZXing = await import('@zxing/browser');
        return ZXing as unknown;
      },

      // Method 2: Try ES module import
      async (): Promise<ZXingLibrary> => {
        const ZXing = await import('@zxing/library');
        return ZXing as unknown;
      },

      // Method 3: Try browser-specific CDN with full browser support
      async (): Promise<ZXingLibrary> => {
        return new Promise((resolve, reject) => {
          // Remove any existing script first
          const existingScript = activeDocument.querySelector('script[src*="zxing"]');
          if (existingScript) {
            existingScript.remove();
          }

          const script = activeDocument.createElement('script');
          script.src = 'https://unpkg.com/@zxing/browser@0.1.1/lib/index.min.js';
          script.onload = () => {
            // Check multiple possible global names
            const ZXing = window.ZXingBrowser || window.ZXing || window.ZXingLibrary;
            if (ZXing) {
              resolve(ZXing);
            } else {
              reject(new Error('ZXing browser not found on window after CDN load'));
            }
          };
          script.onerror = (_error) => {
            reject(new Error('Failed to load ZXing browser from CDN'));
          };
          activeDocument.head.appendChild(script);
        });
      },

      // Method 4: Try CDN import with specific version
      async (): Promise<ZXingLibrary> => {
        return new Promise((resolve, reject) => {
          // Remove any existing script first
          const existingScript = activeDocument.querySelector('script[src*="zxing"]');
          if (existingScript) {
            existingScript.remove();
          }

          const script = activeDocument.createElement('script');
          script.src = 'https://unpkg.com/@zxing/library@0.20.0/umd/index.min.js';
          script.onload = () => {
            // Check multiple possible global names
            const ZXing = window.ZXing || window.ZXingLibrary || window.ZXingBrowser;
            if (ZXing) {
              resolve(ZXing);
            } else {
              reject(new Error('ZXing not found on window after CDN load'));
            }
          };
          script.onerror = (_error) => {
            reject(new Error('Failed to load ZXing from CDN'));
          };
          activeDocument.head.appendChild(script);
        });
      },

      // Method 5: Try alternative CDN
      async (): Promise<ZXingLibrary> => {
        return new Promise((resolve, reject) => {
          const script = activeDocument.createElement('script');
          script.src = 'https://cdn.jsdelivr.net/npm/@zxing/library@0.20.0/umd/index.min.js';
          script.onload = () => {
            const ZXing = window.ZXing || window.ZXingLibrary;
            if (ZXing) {
              resolve(ZXing);
            } else {
              reject(new Error('ZXing not found after jsdelivr load'));
            }
          };
          script.onerror = () => reject(new Error('Failed to load ZXing from jsdelivr'));
          activeDocument.head.appendChild(script);
        });
      },
    ];

    let lastError: Error | null = null;

    for (const loadMethod of loadMethods) {
      try {
        const ZXing = await loadMethod();
        return ZXing;
      } catch (error) {
        lastError = error as Error;
      }
    }

    throw new Error(`Failed to load ZXing library. Last error: ${lastError?.message}`);
  }

  static async createCodeReader(): Promise<ZXingCodeReader> {
    const ZXing = await this.loadZXing();

    // Try different reader constructors with proper TypeScript syntax
    const readerConstructors = [
      (): ZXingCodeReader | null => {
        if (ZXing.BrowserMultiFormatReader) {
          return new ZXing.BrowserMultiFormatReader();
        }
        return null;
      },
      (): ZXingCodeReader | null => {
        if (ZXing.default && ZXing.default.BrowserMultiFormatReader) {
          return new ZXing.default.BrowserMultiFormatReader();
        }
        return null;
      },
      (): ZXingCodeReader | null => {
        // Try browser-specific reader from different import path
        if (ZXing.BrowserCodeReader) {
          return new ZXing.BrowserCodeReader();
        }
        return null;
      },
      (): ZXingCodeReader | null => {
        if (ZXing.MultiFormatReader) {
          const reader = new ZXing.MultiFormatReader();
          // Wrap it with browser-specific methods if needed
          return this.wrapReaderWithBrowserMethods(reader, ZXing);
        }
        return null;
      },
      (): ZXingCodeReader | null => {
        if (ZXing.default && ZXing.default.MultiFormatReader) {
          const reader = new ZXing.default.MultiFormatReader();
          return this.wrapReaderWithBrowserMethods(reader, ZXing.default || ZXing);
        }
        return null;
      },
    ];

    for (const constructor of readerConstructors) {
      try {
        const reader = constructor();
        if (reader) {
          return reader;
        }
      } catch (error) {
        // Continue to next constructor
      }
    }

    throw new Error('Could not create any code reader from ZXing library');
  }

  private static wrapReaderWithBrowserMethods(
    reader: ZXingCodeReader,
    ZXing: ZXingLibrary
  ): ZXingCodeReader {
    // If we get a basic MultiFormatReader, add browser-specific decode methods
    if (!reader.decodeFromCanvas && !reader.decodeFromImageData) {
      // Add decodeFromCanvas method
      reader.decodeFromCanvas = async function (canvas: HTMLCanvasElement): Promise<ZXingResult> {
        const ctx = canvas.getContext('2d');
        if (!ctx) throw new Error('Cannot get canvas context');

        const _imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

        if (
          !ZXing.HTMLCanvasElementLuminanceSource ||
          !ZXing.BinaryBitmap ||
          !ZXing.HybridBinarizer
        ) {
          throw new Error('Required ZXing components not available');
        }

        const luminanceSource = new ZXing.HTMLCanvasElementLuminanceSource(canvas);
        const binaryBitmap = new ZXing.BinaryBitmap(new ZXing.HybridBinarizer(luminanceSource));

        if (!reader.decode) {
          throw new Error('Decode method not available on reader');
        }

        return reader.decode(binaryBitmap);
      };

      // Add decodeFromImageData method
      reader.decodeFromImageData = async function (imageData: ImageData): Promise<ZXingResult> {
        const canvas = activeDocument.createElement('canvas');
        canvas.width = imageData.width;
        canvas.height = imageData.height;
        const ctx = canvas.getContext('2d');
        if (!ctx) throw new Error('Cannot create canvas context');

        ctx.putImageData(imageData, 0, 0);

        if (!reader.decodeFromCanvas) {
          throw new Error('decodeFromCanvas method not available');
        }

        return reader.decodeFromCanvas(canvas);
      };

      // Add decodeFromImageElement method
      reader.decodeFromImageElement = async function (img: HTMLImageElement): Promise<ZXingResult> {
        const canvas = activeDocument.createElement('canvas');
        canvas.width = img.width || img.naturalWidth;
        canvas.height = img.height || img.naturalHeight;
        const ctx = canvas.getContext('2d');
        if (!ctx) throw new Error('Cannot create canvas context');

        ctx.drawImage(img, 0, 0);

        if (!reader.decodeFromCanvas) {
          throw new Error('decodeFromCanvas method not available');
        }

        return reader.decodeFromCanvas(canvas);
      };
    }

    return reader;
  }
}

export class BarcodeUtils {
  static validateBarcode(barcode: string): {
    isValid: boolean;
    format?: string;
    checksumValid?: boolean;
    normalizedCode?: string;
  } {
    const cleaned = barcode.replace(/[\s-]/g, '');

    if (!/^\d+$/.test(cleaned)) {
      return { isValid: false };
    }

    if (cleaned.length === 13) {
      return {
        isValid: true,
        format: 'EAN-13',
        checksumValid: this.validateEan13Checksum(cleaned),
        normalizedCode: cleaned,
      };
    } else if (cleaned.length === 12) {
      return {
        isValid: true,
        format: 'UPC-A',
        checksumValid: this.validateUpcAChecksum(cleaned),
        normalizedCode: cleaned,
      };
    } else if (cleaned.length === 8) {
      return {
        isValid: true,
        format: 'EAN-8',
        checksumValid: this.validateEan8Checksum(cleaned),
        normalizedCode: cleaned,
      };
    } else if (cleaned.length >= 6 && cleaned.length <= 18) {
      return {
        isValid: true,
        format: 'Code-128',
        checksumValid: true,
        normalizedCode: cleaned,
      };
    }

    return { isValid: false };
  }

  private static validateEan13Checksum(ean: string): boolean {
    if (ean.length !== 13) return false;

    let sum = 0;
    for (let i = 0; i < 12; i++) {
      const digit = parseInt(ean[i]);
      sum += i % 2 === 0 ? digit : digit * 3;
    }

    const checksum = (10 - (sum % 10)) % 10;
    return checksum === parseInt(ean[12]);
  }

  private static validateUpcAChecksum(upc: string): boolean {
    if (upc.length !== 12) return false;

    let sum = 0;
    for (let i = 0; i < 11; i++) {
      const digit = parseInt(upc[i]);
      sum += i % 2 === 0 ? digit * 3 : digit;
    }

    const checksum = (10 - (sum % 10)) % 10;
    return checksum === parseInt(upc[11]);
  }

  private static validateEan8Checksum(ean: string): boolean {
    if (ean.length !== 8) return false;

    let sum = 0;
    for (let i = 0; i < 7; i++) {
      const digit = parseInt(ean[i]);
      sum += i % 2 === 0 ? digit * 3 : digit;
    }

    const checksum = (10 - (sum % 10)) % 10;
    return checksum === parseInt(ean[7]);
  }

  static formatBarcodeForDisplay(barcode: string): string {
    const validation = this.validateBarcode(barcode);

    if (!validation.isValid || !validation.normalizedCode) {
      return barcode;
    }

    const code = validation.normalizedCode;

    switch (validation.format) {
      case 'EAN-13':
        return `${code.slice(0, 1)} ${code.slice(1, 7)} ${code.slice(7)}`;
      case 'UPC-A':
        return `${code.slice(0, 6)} ${code.slice(6)}`;
      case 'EAN-8':
        return `${code.slice(0, 4)} ${code.slice(4)}`;
      default:
        return code;
    }
  }
}

export class CameraDiagnostics {
  static async checkCameraAvailability(): Promise<{
    hasCamera: boolean;
    cameras: MediaDeviceInfo[];
    error?: string;
  }> {
    try {
      // Check if mediaDevices is supported
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
        return {
          hasCamera: false,
          cameras: [],
          error: 'Media devices API not supported in this environment',
        };
      }

      // Get list of available devices
      const devices = await navigator.mediaDevices.enumerateDevices();
      const cameras = devices.filter((device) => device.kind === 'videoinput');

      return {
        hasCamera: cameras.length > 0,
        cameras: cameras,
        error: cameras.length === 0 ? 'No cameras detected on this device' : undefined,
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      return {
        hasCamera: false,
        cameras: [],
        error: `Failed to check camera availability: ${errorMessage}`,
      };
    }
  }

  static async testBasicCameraAccess(): Promise<{
    success: boolean;
    error?: string;
  }> {
    try {
      // Try the most basic camera request
      const stream = await navigator.mediaDevices.getUserMedia({
        video: {
          width: { ideal: 640 },
          height: { ideal: 480 },
        },
      });

      // Immediately stop the stream since this is just a test
      stream.getTracks().forEach((track) => track.stop());

      return { success: true };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      return {
        success: false,
        error: errorMessage,
      };
    }
  }
}

export class MobilePermissionHandler {
  static async requestCameraPermission(): Promise<{
    granted: boolean;
    stream?: MediaStream;
    error?: string;
  }> {
    try {
      const isMobile = /Android|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
        navigator.userAgent
      );
      const isDesktop = !isMobile;

      // Check if we're in Obsidian desktop environment
      const isObsidianDesktop =
        !!(window as Window & { require?: unknown }).require ||
        navigator.userAgent.includes('Electron');

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: isMobile ? 'environment' : 'user', // Use front camera on desktop
          width: { ideal: 1280, max: 1920 },
          height: { ideal: 720, max: 1080 },
        },
      };

      // For desktop/Obsidian, try simpler constraints first
      if (isDesktop || isObsidianDesktop) {
        // Try basic video constraints first
        try {
          const basicConstraints = { video: true };
          const stream = await navigator.mediaDevices.getUserMedia(basicConstraints);
          return { granted: true, stream };
        } catch (basicError: unknown) {
          // Try with even more basic constraints
          try {
            const minimalConstraints = {
              video: {
                width: { ideal: 320 },
                height: { ideal: 240 },
              },
            };
            const stream = await navigator.mediaDevices.getUserMedia(minimalConstraints);
            return { granted: true, stream };
          } catch (_minimalError: unknown) {
            // Fall through to error handling
            throw basicError; // Use the original error for better debugging
          }
        }
      }

      // Check permissions API if available (mainly for browsers)
      if (navigator.permissions && !isObsidianDesktop) {
        try {
          const permission = await navigator.permissions.query({
            name: 'camera',
          });

          if (permission.state === 'denied') {
            return {
              granted: false,
              error:
                'Camera permission was previously denied. Please reset permissions or enable camera access in your browser/system settings.',
            };
          }
        } catch (_permError) {
          // Permission query not supported or failed - continue anyway
        }
      }

      // Try to get camera stream with full constraints
      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      return {
        granted: true,
        stream,
      };
    } catch (error: unknown) {
      let errorMessage = '';
      const err = error as { name?: string; message?: string };

      switch (err.name) {
        case 'NotAllowedError':
          errorMessage = this.getDesktopPermissionError();
          break;
        case 'NotFoundError':
          errorMessage =
            'No camera found on this device. Please ensure a camera is connected and functioning.';
          break;
        case 'NotReadableError':
          errorMessage =
            'Camera is already in use by another application. Please close other apps using the camera and try again.';
          break;
        case 'OverconstrainedError':
          errorMessage =
            'Camera constraints could not be satisfied. Try using a different camera or check camera settings.';
          break;
        case 'SecurityError':
          errorMessage =
            "Camera access blocked due to security restrictions. This may be due to Obsidian's security settings.";
          break;
        case 'AbortError':
          errorMessage = 'Camera access was aborted.';
          break;
        default:
          errorMessage = `Camera access failed: ${err.message || 'Unknown error'}. This might be due to Obsidian's security restrictions.`;
      }

      return {
        granted: false,
        error: errorMessage,
      };
    }
  }

  private static getDesktopPermissionError(): string {
    const isObsidianDesktop =
      !!(window as Window & { require?: unknown }).require ||
      navigator.userAgent.includes('Electron');

    if (isObsidianDesktop) {
      return `Camera permission denied in Obsidian. Possible solutions:

1. Check Windows camera privacy settings:
   - Go to Windows Settings > Privacy & Security > Camera
   - Ensure "Camera access" is turned on
   - Ensure "Let apps access your camera" is turned on

2. Restart Obsidian completely and try again

3. Try the "Upload Image" option instead

4. Check if other apps (like Camera app) can access your camera

5. If using antivirus software, check if it's blocking camera access`;
    } else {
      return `Camera permission denied. Please:
1. Check browser camera permissions
2. Ensure you're using HTTPS
3. Check system camera privacy settings`;
    }
  }

  static shouldShowPermissionInstructions(): boolean {
    const isMobile = /Android|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
      navigator.userAgent
    );
    const isObsidianDesktop =
      !!(window as Window & { require?: unknown }).require ||
      navigator.userAgent.includes('Electron');

    return isMobile || isObsidianDesktop;
  }

  static getPermissionInstructions(): string {
    const isIOS = /iPhone|iPad|iPod/i.test(navigator.userAgent);
    const isAndroid = /Android/i.test(navigator.userAgent);
    const isObsidianDesktop =
      !!(window as Window & { require?: unknown }).require ||
      navigator.userAgent.includes('Electron');

    if (isObsidianDesktop) {
      return `­ƒô▒ Desktop: Check Windows camera settings (Settings > Privacy & Security > Camera) and ensure camera access is enabled for apps.`;
    } else if (isIOS) {
      return 'On iOS: Tap the "AA" icon in Safari address bar ÔåÆ Website Settings ÔåÆ Camera ÔåÆ Allow';
    } else if (isAndroid) {
      return 'On Android: Tap the camera icon in the address bar or go to browser Settings ÔåÆ Site permissions ÔåÆ Camera';
    } else {
      return 'Please allow camera access when prompted by your browser.';
    }
  }
}

/**
 * ChartLoader Utility
 * Handles bundled Chart.js library management
 */
import type { Chart } from 'chart.js';
import { Chart as ChartJS, registerables } from 'chart.js';

export class ChartLoader {
  private static instance: ChartLoader;
  private loadPromise: Promise<typeof Chart> | null = null;
  private chartInstances: Map<string, Chart> = new Map();
  private initialized = false;

  public static getInstance(): ChartLoader {
    if (!ChartLoader.instance) {
      ChartLoader.instance = new ChartLoader();
    }
    return ChartLoader.instance;
  }

  public async loadChart(): Promise<typeof Chart> {
    // If we have a cached promise, return it
    if (this.loadPromise) return this.loadPromise;

    // Create a new promise for loading
    this.loadPromise = new Promise<typeof Chart>((resolve) => {
      // Initialize Chart.js if not already done
      if (!this.initialized) {
        // Register all Chart.js components
        ChartJS.register(...registerables);

        // Make ChartJS available on window for backward compatibility
        (window as Window & { Chart: typeof ChartJS }).Chart = ChartJS;

        this.initialized = true;
      }

      // Resolve with the imported Chart
      resolve(ChartJS);
    });

    return this.loadPromise;
  }

  public registerChart(id: string, chart: Chart): void {
    this.destroyChart(id);
    this.chartInstances.set(id, chart);
  }

  public destroyChart(id: string): void {
    const chart = this.chartInstances.get(id);
    if (chart) {
      chart.destroy();
      this.chartInstances.delete(id);
    }
  }

  public destroyAllCharts(): void {
    this.chartInstances.forEach((chart) => chart.destroy());
    this.chartInstances.clear();
  }
}

// ensureChartJsLoaded function is now solely in charts/index.ts
export async function ensureChartJsLoaded(): Promise<void> {
  await ChartLoader.getInstance().loadChart();
}

import type MacrosPlugin from '../main';

/**
 * Unified State Manager that stores UI state inside plugin settings (data.json)
 */
export class MacrosState {
  private plugin: MacrosPlugin;
  private pluginId: string;
  private stateType: string;
  private id: string;

  constructor(plugin: MacrosPlugin, id: string, stateType: string) {
    this.plugin = plugin;
    this.id = id;
    this.stateType = stateType;
    this.pluginId = plugin.manifest.id;
  }

  private getKey(sectionName: string): string {
    return `${this.pluginId}:${this.stateType}:${this.id}:${sectionName}`;
  }

  /** Save collapsed/expanded state to plugin settings */
  saveCollapsedState(sectionName: string, isCollapsed: boolean): void {
    const key = this.getKey(sectionName);
    if (!this.plugin.settings.uiCollapseStates) {
      this.plugin.settings.uiCollapseStates = {};
    }
    this.plugin.settings.uiCollapseStates[key] = isCollapsed;
    this.plugin.saveSettings();
  }

  /** Load collapsed/expanded state from plugin settings */
  getCollapsedState(sectionName: string): boolean {
    const key = this.getKey(sectionName);
    return this.plugin.settings.uiCollapseStates?.[key] ?? false;
  }

  /** Clear all states for this component */
  clearState(): void {
    const prefix = `${this.pluginId}:${this.stateType}:${this.id}:`;
    const states = this.plugin.settings.uiCollapseStates ?? {};
    for (const key of Object.keys(states)) {
      if (key.startsWith(prefix)) {
        delete states[key];
      }
    }
    this.plugin.saveSettings();
  }

  /** Clear all states for the entire plugin */
  static clearAllStates(plugin: MacrosPlugin): void {
    const prefix = `${plugin.manifest.id}:`;
    const states = plugin.settings.uiCollapseStates ?? {};
    for (const key of Object.keys(states)) {
      if (key.startsWith(prefix)) {
        delete states[key];
      }
    }
    plugin.saveSettings();
  }

  /**
   * Static convenience methods for chart state management
   * These replace the MacrosPCState functionality
   */

  static getChartCollapsedState(chartId: string, plugin: MacrosPlugin): boolean {
    const stateManager = new MacrosState(plugin, chartId, 'chart');
    return stateManager.getCollapsedState('dashboard');
  }

  static saveChartCollapsedState(
    chartId: string,
    plugin: MacrosPlugin,
    isCollapsed: boolean
  ): void {
    const stateManager = new MacrosState(plugin, chartId, 'chart');
    stateManager.saveCollapsedState('dashboard', isCollapsed);
  }
}

import { DOMUtils } from './DOMUtils';
import MacrosPlugin from '@/main';

// Global tooltip element and tracking variables
let tooltipEl: HTMLDivElement | null = null;
let mutationObserver: MutationObserver | null = null;
let pluginInstance: MacrosPlugin | null = null;
let isMobileDevice = false;

// Simplified mobile detection
function detectMobileDevice(): boolean {
  return window.innerWidth <= 768 || 'ontouchstart' in window;
}

function ensureTooltipEl(): HTMLDivElement {
  if (!tooltipEl) {
    tooltipEl = activeDocument.createElement('div');
    tooltipEl.className = 'macro-tooltip macro-tooltip-hidden';
    tooltipEl.setAttribute('style', '--x: -9999px; --y: -9999px;');
    activeDocument.body.appendChild(tooltipEl);
  }
  return tooltipEl;
}

export class TooltipManager {
  // Simple state tracking
  private static isActive = false;
  private static activeTarget: HTMLElement | null = null;
  private static activeContent = '';

  // Single timer for delayed operations
  private static timer: number | null = null;
  private static mobileHideTimer: number | null = null;

  // Simplified constants
  private static readonly SHOW_DELAY = 100;
  private static readonly HIDE_DELAY = 200;

  static initGlobalTooltipSystem(plugin: MacrosPlugin): void {
    // Store plugin instance for later use
    pluginInstance = plugin;

    // Update mobile detection on resize
    isMobileDevice = detectMobileDevice();

    const tooltip = ensureTooltipEl();

    // Desktop hover behavior
    plugin.registerDomEvent(tooltip, 'mouseenter', () => {
      if (!isMobileDevice) {
        tooltip.classList.add('tooltip-visible');
      }
    });

    plugin.registerDomEvent(tooltip, 'mouseleave', () => {
      if (!isMobileDevice) {
        TooltipManager.hide();
      }
    });

    // Global event listeners
    plugin.registerDomEvent(activeDocument, 'visibilitychange', () => {
      if (activeDocument.hidden) TooltipManager.forceHide();
    });

    plugin.registerDomEvent(window, 'resize', () => {
      TooltipManager.forceHide();
      isMobileDevice = detectMobileDevice();
    });

    plugin.registerDomEvent(window, 'beforeunload', () => {
      TooltipManager.forceHide();
    });

    // Mobile: Hide tooltip when scrolling
    plugin.registerDomEvent(
      window,
      'scroll',
      () => {
        if (isMobileDevice) {
          TooltipManager.forceHide();
        }
      },
      { passive: true }
    );

    // DOM mutation observer
    if (mutationObserver) {
      mutationObserver.disconnect();
    }

    mutationObserver = new MutationObserver(() => {
      TooltipManager.forceHide();
    });

    const root = activeDocument.querySelector('.workspace') || activeDocument.body;
    mutationObserver.observe(root, { childList: true, subtree: true });
  }

  static cleanup(): void {
    if (mutationObserver) {
      mutationObserver.disconnect();
      mutationObserver = null;
    }

    if (TooltipManager.timer !== null) {
      window.clearTimeout(TooltipManager.timer);
      TooltipManager.timer = null;
    }

    if (TooltipManager.mobileHideTimer !== null) {
      window.clearTimeout(TooltipManager.mobileHideTimer);
      TooltipManager.mobileHideTimer = null;
    }

    if (tooltipEl && tooltipEl.parentNode) {
      tooltipEl.parentNode.removeChild(tooltipEl);
      tooltipEl = null;
    }

    TooltipManager.isActive = false;
    TooltipManager.activeTarget = null;
    TooltipManager.activeContent = '';
    pluginInstance = null;
  }

  static show(targetEl: HTMLElement, text: string): void {
    // Clear any existing timers
    if (TooltipManager.timer !== null) {
      window.clearTimeout(TooltipManager.timer);
      TooltipManager.timer = null;
    }

    if (TooltipManager.mobileHideTimer !== null) {
      window.clearTimeout(TooltipManager.mobileHideTimer);
      TooltipManager.mobileHideTimer = null;
    }

    TooltipManager.activeTarget = targetEl;
    TooltipManager.activeContent = text;

    // Show immediately on mobile, with delay on desktop
    const delay = isMobileDevice ? 0 : TooltipManager.SHOW_DELAY;

    TooltipManager.timer = window.setTimeout(() => {
      TooltipManager.displayTooltip();
      TooltipManager.timer = null;
    }, delay);
  }

  private static displayTooltip(): void {
    if (!TooltipManager.activeTarget || !TooltipManager.activeContent) return;

    const el = ensureTooltipEl();
    const targetEl = TooltipManager.activeTarget;

    // Reset classes
    el.classList.remove('tooltip-visible');
    el.classList.add('macro-tooltip-hidden');

    // Set content
    el.textContent = TooltipManager.activeContent;

    // Position tooltip
    const rect = targetEl.getBoundingClientRect();
    let x = rect.left + rect.width / 2 + window.scrollX;
    let y = rect.bottom + 12 + window.scrollY;

    // Mobile positioning adjustments
    if (isMobileDevice) {
      el.classList.add('macro-tooltip-mobile');

      // Position near the bottom of the Obsidian app, but above the toolbar
      const obsidianApp = activeDocument.querySelector('.app-container') || activeDocument.body;
      const appRect = obsidianApp.getBoundingClientRect();

      // Set Y position to be above the bottom toolbar (more clearance)
      const bottomOffset = 120; // Increased distance from bottom to avoid toolbar
      y = appRect.bottom - bottomOffset + window.scrollY;

      // Center horizontally in the app
      x = appRect.left + appRect.width / 2 + window.scrollX;

      // Keep within viewport horizontally
      const tooltipWidth = 240;
      if (x + tooltipWidth / 2 > window.innerWidth - 10) {
        x = window.innerWidth - tooltipWidth / 2 - 10;
      }
      if (x - tooltipWidth / 2 < 10) {
        x = tooltipWidth / 2 + 10;
      }

      // Ensure it doesn't go below the viewport
      if (y + 40 > window.innerHeight + window.scrollY) {
        y = window.innerHeight + window.scrollY - 50;
      }
    } else {
      el.classList.remove('macro-tooltip-mobile');
    }

    // Set position
    DOMUtils.setCSSProperty(el, '--x', `${x}px`);
    DOMUtils.setCSSProperty(el, '--y', `${y}px`);

    // Show tooltip
    el.classList.remove('macro-tooltip-hidden');
    el.classList.add('macro-tooltip-positioned');

    // Force reflow
    void el.offsetWidth;

    el.classList.add('tooltip-visible');
    TooltipManager.isActive = true;

    // Auto-hide on mobile after 3 seconds
    if (isMobileDevice) {
      TooltipManager.mobileHideTimer = window.setTimeout(() => {
        TooltipManager.forceHide();
      }, 3000);
    }
  }

  static hide(): void {
    if (TooltipManager.timer !== null) {
      window.clearTimeout(TooltipManager.timer);
      TooltipManager.timer = null;
    }

    if (!TooltipManager.isActive) return;

    // Hide immediately on mobile
    const hideDelay = isMobileDevice ? 0 : TooltipManager.HIDE_DELAY;

    TooltipManager.timer = window.setTimeout(() => {
      TooltipManager.hideTooltip();
      TooltipManager.timer = null;
    }, hideDelay);
  }

  private static hideTooltip(): void {
    const el = ensureTooltipEl();

    el.classList.remove('tooltip-visible');

    window.setTimeout(() => {
      if (!el.classList.contains('tooltip-visible')) {
        el.classList.add('macro-tooltip-hidden');
        el.classList.remove('macro-tooltip-positioned');
        el.classList.remove('macro-tooltip-mobile');
        DOMUtils.setCSSProperty(el, '--x', `-9999px`);
        DOMUtils.setCSSProperty(el, '--y', `-9999px`);
        el.textContent = '';

        TooltipManager.isActive = false;
        TooltipManager.activeTarget = null;
        TooltipManager.activeContent = '';
      }
    }, 150);
  }

  static forceHide(): void {
    if (TooltipManager.timer !== null) {
      window.clearTimeout(TooltipManager.timer);
      TooltipManager.timer = null;
    }

    if (TooltipManager.mobileHideTimer !== null) {
      window.clearTimeout(TooltipManager.mobileHideTimer);
      TooltipManager.mobileHideTimer = null;
    }

    const el = tooltipEl;
    if (el) {
      el.classList.remove('tooltip-visible');
      el.classList.remove('macro-tooltip-mobile');
      el.classList.add('macro-tooltip-hidden');
      el.classList.remove('macro-tooltip-positioned');

      DOMUtils.setCSSProperty(el, '--x', `-9999px`);
      DOMUtils.setCSSProperty(el, '--y', `-9999px`);
      el.textContent = '';
    }

    TooltipManager.isActive = false;
    TooltipManager.activeTarget = null;
    TooltipManager.activeContent = '';
  }
}

// Simplified attachment functions
export function attachTooltip(targetEl: HTMLElement, tooltipContent: string): void {
  if (!pluginInstance) return;

  if (isMobileDevice) {
    // Simple tap to show on mobile
    pluginInstance.registerDomEvent(targetEl, 'click', (e: Event) => {
      e.preventDefault();
      e.stopPropagation();
      TooltipManager.show(targetEl, tooltipContent);
    });
  } else {
    // Hover on desktop
    pluginInstance.registerDomEvent(targetEl, 'pointerenter', () => {
      TooltipManager.show(targetEl, tooltipContent);
    });

    pluginInstance.registerDomEvent(targetEl, 'pointerleave', () => {
      TooltipManager.hide();
    });
  }
}

export function attachLazyTooltip(targetEl: HTMLElement, tooltipContent: string): void {
  attachTooltip(targetEl, tooltipContent);
}

export function safeAttachTooltip(
  targetEl: HTMLElement,
  tooltipContent: string,
  plugin: MacrosPlugin
): void {
  if (!pluginInstance) {
    pluginInstance = plugin;
    isMobileDevice = detectMobileDevice();
  }

  if (plugin.settings.disableTooltips) {
    return;
  }
  attachTooltip(targetEl, tooltipContent);
}

/**
 * Nutrition Utilities
 * ------------------
 * Helper functions specific to nutritional calculations and processing.
 */

import { App, TFile } from 'obsidian';
import { parseGrams } from './parsingUtils';

/**
 * Interface for nutrition data
 */
export interface NutritionData {
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
  name?: string;
  serving?: string;
  macroLine?: string;
}

/**
 * Interface for macro row data
 */
export interface MacroRow {
  name: string;
  serving: string;
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
  macroLine: string;
}

/**
 * Extracts the serving size from a food description
 * @param description The food description text
 * @returns The extracted serving size or "Unknown"
 */
export function extractServingSize(description: string): string {
  try {
    const regex = /Per\s*(\d+(\.\d+)?)\s*(g|medium|large|slice|cup|tbsp|oz)/i;
    const match = description.match(regex);
    return match ? `${match[1]}${match[3]}` : 'Unknown';
  } catch (error) {
    console.error('Error extracting serving size:', error);
    return 'Unknown';
  }
}

/**
 * Extracts nutritional data from a food description
 * @param description The food description text
 * @returns Object with extracted nutritional values
 */
export function extractNutritionalData(description: string): {
  calories: string;
  fat: string;
  carbs: string;
  protein: string;
} {
  try {
    const caloriesMatch = description.match(/Calories:\s*(\d+(\.\d+)?)kcal/i);
    const fatMatch = description.match(/Fat:\s*(\d+(\.\d+)?)g/i);
    const carbsMatch = description.match(/Carbs:\s*(\d+(\.\d+)?)g/i);
    const proteinMatch = description.match(/Protein:\s*(\d+(\.\d+)?)g/i);
    return {
      calories: caloriesMatch ? caloriesMatch[1] : 'N/A',
      fat: fatMatch ? fatMatch[1] : 'N/A',
      carbs: carbsMatch ? carbsMatch[1] : 'N/A',
      protein: proteinMatch ? proteinMatch[1] : 'N/A',
    };
  } catch (error) {
    console.error('Error extracting nutritional data:', error);
    return { calories: 'N/A', fat: 'N/A', carbs: 'N/A', protein: 'N/A' };
  }
}

/**
 * Processes nutritional data from a food file
 * @param app The Obsidian App instance
 * @param foodFile The food file to process
 * @param specifiedQuantity Optional quantity override
 * @returns Processed nutrition data or null if processing fails
 */
export function processNutritionalData(
  app: App,
  foodFile: TFile,
  specifiedQuantity: number | null = null
): NutritionData | null {
  const metadataCache = app.metadataCache;
  if (!metadataCache) return null;

  const cache = metadataCache.getFileCache(foodFile);
  if (!cache || !cache.frontmatter) return null;

  const fm = cache.frontmatter as Record<string, unknown>;
  // Coerce to string: YAML may parse `serving_size: 100` as a number, and a
  // runtime number would throw on `.toLowerCase()`.
  const storedServing = fm['serving_size'] != null ? String(fm['serving_size']) : '';
  if (!storedServing.toLowerCase().includes('g')) return null;

  const storedServingGrams = parseGrams(storedServing);
  if (isNaN(storedServingGrams)) return null;

  const quantity =
    specifiedQuantity != null && !isNaN(specifiedQuantity) ? specifiedQuantity : storedServingGrams;
  const scale = quantity / storedServingGrams;

  const cal = parseFloat(fm['calories'] as string) || 0;
  const prot = parseFloat(fm['protein'] as string) || 0;
  const fat = parseFloat(fm['fat'] as string) || 0;
  const carbs = parseFloat(fm['carbs'] as string) || 0;

  return {
    name: foodFile.name.replace(/\.md$/, ''),
    serving: `${quantity}g`,
    calories: cal * scale,
    protein: parseFloat((prot * scale).toFixed(1)),
    fat: parseFloat((fat * scale).toFixed(1)),
    carbs: parseFloat((carbs * scale).toFixed(1)),
  };
}

/**
 * Merges macro lines into unique entries
 * SIMPLIFIED: No multiplier logic, direct quantity merging
 * @param lines Array of macro lines
 * @returns Merged array of lines
 */
export function mergeMacroLines(lines: string[]): string[] {
  // Group items by meal and individual items
  const mealStructure = new Map<string, Map<string, number>>();
  const individualItems = new Map<string, number>();

  let currentMeal: string | null = null;

  lines.forEach((line) => {
    if (line.toLowerCase().startsWith('meal:')) {
      // SIMPLIFIED: Just extract meal name, no multiplier parsing
      currentMeal = line.substring(5).trim();

      if (!mealStructure.has(currentMeal)) {
        mealStructure.set(currentMeal, new Map());
      }
    } else if (line.startsWith('-') && currentMeal) {
      // Bullet point under a meal
      const itemText = line.substring(1).trim();
      const { foodName, quantity } = parseItemText(itemText);

      if (foodName) {
        const mealItems = mealStructure.get(currentMeal);
        if (mealItems) {
          const existingQuantity = mealItems.get(foodName) || 0;
          mealItems.set(foodName, existingQuantity + quantity);
        }
      }
    } else if (!line.startsWith('-')) {
      // Individual food item (not under a meal)
      currentMeal = null;
      const { foodName, quantity } = parseItemText(line);

      if (foodName) {
        const existingQuantity = individualItems.get(foodName) || 0;
        individualItems.set(foodName, existingQuantity + quantity);
      }
    }
  });

  // Build output
  const output: string[] = [];

  // Add meals
  for (const [mealName, mealItems] of mealStructure) {
    output.push(`meal:${mealName}`);

    for (const [foodName, quantity] of mealItems) {
      output.push(`- ${foodName}:${quantity}g`);
    }
  }

  // Add individual items
  for (const [foodName, quantity] of individualItems) {
    output.push(`${foodName}:${quantity}g`);
  }

  return output;
}

/**
 * Parse item text to extract food name and quantity
 * HELPER: Common logic for parsing food items
 */
function parseItemText(itemText: string): { foodName: string; quantity: number } {
  if (itemText.includes(':')) {
    const parts = itemText.split(':').map((s) => s.trim());
    const foodName = parts[0];
    const quantityMatch = parts[1].match(/^([\d.]+)g?$/i);
    const quantity = quantityMatch ? parseFloat(quantityMatch[1]) : 100;

    return { foodName, quantity };
  } else {
    // No quantity specified, assume 100g default
    return { foodName: itemText.trim(), quantity: 100 };
  }
}

import { App, TFile } from 'obsidian';
import { parseGrams } from '../parsing';

/**
 * Interface for nutrition data
 */
export interface NutritionData {
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
  name?: string;
  serving?: string;
  macroLine?: string;
}

/**
 * Interface for macro row data
 */
export interface MacroRow {
  name: string;
  serving: string;
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
  macroLine: string;
}

/**
 * Process nutritional data from a food file
 * @param app Obsidian app instance
 * @param foodFile The food file to process
 * @param specifiedQuantity Optional quantity override
 * @returns Processed nutrition data or null if processing fails
 */
export function processNutritionalData(
  app: App,
  foodFile: TFile,
  specifiedQuantity: number | null = null
): NutritionData | null {
  const metadataCache = app.metadataCache;
  if (!metadataCache) return null;

  const cache = metadataCache.getFileCache(foodFile);
  if (!cache || !cache.frontmatter) return null;

  const fm = cache.frontmatter as Record<string, unknown>;
  // Frontmatter values can be non-strings (e.g. YAML parses `serving_size: 100`
  // as a number). A `as string` cast does nothing at runtime, so coerce here to
  // avoid "toLowerCase is not a function" on numeric/other values.
  const storedServing = fm['serving_size'] != null ? String(fm['serving_size']) : '';
  if (!storedServing.toLowerCase().includes('g')) return null;

  const storedServingGrams = parseGrams(storedServing);
  if (isNaN(storedServingGrams)) return null;

  const quantity =
    specifiedQuantity != null && !isNaN(specifiedQuantity) ? specifiedQuantity : storedServingGrams;
  const scale = quantity / storedServingGrams;

  const cal = parseFloat(fm['calories'] as string) || 0;
  const prot = parseFloat(fm['protein'] as string) || 0;
  const fat = parseFloat(fm['fat'] as string) || 0;
  const carbs = parseFloat(fm['carbs'] as string) || 0;

  return {
    name: foodFile.name.replace(/\.md$/, ''),
    serving: `${quantity}g`,
    calories: cal * scale,
    protein: parseFloat((prot * scale).toFixed(1)),
    fat: parseFloat((fat * scale).toFixed(1)),
    carbs: parseFloat((carbs * scale).toFixed(1)),
  };
}

/**
 * Merges macro lines into unique entries
 * @param lines Array of macro lines
 * @returns Merged array of lines
 */
export function mergeMacroLines(lines: string[]): string[] {
  const mergedFood: Record<string, { foodName: string; totalServing: number; firstIndex: number }> =
    {};
  const mergedMeals: Record<string, { mealName: string; count: number; firstIndex: number }> = {};

  lines.forEach((line, index) => {
    if (line.toLowerCase().startsWith('meal:')) {
      const fullMealText = line.substring(5).trim();
      let mealName = fullMealText;
      let existingCount = 1;
      const countMatch = fullMealText.match(/^(.*)\s+├ù\s+(\d+)$/);
      if (countMatch) {
        mealName = countMatch[1];
        existingCount = parseInt(countMatch[2]);
      }
      const key = mealName.toLowerCase();
      if (!mergedMeals[key]) {
        mergedMeals[key] = { mealName, count: existingCount, firstIndex: index };
      } else {
        mergedMeals[key].count += existingCount;
      }
    } else if (!line.toLowerCase().startsWith('-') && line.includes(':')) {
      const match = line.match(/^([^:]+):\s*([\d.]+)g$/i);
      if (match) {
        const foodName = match[1].trim();
        const serving = parseFloat(match[2]);
        const key = foodName.toLowerCase();
        if (isNaN(serving)) return;
        if (!mergedFood[key]) {
          mergedFood[key] = { foodName, totalServing: serving, firstIndex: index };
        } else {
          mergedFood[key].totalServing += serving;
        }
      }
    }
  });

  const output: string[] = [];
  lines.forEach((line, index) => {
    if (line.toLowerCase().startsWith('meal:')) {
      const fullMealText = line.substring(5).trim();
      let mealName = fullMealText;
      const countMatch = fullMealText.match(/^(.*)\s+├ù\s+(\d+)$/);
      if (countMatch) mealName = countMatch[1];
      const key = mealName.toLowerCase();
      if (mergedMeals[key] && mergedMeals[key].firstIndex === index) {
        output.push(
          mergedMeals[key].count > 1
            ? `meal:${mealName} ├ù ${mergedMeals[key].count}`
            : `meal:${mealName}`
        );
      }
    } else if (!line.toLowerCase().startsWith('-') && line.includes(':')) {
      const match = line.match(/^([^:]+):\s*([\d.]+)g$/i);
      if (match) {
        const key = match[1].trim().toLowerCase();
        if (mergedFood[key] && mergedFood[key].firstIndex === index) {
          output.push(`${mergedFood[key].foodName}:${mergedFood[key].totalServing}g`);
        }
        return;
      }
      output.push(line);
    } else if (!line.toLowerCase().startsWith('-')) {
      output.push(line);
    }
  });

  return output;
}

/**
 * Calculates consistent calorie values for nutrition data
 * @param data The nutrition data to calculate calories for
 * @returns Calories value with consistent rounding
 */
export function calculateConsistentCalories(data: NutritionData): number {
  return parseFloat(data.calories.toFixed(1));
}

